import { GoogleGenAI, Type } from "@google/genai";
import { User, Match, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';

export const getCompatibilityInsight = async (user: User, match: Match): Promise<{ score: number, insight: string }> => {
    if (!process.env.API_KEY) {
        return { score: 85, insight: "You both share a passion for career growth and value deep connection." };
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-pro-preview';

    const prompt = `
        Act as a professional marriage matchmaker. Analyze the compatibility between two individuals for a long-term, marriage-oriented relationship.

        User (${user.name}):
        - Bio: ${user.bio}
        - Values: ${user.personalValues.join(', ')}
        - Religion: ${user.religion}
        - Marriage Timeline: ${user.marriageTimeline}
        - Children Preference: ${user.childrenPreference}
        - Willing to Relocate: ${user.willingToRelocate}

        Match (${match.name}):
        - Bio: ${match.bio}
        - Values: ${match.personalValues.join(', ')}
        - Religion: ${match.religion}
        - Marriage Timeline: ${match.marriageTimeline}
        - Children Preference: ${match.childrenPreference}
        - Willing to Relocate: ${match.willingToRelocate}

        Provide:
        1. A compatibility score (0-100) based strictly on marriage-critical factors.
        2. A concise 2-sentence "Match Insight" explaining why they are a good fit.

        Return JSON format: { "score": number, "insight": string }
    `;

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.INTEGER },
                        insight: { type: Type.STRING }
                    },
                    required: ["score", "insight"]
                }
            }
        });

        return JSON.parse(response.text);
    } catch (error) {
        console.error("Matchmaking error:", error);
        return { score: 75, insight: "AI analysis unavailable. You both appear to have compatible life goals based on your profiles." };
    }
};

export const generateAIReply = async (match: Match, conversationHistory: string[]): Promise<string> => {
     if (!process.env.API_KEY) return "That's really interesting! Tell me more.";

     const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
     const model = 'gemini-3-flash-preview';

     const prompt = `
        You are ${match.name}. Your profile: "${match.bio}".
        Conversation history:
        ${conversationHistory.join('\n')}

        Write a brief, friendly, and engaging reply to the last message that moves the conversation towards getting to know each other for marriage. Keep it under 20 words.
     `;

     try {
         const response = await ai.models.generateContent({
             model: model,
             contents: prompt
         });
         return response.text.trim();
     } catch (e) {
         return "I'd love to hear your thoughts on that!";
     }
};

/**
 * Simulates querying a "Global Centralized Database" by using Gemini to generate
 * high-quality, unique profiles of individuals seeking marriage.
 */
export const queryGlobalRegistry = async (count: number = 3): Promise<Match[]> => {
    if (!process.env.API_KEY) return [];

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-flash-preview';

    const prompt = `
        Generate ${count} highly detailed, realistic profiles for a marriage-oriented matchmaking app called "Knot".
        Each profile must represent a "real user" from around the world who is seriously seeking a spouse.

        Requirements for each profile:
        - Unique name and realistic age (24-45).
        - Detailed bio reflecting maturity and marriage intent.
        - Occupation, City, and Country (be diverse: e.g., Tokyo, London, Nairobi, NYC, Mumbai).
        - Marriage Timeline (e.g., "Within 1 year", "1-2 years").
        - Personal Values (array of strings).
        - Children Preference (Choose from: "Wants children", "Doesn't want children", "Open to children", "Has children").
        - Profile Image: Use high-quality Unsplash URLs for portraits (e.g., https://images.unsplash.com/photo-...).

        Return a JSON array of objects following the Match interface structure.
    `;

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            name: { type: Type.STRING },
                            age: { type: Type.INTEGER },
                            bio: { type: Type.STRING },
                            occupation: { type: Type.STRING },
                            city: { type: Type.STRING },
                            country: { type: Type.STRING },
                            marriageTimeline: { type: Type.STRING },
                            interests: { type: Type.ARRAY, items: { type: Type.STRING } },
                            profileImageUrls: { type: Type.ARRAY, items: { type: Type.STRING } },
                            religion: { type: Type.STRING },
                            personalValues: { type: Type.ARRAY, items: { type: Type.STRING } },
                            childrenPreference: { type: Type.STRING },
                            isVerified: { type: Type.BOOLEAN },
                            isPremium: { type: Type.BOOLEAN },
                            maritalStatus: { type: Type.STRING },
                            willingToRelocate: { type: Type.STRING },
                            marriageExpectations: { type: Type.STRING }
                        },
                        required: ["id", "name", "age", "bio", "occupation", "city", "country", "profileImageUrls"]
                    }
                }
            }
        });

        const rawMatches = JSON.parse(response.text);

        // Map strings to Enums for safety
        return rawMatches.map((m: any) => ({
            ...m,
            id: `global_${m.id || Math.random().toString(36).substr(2, 9)}`,
            smoking: SmokingHabits.NonSmoker,
            drinking: DrinkingHabits.Socially,
            maritalStatus: m.maritalStatus || MaritalStatus.NeverMarried,
            willingToRelocate: m.willingToRelocate || WillingToRelocate.Maybe,
            childrenPreference: m.childrenPreference || ChildrenPreference.OpenToChildren,
            languages: m.languages || ["English"],
            education: m.education || "University Graduate",
            isVerified: m.isVerified ?? Math.random() > 0.3,
            isPremium: m.isPremium ?? false,
            idealPartnerTraits: m.idealPartnerTraits || ["Kind", "Supportive"],
            culturalBackground: m.culturalBackground || "Diverse",
            nationality: m.country,
            careerGoals: "Continuing to grow and provide."
        }));
    } catch (error) {
        console.error("Global Registry Error:", error);
        return [];
    }
};

import { User, Match, Message } from '../types';
import { CURRENT_USER, MATCHES_DATA, LIKED_MATCHES_DATA, MESSAGES_DATA } from '../constants';

const DB_KEYS = {
    USER: 'knot_user_profile',
    MATCHES: 'knot_matches_v2', // Versioned to avoid old schema conflicts
    LIKES: 'knot_likes',
    MESSAGES: 'knot_messages_history'
};

class DatabaseService {
    private isInitialized = false;

    constructor() {
        this.init();
    }

    private init() {
        if (this.isInitialized) return;
        if (!localStorage.getItem(DB_KEYS.USER)) {
            localStorage.setItem(DB_KEYS.USER, JSON.stringify(CURRENT_USER));
        }
        if (!localStorage.getItem(DB_KEYS.MATCHES)) {
            localStorage.setItem(DB_KEYS.MATCHES, JSON.stringify(MATCHES_DATA));
        }
        if (!localStorage.getItem(DB_KEYS.LIKES)) {
            localStorage.setItem(DB_KEYS.LIKES, JSON.stringify(LIKED_MATCHES_DATA));
        }
        if (!localStorage.getItem(DB_KEYS.MESSAGES)) {
            localStorage.setItem(DB_KEYS.MESSAGES, JSON.stringify(MESSAGES_DATA));
        }
        this.isInitialized = true;
    }

    async getUser(): Promise<User> {
        return JSON.parse(localStorage.getItem(DB_KEYS.USER)!);
    }

    async saveUser(user: User): Promise<void> {
        localStorage.setItem(DB_KEYS.USER, JSON.stringify(user));
    }

    async getMatches(): Promise<Match[]> {
        return JSON.parse(localStorage.getItem(DB_KEYS.MATCHES)!);
    }

    async saveMatches(matches: Match[]): Promise<void> {
        localStorage.setItem(DB_KEYS.MATCHES, JSON.stringify(matches));
    }

    async addGlobalMatches(newMatches: Match[]): Promise<void> {
        const current = await this.getMatches();
        const existingIds = new Set(current.map(m => m.id));
        const uniqueNew = newMatches.filter(m => !existingIds.has(m.id));
        await this.saveMatches([...current, ...uniqueNew]);
    }

    async getLikedMatches(): Promise<Match[]> {
        return JSON.parse(localStorage.getItem(DB_KEYS.LIKES)!);
    }

    async addLike(match: Match): Promise<void> {
        const likes = await this.getLikedMatches();
        if (!likes.find(l => l.id === match.id)) {
            likes.push(match);
            localStorage.setItem(DB_KEYS.LIKES, JSON.stringify(likes));
        }
    }

    async getMessages(matchId: string): Promise<Message[]> {
        const historyStr = localStorage.getItem(DB_KEYS.MESSAGES);
        if (!historyStr) return [];
        const history = JSON.parse(historyStr);
        const conv = history.find((h: any) => h.matchId === matchId);
        return conv ? conv.messages.map((m: any) => ({ ...m, timestamp: new Date(m.timestamp) })) : [];
    }

    async sendMessage(matchId: string, message: Message): Promise<void> {
        const historyStr = localStorage.getItem(DB_KEYS.MESSAGES);
        const history = historyStr ? JSON.parse(historyStr) : [];
        let conv = history.find((h: any) => h.matchId === matchId);
        if (!conv) {
            conv = { matchId, messages: [] };
            history.push(conv);
        }
        conv.messages.push(message);
        localStorage.setItem(DB_KEYS.MESSAGES, JSON.stringify(history));
    }
}

export const db = new DatabaseService();

