import { GoogleGenAI, Type } from "@google/genai";

export interface GlobalEvent {
    id: string;
    message: string;
    location: string;
    timestamp: Date;
}

export const fetchRecentGlobalActivity = async (): Promise<GlobalEvent[]> => {
    if (!process.env.API_KEY) {
        return [
            { id: '1', message: "New marriage-minded match found", location: "London, UK", timestamp: new Date() },
            { id: '2', message: "User profile verified", location: "Toronto, CA", timestamp: new Date() }
        ];
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-flash-preview';

    const prompt = `
        Generate 5 "Live Community Events" for a global marriage matchmaking app called "Knot".
        Events should sound realistic and professional (e.g., "A new match was made", "User verified", "Wedding date set by Knot couple").
        Be diverse with locations.
        Return as a JSON array of objects with 'message' and 'location'.
    `;

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            message: { type: Type.STRING },
                            location: { type: Type.STRING }
                        },
                        required: ["message", "location"]
                    }
                }
            }
        });

        const data = JSON.parse(response.text);
        return data.map((item: any, idx: number) => ({
            id: `event_${Date.now()}_${idx}`,
            message: item.message,
            location: item.location,
            timestamp: new Date()
        }));
    } catch (e) {
        return [];
    }
};

import React, { useState, useEffect } from 'react';
import { fetchRecentGlobalActivity, GlobalEvent } from '../services/globalActivityService';

const GlobalActivityTicker: React.FC = () => {
    const [events, setEvents] = useState<GlobalEvent[]>([]);
    const [currentIndex, setCurrentIndex] = useState(0);

    useEffect(() => {
        const loadActivity = async () => {
            const newEvents = await fetchRecentGlobalActivity();
            if (newEvents.length > 0) {
                setEvents(newEvents);
            }
        };

        loadActivity();
        const fetchInterval = setInterval(loadActivity, 60000); // Refresh registry activity every minute

        return () => clearInterval(fetchInterval);
    }, []);

    useEffect(() => {
        if (events.length === 0) return;
        const rotateInterval = setInterval(() => {
            setCurrentIndex(prev => (prev + 1) % events.length);
        }, 5000); // Rotate message every 5 seconds

        return () => clearInterval(rotateInterval);
    }, [events]);

    if (events.length === 0) return null;

    const currentEvent = events[currentIndex];

    return (
        <div className="bg-brand-dark/95 backdrop-blur-md h-7 flex items-center justify-center overflow-hidden border-b border-white/5">
            <div className="flex items-center gap-2 animate-pulse-slow">
                <div className="w-1.5 h-1.5 bg-green-400 rounded-full"></div>
                <p className="text-[10px] font-bold text-white/90 uppercase tracking-[0.1em]">
                    Live Knot Registry: <span className="text-brand-accent">{currentEvent.message}</span> in {currentEvent.location}
                </p>
            </div>
            <style>{`
                @keyframes pulse-slow {
                    0%, 100% { opacity: 1; }
                    50% { opacity: 0.7; }
                }
                .animate-pulse-slow { animation: pulse-slow 3s infinite ease-in-out; }
            `}</style>
        </div>
    );
};

