import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
// Fixed: Removed ChildrenStatus from imports as it is not defined in types.ts
import { User, Match, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';

async function callGeminiWithRetry(
  ai: any, 
  params: any, 
  retries = 3, 
  delay = 1000
): Promise<GenerateContentResponse> {
  try {
    return await ai.models.generateContent(params);
  } catch (error: any) {
    if (retries > 0 && (error?.status === 'UNKNOWN' || error?.code === 500 || error?.code === 503)) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return callGeminiWithRetry(ai, params, retries - 1, delay * 2);
    }
    throw error;
  }
}

export const getCompatibilityInsight = async (user: User, match: Match): Promise<{ score: number, insight: string }> => {
    if (!process.env.API_KEY) {
        return { score: 85, insight: "You both share a passion for career growth and value deep connection." };
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-pro-preview';

    const prompt = `
        Act as a professional marriage matchmaker. Analyze the compatibility between two individuals for a long-term, marriage-oriented relationship.

        User (${user.name}):
        - Marital History: ${user.maritalStatus}
        - Current Children: ${user.childrenStatus}
        - Bio: ${user.bio}
        - Values: ${user.personalValues.join(', ')}
        - Religion: ${user.religion}
        - Marriage Timeline: ${user.marriageTimeline}
        - Children Preference (Future): ${user.childrenPreference}

        Match (${match.name}):
        - Marital History: ${match.maritalStatus}
        - Current Children: ${match.childrenStatus}
        - Bio: ${match.bio}
        - Values: ${match.personalValues.join(', ')}
        - Religion: ${match.religion}
        - Marriage Timeline: ${match.marriageTimeline}
        - Children Preference (Future): ${match.childrenPreference}

        Provide:
        1. A compatibility score (0-100) based strictly on marriage-critical factors (especially children and marital history alignment).
        2. A concise 2-sentence "Match Insight" explaining why they are a good fit.

        Return JSON format: { "score": number, "insight": string }
    `;

    try {
        const response = await callGeminiWithRetry(ai, {
            model: model,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.INTEGER },
                        insight: { type: Type.STRING }
                    },
                    required: ["score", "insight"]
                }
            }
        });

        return JSON.parse(response.text || '{"score": 75, "insight": "Stable connection predicted."}');
    } catch (error) {
        console.error("Matchmaking error:", error);
        return { score: 75, insight: "AI analysis currently processing. You both appear to have highly compatible life goals." };
    }
};

export const generateAIReply = async (match: Match, conversationHistory: string[]): Promise<string> => {
     if (!process.env.API_KEY) return "That's really interesting! Tell me more.";

     const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
     const model = 'gemini-3-flash-preview';

     const prompt = `
        You are ${match.name}. Your profile: "${match.bio}".
        Conversation history:
        ${conversationHistory.join('\n')}

        Write a brief, friendly, and engaging reply to the last message that moves the conversation towards getting to know each other for marriage. Keep it under 20 words.
     `;

     try {
         const response = await callGeminiWithRetry(ai, {
             model: model,
             contents: prompt
         });
         return response.text?.trim() || "I'd love to hear more about your day!";
     } catch (e) {
         return "That's wonderful! I'm really enjoying getting to know you.";
     }
};

export const queryGlobalRegistry = async (count: number = 3): Promise<Match[]> => {
    if (!process.env.API_KEY) return [];

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-flash-preview';

    const prompt = `
        Generate ${count} highly detailed, realistic profiles for a marriage-oriented matchmaking app called "Knot".

        Requirements for each profile:
        - Unique name and realistic age (24-45).
        - Marital History (Must choose from: "Never Married", "Divorced", "Widowed").
        - Current Children (Must choose from: "No children at all", "Has child / children").
        - Detailed bio reflecting maturity and marriage intent.
        - Occupation, City, and Country.
        - Marriage Timeline.
        - Future Children Preference.

        Return a JSON array of objects.
    `;

    try {
        const response = await callGeminiWithRetry(ai, {
            model: model,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            name: { type: Type.STRING },
                            age: { type: Type.INTEGER },
                            bio: { type: Type.STRING },
                            occupation: { type: Type.STRING },
                            city: { type: Type.STRING },
                            country: { type: Type.STRING },
                            marriageTimeline: { type: Type.STRING },
                            interests: { type: Type.ARRAY, items: { type: Type.STRING } },
                            profileImageUrls: { type: Type.ARRAY, items: { type: Type.STRING } },
                            religion: { type: Type.STRING },
                            personalValues: { type: Type.ARRAY, items: { type: Type.STRING } },
                            childrenPreference: { type: Type.STRING },
                            childrenStatus: { type: Type.STRING },
                            maritalStatus: { type: Type.STRING },
                            isVerified: { type: Type.BOOLEAN },
                            isPremium: { type: Type.BOOLEAN },
                            willingToRelocate: { type: Type.STRING },
                            marriageExpectations: { type: Type.STRING }
                        },
                        required: ["id", "name", "age", "bio", "maritalStatus", "childrenStatus", "profileImageUrls"]
                    }
                }
            }
        });

        const rawMatches = JSON.parse(response.text || '[]');

        return rawMatches.map((m: any) => ({
            ...m,
            id: `global_${m.id || Math.random().toString(36).substr(2, 9)}`,
            smoking: SmokingHabits.NonSmoker,
            drinking: DrinkingHabits.Socially,
            maritalStatus: m.maritalStatus as MaritalStatus || MaritalStatus.NeverMarried,
            // Fixed: Updated to use a default string value "No kids" instead of an undefined ChildrenStatus enum/type
            childrenStatus: m.childrenStatus || "No kids",
            willingToRelocate: m.willingToRelocate || WillingToRelocate.Maybe,
            childrenPreference: m.childrenPreference || ChildrenPreference.OpenToChildren,
            languages: m.languages || ["English"],
            education: m.education || "University Graduate",
            isVerified: m.isVerified ?? Math.random() > 0.3,
            isPremium: m.isPremium ?? false,
            idealPartnerTraits: m.idealPartnerTraits || ["Kind", "Supportive"],
            culturalBackground: m.culturalBackground || "Diverse",
            nationality: m.country,
            careerGoals: "Continuing to grow and provide."
        }));
    } catch (error) {
        console.error("Global Registry Error:", error);
        return [];
    }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Match, User, Message } from '../types';
import { generateConversationStarters } from '../services/geminiService';
import { generateAIReply } from '../services/matchingService';
import { db } from '../services/databaseService';
import { SparklesIcon } from './icons/SparklesIcon';
import { SendIcon } from './icons/SendIcon';
import { VideoCameraIcon } from './icons/VideoCameraIcon';
import { useToast } from './feedback/useToast';

interface ChatScreenProps {
  match: Match;
  user: User;
  onBack: () => void;
  onStartCall: (match: Match) => void;
}

const ChatScreen: React.FC<ChatScreenProps> = ({ match, user, onBack, onStartCall }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [starters, setStarters] = useState<string[]>([]);
  const [isLoadingStarters, setIsLoadingStarters] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const { addToast } = useToast();

  useEffect(() => {
    const loadHistory = async () => {
        const history = await db.getMessages(match.id);
        if (history.length === 0) {
            const initialMsg: Message = { id: '1', senderId: match.id, text: `Hey ${user.name}! It's great to connect.`, timestamp: new Date() };
            setMessages([initialMsg]);
            db.sendMessage(match.id, initialMsg);
        } else {
            setMessages(history);
        }
    };
    loadHistory();
  }, [match.id, user.name]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleGenerateStarters = useCallback(async () => {
    setIsLoadingStarters(true);
    try {
      const newStarters = await generateConversationStarters(user, match);
      setStarters(newStarters);
    } catch (error) {
      console.error("Failed to generate starters:", error);
      setStarters(["What's one value you hold that has shaped who you are today?"]);
    } finally {
      setIsLoadingStarters(false);
    }
  }, [user, match]);

  const handleSendMessage = async () => {
    if (newMessage.trim() === '') return;

    const message: Message = {
      id: String(Date.now()),
      senderId: user.id,
      text: newMessage,
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, message]);
    setNewMessage('');
    await db.sendMessage(match.id, message);

    // Backend Simulation: Auto-reply
    setIsTyping(true);
    const historyStrings = [...messages, message].map(m => `${m.senderId === user.id ? user.name : match.name}: ${m.text}`);

    setTimeout(async () => {
        const replyText = await generateAIReply(match, historyStrings);
        const replyMsg: Message = {
            id: String(Date.now() + 1),
            senderId: match.id,
            text: replyText,
            timestamp: new Date()
        };
        setIsTyping(false);
        setMessages(prev => [...prev, replyMsg]);
        await db.sendMessage(match.id, replyMsg);
    }, 2500);
  };

  const handleStarterClick = (starter: string) => {
    setNewMessage(starter);
    setStarters([]);
  };

  return (
    <div className="flex flex-col h-screen max-h-screen">
      {/* Header */}
      <div className="flex items-center p-3 border-b border-gray-200 bg-white sticky top-0 z-10 shadow-sm">
        <button onClick={onBack} className="text-gray-600 mr-3 p-1 rounded-full hover:bg-gray-100">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
        </button>
        <img src={match.profileImageUrls[0]} alt={match.name} className="w-10 h-10 rounded-full object-cover" />
        <div className="ml-3 flex-1">
          <h2 className="font-bold text-lg text-brand-dark">{match.name}</h2>
          <p className="text-xs text-gray-500">{isTyping ? 'Typing...' : 'Online'}</p>
        </div>
        <button onClick={() => onStartCall(match)} className="p-2 text-brand-primary hover:bg-brand-light rounded-full">
            <VideoCameraIcon className="w-6 h-6" />
        </button>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 bg-brand-light/30 pb-44">
        <div className="space-y-4">
          {messages.map((msg) => (
            <div key={msg.id} className={`flex items-end gap-2 ${msg.senderId === user.id ? 'justify-end' : 'justify-start'}`}>
              {msg.senderId !== user.id && <img src={match.profileImageUrls[0]} alt={match.name} className="w-6 h-6 rounded-full self-start" />}
              <div
                className={`max-w-[75%] px-4 py-2 rounded-2xl ${
                  msg.senderId === user.id
                    ? 'bg-brand-primary text-white rounded-br-none'
                    : 'bg-white text-gray-900 border border-gray-200 rounded-bl-none shadow-sm'
                }`}
              >
                <p className="text-sm font-medium">{msg.text}</p>
              </div>
            </div>
          ))}
          {isTyping && (
             <div className="flex items-center gap-2">
                <img src={match.profileImageUrls[0]} alt={match.name} className="w-6 h-6 rounded-full" />
                <div className="bg-white px-4 py-3 rounded-2xl rounded-bl-none border border-gray-200 shadow-sm flex gap-1">
                    <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce"></div>
                    <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                    <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                </div>
             </div>
          )}
        </div>
        <div ref={chatEndRef} />
      </div>

      {/* Input */}
      <div className="bg-white border-t border-gray-200 p-3 fixed bottom-20 left-0 right-0 max-w-md mx-auto">
        {starters.length > 0 && (
          <div className="mb-2 flex gap-2 overflow-x-auto pb-2 hide-scrollbar">
            {starters.map((starter, index) => (
              <button 
                key={index} 
                onClick={() => handleStarterClick(starter)} 
                className="flex-shrink-0 text-sm bg-brand-light border border-brand-primary/20 p-2 px-3 rounded-full text-brand-primary hover:bg-brand-primary hover:text-white transition-colors"
              >
                {starter}
              </button>
            ))}
          </div>
        )}
        <div className="flex items-center gap-2">
            <button onClick={handleGenerateStarters} disabled={isLoadingStarters} className="p-2 text-brand-secondary hover:bg-gray-100 rounded-full disabled:opacity-50">
                {isLoadingStarters ? <div className="w-5 h-5 border-2 border-brand-secondary border-t-transparent rounded-full animate-spin"></div> : <SparklesIcon className="w-6 h-6" />}
            </button>
          <input
            type="text"
            value={newMessage}
            onChange={(e) => setNewMessage(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
            placeholder="Type a message..."
            className="flex-1 border border-gray-300 rounded-full py-2.5 px-4 focus:outline-none focus:ring-2 focus:ring-brand-secondary bg-gray-50 text-gray-900"
          />
          <button onClick={handleSendMessage} className="bg-brand-primary text-white rounded-full p-2.5 hover:bg-brand-secondary transition-transform active:scale-95">
            <SendIcon className="w-5 h-5" />
          </button>
        </div>
      </div>
    </div>
  );
};

export default ChatScreen;

