import { GoogleGenAI, Type } from "@google/genai";

export interface GlobalEvent {
    id: string;
    message: string;
    location: string;
    timestamp: Date;
}

const CACHE_KEY = 'knot_global_activity_cache';
const CACHE_EXPIRY = 1000 * 60 * 15; // 15 minutes

const FALLBACK_EVENTS: GlobalEvent[] = [
    { id: 'f1', message: "New marriage-minded match found", location: "London, UK", timestamp: new Date() },
    { id: 'f2', message: "User profile verified", location: "Toronto, CA", timestamp: new Date() },
    { id: 'f3', message: "Marriage timeline aligned for new couple", location: "Lagos, NG", timestamp: new Date() },
    { id: 'f4', message: "Knot Cloud Match synchronized", location: "Dubai, UAE", timestamp: new Date() },
    { id: 'f5', message: "Soulmates connected via values search", location: "Austin, USA", timestamp: new Date() }
];

export const fetchRecentGlobalActivity = async (): Promise<GlobalEvent[]> => {
    // 1. Check Cache first to avoid 429
    const cached = localStorage.getItem(CACHE_KEY);
    if (cached) {
        const { timestamp, data } = JSON.parse(cached);
        if (Date.now() - timestamp < CACHE_EXPIRY) {
            return data.map((d: any) => ({ ...d, timestamp: new Date(d.timestamp) }));
        }
    }

    if (!process.env.API_KEY) return FALLBACK_EVENTS;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-flash-preview';

    const prompt = `
        Generate 5 "Live Community Events" for a global marriage matchmaking app called "Knot".
        Events should sound realistic and professional (e.g., "A new match was made", "User verified", "Wedding date set by Knot couple").
        Be diverse with locations.
        Return as a JSON array of objects with 'message' and 'location'.
    `;

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            message: { type: Type.STRING },
                            location: { type: Type.STRING }
                        },
                        required: ["message", "location"]
                    }
                }
            }
        });

        const data = JSON.parse(response.text || '[]');
        const events = data.map((item: any, idx: number) => ({
            id: `event_${Date.now()}_${idx}`,
            message: item.message,
            location: item.location,
            timestamp: new Date()
        }));

        // Store in cache
        localStorage.setItem(CACHE_KEY, JSON.stringify({
            timestamp: Date.now(),
            data: events
        }));

        return events;
    } catch (e: any) {
        console.error("Global Activity Fetch Error:", e);
        // If 429 or 500, return fallbacks or old cache
        if (cached) {
            return JSON.parse(cached).data;
        }
        return FALLBACK_EVENTS;
    }
};

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { User, Match, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';

async function callGeminiWithRetry(
  ai: any, 
  params: any, 
  retries = 3, 
  delay = 1500
): Promise<GenerateContentResponse> {
  try {
    return await ai.models.generateContent(params);
  } catch (error: any) {
    const isRetryable = error?.status === 'UNKNOWN' || error?.code === 500 || error?.code === 503 || error?.code === 429;
    if (retries > 0 && isRetryable) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return callGeminiWithRetry(ai, params, retries - 1, delay * 2);
    }
    throw error;
  }
}

export const getCompatibilityInsight = async (user: User, match: Match): Promise<{ score: number, insight: string }> => {
    if (!process.env.API_KEY) {
        return { score: 85, insight: "You both share a passion for career growth and value deep connection." };
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-pro-preview';

    const prompt = `
        Act as a professional marriage matchmaker. Analyze compatibility.
        User: ${user.name}, Bio: ${user.bio}, Values: ${user.personalValues.join(', ')}
        Match: ${match.name}, Bio: ${match.bio}, Values: ${match.personalValues.join(', ')}
        Return JSON format: { "score": number, "insight": string }
    `;

    try {
        const response = await callGeminiWithRetry(ai, {
            model: model,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.INTEGER },
                        insight: { type: Type.STRING }
                    },
                    required: ["score", "insight"]
                }
            }
        });

        return JSON.parse(response.text || '{"score": 75, "insight": "Stable connection predicted."}');
    } catch (error) {
        return { score: 75, insight: "Shared values in family and growth make you a strong potential match." };
    }
};

export const generateAIReply = async (match: Match, conversationHistory: string[]): Promise<string> => {
     if (!process.env.API_KEY) return "I'd love to hear more about your journey!";

     const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
     const model = 'gemini-3-flash-preview';

     const prompt = `Reply as ${match.name}. History: ${conversationHistory.slice(-3).join('\n')}. Keep it short and friendly.`;

     try {
         const response = await callGeminiWithRetry(ai, { model: model, contents: prompt });
         return response.text?.trim() || "That's wonderful to hear!";
     } catch (e) {
         return "I'm really enjoying our conversation!";
     }
};

export const queryGlobalRegistry = async (count: number = 3): Promise<Match[]> => {
    if (!process.env.API_KEY) return [];

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-flash-preview';

    const prompt = `Generate ${count} detailed marriage-oriented dating profiles. Return JSON array.`;

    try {
        const response = await callGeminiWithRetry(ai, {
            model: model,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            name: { type: Type.STRING },
                            age: { type: Type.INTEGER },
                            bio: { type: Type.STRING },
                            occupation: { type: Type.STRING },
                            city: { type: Type.STRING },
                            country: { type: Type.STRING },
                            marriageTimeline: { type: Type.STRING },
                            profileImageUrls: { type: Type.ARRAY, items: { type: Type.STRING } },
                            maritalStatus: { type: Type.STRING }
                        },
                        required: ["id", "name", "age", "bio", "maritalStatus", "profileImageUrls"]
                    }
                }
            }
        });

        const rawMatches = JSON.parse(response.text || '[]');
        return rawMatches.map((m: any) => ({
            ...m,
            id: `global_${m.id || Math.random().toString(36).substr(2, 9)}`,
            smoking: SmokingHabits.NonSmoker,
            drinking: DrinkingHabits.Socially,
            maritalStatus: m.maritalStatus as MaritalStatus || MaritalStatus.NeverMarried,
            childrenStatus: "No kids",
            willingToRelocate: WillingToRelocate.Maybe,
            childrenPreference: ChildrenPreference.OpenToChildren,
            languages: ["English"],
            education: "University Graduate",
            isVerified: true,
            isPremium: false,
            personalValues: ["Family", "Commitment"],
            idealPartnerTraits: ["Kind"],
            interests: ["Travel"],
            religion: "Spiritual",
            culturalBackground: "International",
            nationality: m.country,
            careerGoals: "Professional growth."
        }));
    } catch (error) {
        return [];
    }
};

