import { verifyTransaction } from '../services/paystack.service';

export const handleVerifyPayment = async (req: any, res: any) => {
  const { reference, userId } = req.body;
  try {
    const response = await verifyTransaction(reference);
    if (response.status && response.data.status === 'success') {
      // In a real DB: await User.update({ isPremium: true }, { where: { id: userId } });
      res.json({ success: true, message: 'Premium activated' });
    } else {
      res.status(400).json({ success: false, message: 'Payment verification failed' });
    }
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
};

import express from 'express';
import cors from 'cors';
import paymentRoutes from './routes/payment.routes';
import matchingRoutes from './routes/matching.routes';

const app = express();

// Middleware
app.use(cors());
app.use(express.json() as any);

// Routes
app.use('/api/payments', paymentRoutes);
app.use('/api/matching', matchingRoutes);

// Error Handling
app.use((err: any, req: express.Request, res: any, next: express.NextFunction) => {
  console.error(err.stack);
  res.status(500).send({ error: 'Something went wrong!' });
});

export default app;

export type Screen = 'home' | 'likes' | 'messages' | 'resources' | 'profile' | 'chat' | 'profileDetail' | 'videoCall' | 'verification' | 'editProfile' | 'managePhotos' | 'auth' | 'payment' | 'onboarding';

