import React, { useState, useEffect, useCallback } from 'react';
import { User, Match, Screen, FilterState } from './types';
import { INITIAL_FILTERS } from './constants';
import { db } from './services/databaseService';
import { queryGlobalRegistry } from './services/matchingService';
import Header from './components/Header';
import BottomNav from './components/BottomNav';
import MatchCard from './components/MatchCard';
import ProfileDetailScreen from './components/ProfileDetailScreen';
import ChatScreen from './components/ChatScreen';
import VideoCallScreen from './components/VideoCallScreen';
import ProfileCard from './components/ProfileCard';
import VerificationScreen from './components/VerificationScreen';
import EditProfileScreen from './components/EditProfileScreen';
import PhotoManagerScreen from './components/PhotoManagerScreen';
import AuthScreen from './components/AuthScreen';
import LikesScreen from './components/LikesScreen';
import PremiumModal from './components/PremiumModal';
import MessagesScreen from './components/MessagesScreen';
import ResourceCard from './components/ResourceCard';
import FilterModal from './components/FilterModal';
import PaymentScreen from './components/PaymentScreen';
import GlobalActivityTicker from './components/GlobalActivityTicker';
import OnboardingFlow from './components/OnboardingFlow';
import { FilterIcon } from './components/icons/FilterIcon';
import { SparklesIcon } from './components/icons/SparklesIcon';
import { RESOURCES_DATA } from './constants';
import { ToastProvider, useToast } from './components/feedback/useToast';

const AppContent: React.FC = () => {
    const [user, setUser] = useState<User | null>(null);
    const [matches, setMatches] = useState<Match[]>([]);
    const [isLoggedIn, setIsLoggedIn] = useState(false);
    const [activeScreen, setActiveScreen] = useState<Screen>('home');
    const [selectedMatch, setSelectedMatch] = useState<Match | null>(null);
    const [filters, setFilters] = useState<FilterState>(INITIAL_FILTERS);
    const [isFilterModalOpen, setIsFilterModalOpen] = useState(false);
    const [isPremiumModalOpen, setIsPremiumModalOpen] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);
    const { addToast } = useToast();

    // Initial load from "backend"
    useEffect(() => {
        const loadData = async () => {
            const userData = await db.getUser();
            const matchesData = await db.getMatches();
            setUser(userData);
            setMatches(matchesData);
        };
        loadData();
    }, []);

    const fetchMoreFromGlobalRegistry = useCallback(async (isSilent = false) => {
        if (isSyncing) return;
        setIsSyncing(true);
        if (!isSilent) addToast("Updating from Global Registry...", "info");

        try {
            const newMatches = await queryGlobalRegistry(3);
            if (newMatches.length > 0) {
                await db.addGlobalMatches(newMatches);
                const updatedMatches = await db.getMatches();
                setMatches(updatedMatches);
                if (!isSilent) addToast(`Found ${newMatches.length} new profiles.`, "success");
            }
        } catch (e) {
            if (!isSilent) addToast("Registry sync failed.", "error");
        } finally {
            setIsSyncing(false);
        }
    }, [isSyncing, addToast]);

    const handleLogin = (isNewUser: boolean = false, name?: string) => {
        if (name && user) {
            const updated = {...user, name};
            setUser(updated);
            db.saveUser(updated);
        }
        setIsLoggedIn(true);
        if (isNewUser) {
            setActiveScreen('onboarding');
        } else {
            setActiveScreen('home');
            setTimeout(() => fetchMoreFromGlobalRegistry(true), 500);
        }
    };

    const handleNavigate = (screen: Screen) => {
        if (screen === 'likes' && user && !user.isPremium) {
            setIsPremiumModalOpen(true);
        } else {
            setActiveScreen(screen);
        }
    };

    const handleCardClick = (match: Match) => {
        setSelectedMatch(match);
        setActiveScreen('profileDetail');
    };

    const handleStartChat = (match: Match) => {
        if (user && !user.isPremium) {
            setIsPremiumModalOpen(true);
            return;
        }
        setSelectedMatch(match);
        setActiveScreen('chat');
    };

    const handleStartCall = (match: Match) => {
        if (user && !user.isPremium) {
            setIsPremiumModalOpen(true);
            return;
        }
        setSelectedMatch(match);
        setActiveScreen('videoCall');
    };

    const handleBack = () => {
        if (activeScreen === 'chat' || activeScreen === 'videoCall') {
            setActiveScreen('profileDetail');
        } else if (activeScreen === 'profileDetail' || activeScreen === 'payment') {
            setActiveScreen('home');
            setSelectedMatch(null);
        } else if (['verification', 'editProfile', 'managePhotos'].includes(activeScreen)) {
            setActiveScreen('profile');
            setSelectedMatch(null);
        } else {
            setActiveScreen('home');
            setSelectedMatch(null);
        }
    };

    const handleUpgradeClick = () => {
        setIsPremiumModalOpen(false);
        setActiveScreen('payment');
    };

    const handleSubscribe = () => {
        if (user) {
            const updated = { ...user, isPremium: true };
            setUser(updated);
            db.saveUser(updated);
        }
        addToast('Welcome to Premium!', 'success');
        setActiveScreen('likes'); 
    };

    const handleSaveProfile = (updatedUser: User) => {
        setUser(updatedUser);
        db.saveUser(updatedUser);
        addToast('Profile saved successfully!', 'success');
        if (activeScreen === 'onboarding') {
            setActiveScreen('home');
            setTimeout(() => fetchMoreFromGlobalRegistry(true), 500);
        } else {
            handleBack();
        }
    };

    const handleVerificationComplete = () => {
        if (user) {
            const updated = {...user, isVerified: true};
            setUser(updated);
            db.saveUser(updated);
        }
        setActiveScreen('profile');
    };

    const handleUpdatePhotos = (photos: string[]) => {
        if (user) {
            const updated = {...user, profileImageUrls: photos};
            setUser(updated);
            db.saveUser(updated);
        }
        addToast('Photos updated!', 'success');
        handleBack();
    };

    const filteredMatches = matches.filter(match => {
        const ageMatch = match.age >= filters.ageRange[0] && match.age <= filters.ageRange[1];
        const locationMatch = filters.location ? (match.city?.toLowerCase().includes(filters.location.toLowerCase()) || match.country?.toLowerCase().includes(filters.location.toLowerCase())) : true;
        const verifiedMatch = filters.showVerifiedOnly ? match.isVerified : true;
        return ageMatch && locationMatch && verifiedMatch;
    });

    if (!isLoggedIn) {
        return <AuthScreen onLogin={(name) => handleLogin(false, name)} onSignUp={(name) => handleLogin(true, name)} />;
    }

    if (!user) return <div className="h-screen flex items-center justify-center">Loading Knot Registry...</div>;

    const renderScreen = () => {
        if (selectedMatch) {
            switch(activeScreen) {
                case 'profileDetail':
                    return <ProfileDetailScreen match={selectedMatch} user={user} onBack={handleBack} onStartChat={handleStartChat} onStartCall={handleStartCall} />;
                case 'chat':
                    return <ChatScreen match={selectedMatch} user={user} onBack={handleBack} onStartCall={handleStartCall} />;
                case 'videoCall':
                    return <VideoCallScreen match={selectedMatch} user={user} onEndCall={handleBack} />;
            }
        }

        switch (activeScreen) {
            case 'onboarding':
                return <OnboardingFlow user={user} onComplete={handleSaveProfile} />;
            case 'home':
                return (
                    <div className="p-4 space-y-4 pb-32">
                        {filteredMatches.map(match => (
                            <MatchCard key={match.id} match={match} onCardClick={handleCardClick} />
                        ))}

                        <div className="pt-8 pb-4 flex flex-col items-center">
                            <button 
                                onClick={() => fetchMoreFromGlobalRegistry(false)} 
                                disabled={isSyncing}
                                className="flex items-center gap-2 bg-white border border-brand-primary/20 text-brand-primary font-bold px-8 py-3 rounded-full shadow-sm hover:shadow-md transition-all active:scale-95 disabled:opacity-50"
                            >
                                {isSyncing ? (
                                    <div className="w-5 h-5 border-2 border-brand-primary border-t-transparent rounded-full animate-spin"></div>
                                ) : (
                                    <SparklesIcon className="w-5 h-5" />
                                )}
                                <span>{isSyncing ? 'Synchronizing...' : 'Discover More Globally'}</span>
                            </button>
                        </div>
                    </div>
                );
            case 'likes':
                 return <LikesScreen likedMatches={[]} onMatchClick={handleCardClick} />;
            case 'messages':
                return <MessagesScreen onChatSelect={handleStartChat} user={user} />;
            case 'resources':
                return (
                    <div className="p-4 space-y-4 pb-24">
                        <h1 className="text-2xl font-bold text-brand-dark text-center py-4">Marriage & Commitment</h1>
                        {RESOURCES_DATA.map(resource => (
                           <ResourceCard key={resource.id} resource={resource} />
                        ))}
                    </div>
                );
            case 'profile':
                return <ProfileCard 
                    user={user} 
                    onEditProfile={() => setActiveScreen('editProfile')} 
                    onManagePhotos={() => setActiveScreen('managePhotos')}
                    onVerifyProfile={() => setActiveScreen('verification')}
                />;
            case 'verification':
                return <VerificationScreen onVerificationComplete={handleVerificationComplete} onBack={handleBack} />;
            case 'editProfile':
                return <EditProfileScreen user={user} onBack={handleBack} onSave={handleSaveProfile} />;
            case 'managePhotos':
                return <PhotoManagerScreen user={user} onBack={handleBack} onUpdatePhotos={handleUpdatePhotos} />;
            case 'payment':
                return <PaymentScreen onBack={handleBack} onSubscribe={handleSubscribe} />;
            default:
                return <div>Home</div>;
        }
    };

    const showHeader = ['home', 'likes', 'messages', 'resources', 'profile'].includes(activeScreen);
    const showBottomNav = ['home', 'likes', 'messages', 'resources', 'profile'].includes(activeScreen);

    return (
        <div className="max-w-md mx-auto bg-gray-50 min-h-screen font-sans">
            {showHeader && (
                <div className="fixed top-0 left-0 right-0 max-w-md mx-auto z-20">
                    <GlobalActivityTicker />
                    <Header />
                    {isSyncing && (
                        <div className="h-0.5 w-full bg-brand-light relative overflow-hidden">
                            <div className="absolute inset-0 bg-brand-primary animate-progress-ind"></div>
                        </div>
                    )}
                </div>
            )}

            {activeScreen === 'home' && (
                <div className="fixed top-[5.75rem] left-0 right-0 max-w-md mx-auto z-10 bg-white p-2 border-b h-[3.25rem] flex items-center shadow-sm">
                    <button onClick={() => setIsFilterModalOpen(true)} className="flex items-center gap-2 text-sm text-gray-600 font-semibold p-2 rounded-md hover:bg-gray-100">
                        <FilterIcon className="w-5 h-5" />
                        <span>Filter Matches</span>
                    </button>
                    <div className="ml-auto flex items-center gap-1.5 px-3">
                         <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
                         <span className="text-[10px] font-bold text-gray-400 uppercase tracking-tighter">Connected</span>
                    </div>
                </div>
            )}

            <main className={`${showHeader ? 'pt-[5.75rem]' : ''} ${activeScreen === 'home' ? 'pt-[3.25rem]' : ''}`}>
                {renderScreen()}
            </main>

            {showBottomNav && (
                <BottomNav activeScreen={activeScreen} onNavigate={handleNavigate} />
            )}

            <FilterModal 
                isOpen={isFilterModalOpen} 
                onClose={() => setIsFilterModalOpen(false)}
                currentFilters={filters}
                onApplyFilters={(newFilters) => {
                    setFilters(newFilters);
                    addToast('Filters updated.', 'info');
                }}
                initialFilters={INITIAL_FILTERS}
            />

            <PremiumModal 
                isOpen={isPremiumModalOpen}
                onClose={() => setIsPremiumModalOpen(false)}
                onUpgrade={handleUpgradeClick}
            />

            <style>{`
                @keyframes progress-ind {
                    0% { left: -100%; width: 100%; }
                    100% { left: 100%; width: 100%; }
                }
                .animate-progress-ind { animation: progress-ind 1.5s infinite linear; }
            `}</style>
        </div>
    );
};


const App: React.FC = () => {
    return (
        <ToastProvider>
            <AppContent />
        </ToastProvider>
    );
};

export default App;

import React, { useState } from 'react';
import { KnotLogo } from './KnotLogo';
import { EnvelopeIcon } from './icons/EnvelopeIcon';
import { GmailIcon } from './icons/GmailIcon';
import { AppleIcon } from './icons/AppleIcon';

interface AuthScreenProps {
    onLogin: (name?: string) => void;
    onSignUp: (name?: string) => void;
}

const AuthScreen: React.FC<AuthScreenProps> = ({ onLogin, onSignUp }) => {
    const [isLogin, setIsLogin] = useState(true);
    const [showEmailForm, setShowEmailForm] = useState(false);
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');

    const toggleAuthMode = () => {
        setIsLogin(!isLogin);
        setShowEmailForm(false);
    };

    const handleEmailContinue = () => {
        setShowEmailForm(true);
    };

    const handleFormSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (isLogin) {
            onLogin();
        } else {
            onSignUp(name);
        }
    };

    return (
        <div className="min-h-screen bg-brand-light flex flex-col justify-center items-center p-6">
            <KnotLogo className="text-4xl mb-8" />

            <div className="w-full max-w-sm bg-white p-8 rounded-2xl shadow-lg">
                <h1 className="text-2xl font-bold text-center text-brand-dark mb-6">
                    {isLogin ? 'Welcome Back' : 'Create Account'}
                </h1>

                {showEmailForm ? (
                    <form onSubmit={handleFormSubmit} className="space-y-4">
                        {!isLogin && (
                             <div>
                                <label className="text-sm font-medium text-gray-700" htmlFor="name">Name</label>
                                <input 
                                    id="name"
                                    type="text" 
                                    value={name}
                                    onChange={(e) => setName(e.target.value)}
                                    required
                                    className="mt-1 w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-brand-secondary focus:border-brand-secondary"
                                    placeholder="Your Name"
                                />
                            </div>
                        )}
                        <div>
                            <label className="text-sm font-medium text-gray-700" htmlFor="email">Email</label>
                            <input 
                                id="email"
                                type="email" 
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                required
                                className="mt-1 w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-brand-secondary focus:border-brand-secondary"
                                placeholder="you@example.com"
                            />
                        </div>
                        <div>
                            <label className="text-sm font-medium text-gray-700" htmlFor="password">Password</label>
                            <input 
                                id="password"
                                type="password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                                className="mt-1 w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-brand-secondary focus:border-brand-secondary"
                                placeholder="••••••••"
                            />
                        </div>
                         <button 
                            type="submit"
                            className="w-full bg-brand-primary text-white font-bold py-3 rounded-lg hover:bg-brand-secondary transition-colors mt-2"
                        >
                            {isLogin ? 'Log In' : 'Sign Up'}
                        </button>
                    </form>
                ) : (
                    <div className="space-y-4">
                        <button onClick={() => onLogin()} className="w-full flex items-center justify-center gap-3 bg-gray-100 text-gray-700 font-semibold py-3 rounded-lg hover:bg-gray-200 transition-colors">
                            <GmailIcon className="w-5 h-5" />
                            Continue with Gmail
                        </button>
                        <button onClick={() => onLogin()} className="w-full flex items-center justify-center gap-3 bg-black text-white font-semibold py-3 rounded-lg hover:bg-gray-800 transition-colors">
                            <AppleIcon className="w-5 h-5" />
                            Continue with Apple
                        </button>
                        <div className="relative flex py-2 items-center">
                            <div className="flex-grow border-t border-gray-300"></div>
                            <span className="flex-shrink mx-4 text-gray-400 text-sm">OR</span>
                            <div className="flex-grow border-t border-gray-300"></div>
                        </div>
                        <button onClick={handleEmailContinue} className="w-full flex items-center justify-center gap-3 bg-gray-100 text-gray-700 font-semibold py-3 rounded-lg hover:bg-gray-200 transition-colors">
                            <EnvelopeIcon className="w-5 h-5" />
                            Continue with Email
                        </button>
                    </div>
                )}

                <p className="text-center text-sm text-gray-500 mt-6">
                    {isLogin ? "Don't have an account?" : "Already have an account?"}{' '}
                    <button onClick={toggleAuthMode} className="font-semibold text-brand-primary hover:underline">
                        {isLogin ? 'Sign Up' : 'Log In'}
                    </button>
                </p>
            </div>
        </div>
    );
};

export default AuthScreen;

import React, { useState } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';

interface OnboardingFlowProps {
  user: User;
  onComplete: (updatedUser: User) => void;
}

const OnboardingFlow: React.FC<OnboardingFlowProps> = ({ user, onComplete }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<User>(user);

  const totalSteps = 4;

  const handleNext = () => {
    if (step < totalSteps) {
      setStep(step + 1);
    } else {
      onComplete(formData);
    }
  };

  const handlePrev = () => {
    if (step > 1) setStep(step - 1);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const inputClass = "w-full p-3 border border-gray-200 rounded-xl bg-white text-brand-dark focus:ring-2 focus:ring-brand-primary focus:outline-none shadow-sm";
  const labelClass = "block text-sm font-bold text-gray-600 mb-2 uppercase tracking-tight";

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col p-6 pb-24 relative">
      {/* Progress Header */}
      <div className="mb-8">
        <div className="flex justify-between items-center mb-2">
            <span className="text-xs font-black text-brand-primary uppercase">Step {step} of {totalSteps}</span>
            <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">{Math.round((step / totalSteps) * 100)}% Complete</span>
        </div>
        <div className="w-full h-2 bg-gray-200 rounded-full overflow-hidden">
            <div className="h-full bg-brand-primary transition-all duration-500 ease-out" style={{ width: `${(step / totalSteps) * 100}%` }}></div>
        </div>
      </div>

      <div className="flex-1 animate-fade-in">
        {step === 1 && (
          <div className="space-y-6">
            <h2 className="text-3xl font-black text-brand-dark">The Basics</h2>
            <p className="text-gray-500">Let's start with who you are. This information will be your digital first impression.</p>
            <div className="space-y-4">
              <div>
                <label className={labelClass}>Full Name</label>
                <input name="name" value={formData.name} onChange={handleChange} className={inputClass} placeholder="e.g. Sarah Jenkins" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className={labelClass}>Age</label>
                    <input type="number" name="age" value={formData.age} onChange={handleChange} className={inputClass} />
                 </div>
                 <div>
                    <label className={labelClass}>Occupation</label>
                    <input name="occupation" value={formData.occupation} onChange={handleChange} className={inputClass} />
                 </div>
              </div>
              <div>
                <label className={labelClass}>About You</label>
                <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className={inputClass} placeholder="Tell us about your life, passions, and journey..." />
              </div>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6">
            <h2 className="text-3xl font-black text-brand-dark">Lifestyle & Background</h2>
            <p className="text-gray-500">Compatibility is key. Help us find matches that share your way of life.</p>
            <div className="space-y-4">
              <div>
                <label className={labelClass}>Religion / Beliefs</label>
                <input name="religion" value={formData.religion} onChange={handleChange} className={inputClass} placeholder="e.g. Christian, Spiritual, None" />
              </div>
              <div>
                <label className={labelClass}>Cultural Background</label>
                <input name="culturalBackground" value={formData.culturalBackground} onChange={handleChange} className={inputClass} placeholder="e.g. African American, Mediterranean" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelClass}>Smoking</label>
                  <select name="smoking" value={formData.smoking} onChange={handleChange} className={inputClass}>
                    {Object.values(SmokingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelClass}>Drinking</label>
                  <select name="drinking" value={formData.drinking} onChange={handleChange} className={inputClass}>
                    {Object.values(DrinkingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6">
            <h2 className="text-3xl font-black text-brand-dark">Commitment Readiness</h2>
            <p className="text-gray-500">Knot is for serious seekers. Define your marriage roadmap.</p>
            <div className="space-y-4">
              <div>
                <label className={labelClass}>Desired Marriage Timeline</label>
                <input name="marriageTimeline" value={formData.marriageTimeline} onChange={handleChange} className={inputClass} placeholder="e.g. Within 1 year, 2-3 years" />
              </div>
              <div>
                <label className={labelClass}>Children Preference</label>
                <select name="childrenPreference" value={formData.childrenPreference} onChange={handleChange} className={inputClass}>
                  {Object.values(ChildrenPreference).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
              <div>
                <label className={labelClass}>Willingness to Relocate</label>
                <select name="willingToRelocate" value={formData.willingToRelocate} onChange={handleChange} className={inputClass}>
                  {Object.values(WillingToRelocate).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-6">
            <h2 className="text-3xl font-black text-brand-dark">Final Touch</h2>
            <p className="text-gray-500">A clear face photo increases your matching success by 80%. Select your primary photo.</p>
            <div className="space-y-4 text-center">
              <div className="relative inline-block w-48 h-48 mx-auto">
                 <img src={formData.profileImageUrls[0]} className="w-full h-full object-cover rounded-3xl shadow-lg border-4 border-white" />
                 <button className="absolute -bottom-2 -right-2 bg-brand-primary text-white p-3 rounded-full shadow-md">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M4 5a2 2 0 012-2h8a2 2 0 012 2v10a2 2 0 01-2 2H6a2 2 0 01-2-2V5zm3 1a1 1 0 112 0 1 1 0 01-2 0zm7 7a1 1 0 100-2 1 1 0 000 2z" clipRule="evenodd" />
                    </svg>
                 </button>
              </div>
              <p className="text-xs text-gray-400 italic">Tap to change photo. You can add more later in your profile settings.</p>
            </div>
          </div>
        )}
      </div>

      {/* Footer Nav */}
      <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto p-6 bg-gray-50 flex items-center gap-4">
        {step > 1 && (
          <button onClick={handlePrev} className="px-6 py-4 rounded-2xl border border-gray-200 text-gray-500 font-bold hover:bg-white transition-colors">
            Back
          </button>
        )}
        <button onClick={handleNext} className="flex-1 bg-brand-primary text-white font-black py-4 rounded-2xl text-lg hover:bg-brand-secondary transition-all shadow-xl active:scale-95">
          {step === totalSteps ? 'Complete Registry' : 'Continue'}
        </button>
      </div>

      <style>{`
        .animate-fade-in { animation: fadeIn 0.4s ease-out forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

export default OnboardingFlow;

import React, { useState } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';

interface OnboardingFlowProps {
  user: User;
  onComplete: (updatedUser: User) => void;
}

const OnboardingFlow: React.FC<OnboardingFlowProps> = ({ user, onComplete }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<User>(user);

  const totalSteps = 4;

  const handleNext = () => {
    if (step < totalSteps) {
      setStep(step + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      onComplete(formData);
    }
  };

  const handlePrev = () => {
    if (step > 1) {
      setStep(step - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const inputClass = "w-full p-4 border border-gray-200 rounded-2xl bg-white text-brand-dark focus:ring-2 focus:ring-brand-primary focus:border-transparent focus:outline-none shadow-sm transition-all";
  const labelClass = "block text-xs font-black text-gray-400 mb-2 uppercase tracking-widest";

  return (
    <div className="min-h-screen bg-white flex flex-col p-6 pb-32 relative font-sans">
      {/* Progress Header */}
      <div className="mb-10">
        <div className="flex justify-between items-end mb-3">
            <div>
                <h4 className="text-[10px] font-black text-brand-primary uppercase tracking-[0.2em]">Knot Registry</h4>
                <h2 className="text-2xl font-black text-brand-dark">Build Your Profile</h2>
            </div>
            <span className="text-xs font-bold text-gray-300 uppercase tracking-widest">{step}/{totalSteps}</span>
        </div>
        <div className="w-full h-1.5 bg-gray-100 rounded-full overflow-hidden">
            <div 
                className="h-full bg-brand-primary transition-all duration-700 ease-in-out" 
                style={{ width: `${(step / totalSteps) * 100}%` }}
            ></div>
        </div>
      </div>

      <div className="flex-1 animate-slide-in">
        {step === 1 && (
          <div className="space-y-8">
            <div>
                <h3 className="text-3xl font-serif text-brand-primary mb-2">The Basics</h3>
                <p className="text-gray-500 text-sm leading-relaxed">Tell the registry about your identity. Clear information leads to better compatibility scores.</p>
            </div>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Full Name</label>
                <input name="name" value={formData.name} onChange={handleChange} className={inputClass} placeholder="Sarah Jenkins" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className={labelClass}>Your Age</label>
                    <input type="number" name="age" value={formData.age} onChange={handleChange} className={inputClass} />
                 </div>
                 <div>
                    <label className={labelClass}>Occupation</label>
                    <input name="occupation" value={formData.occupation} onChange={handleChange} className={inputClass} placeholder="e.g. Architect" />
                 </div>
              </div>
              <div>
                <label className={labelClass}>Marriage-Oriented Bio</label>
                <textarea 
                    name="bio" 
                    rows={4} 
                    value={formData.bio} 
                    onChange={handleChange} 
                    className={inputClass} 
                    placeholder="What are you looking for in a life partner? Share your values and vision for a family..." 
                />
              </div>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-8">
            <div>
                <h3 className="text-3xl font-serif text-brand-primary mb-2">Lifestyle & Values</h3>
                <p className="text-gray-500 text-sm leading-relaxed">Shared values are the foundation of a lasting marriage. Be honest about your way of life.</p>
            </div>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Religion / Faith</label>
                <input name="religion" value={formData.religion} onChange={handleChange} className={inputClass} placeholder="e.g. Christian, Muslim, Secular" />
              </div>
              <div>
                <label className={labelClass}>Cultural / Ethnic Roots</label>
                <input name="culturalBackground" value={formData.culturalBackground} onChange={handleChange} className={inputClass} placeholder="e.g. South Asian, Hispanic" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelClass}>Smoking</label>
                  <select name="smoking" value={formData.smoking} onChange={handleChange} className={inputClass}>
                    {Object.values(SmokingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelClass}>Drinking</label>
                  <select name="drinking" value={formData.drinking} onChange={handleChange} className={inputClass}>
                    {Object.values(DrinkingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-8">
            <div>
                <h3 className="text-3xl font-serif text-brand-primary mb-2">Commitment</h3>
                <p className="text-gray-500 text-sm leading-relaxed">Knot matches users based on their marriage timeline and relocation readiness.</p>
            </div>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Ideal Marriage Timeline</label>
                <select name="marriageTimeline" value={formData.marriageTimeline} onChange={handleChange} className={inputClass}>
                    <option value="ASAP">As soon as I find the one</option>
                    <option value="1-2 years">Within 1-2 years</option>
                    <option value="3+ years">3+ years</option>
                    <option value="Not sure">Not sure yet</option>
                </select>
              </div>
              <div>
                <label className={labelClass}>Future Children</label>
                <select name="childrenPreference" value={formData.childrenPreference} onChange={handleChange} className={inputClass}>
                  {Object.values(ChildrenPreference).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
              <div>
                <label className={labelClass}>Relocation Willingness</label>
                <select name="willingToRelocate" value={formData.willingToRelocate} onChange={handleChange} className={inputClass}>
                  {Object.values(WillingToRelocate).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-8 text-center">
            <div>
                <h3 className="text-3xl font-serif text-brand-primary mb-2">Your Registry Photo</h3>
                <p className="text-gray-500 text-sm leading-relaxed">Profiles with clear, friendly photos receive 5x more quality matches.</p>
            </div>
            <div className="relative inline-block w-64 h-64 mx-auto group">
                 <img 
                    src={formData.profileImageUrls[0] || 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=800&auto=format&fit=crop'} 
                    className="w-full h-full object-cover rounded-[3rem] shadow-2xl border-[6px] border-brand-light group-hover:scale-[1.02] transition-transform duration-500" 
                 />
                 <button className="absolute -bottom-4 -right-4 bg-brand-primary text-white p-5 rounded-full shadow-2xl hover:bg-brand-secondary transition-colors">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
                    </svg>
                 </button>
            </div>
            <div className="pt-4 px-6 text-gray-400 text-xs italic">
                By completing the registry, you agree to our Community Guidelines focused on serious, respectful commitment.
            </div>
          </div>
        )}
      </div>

      {/* Persistent Footer Navigation */}
      <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto p-6 bg-white/90 backdrop-blur-md border-t border-gray-100 flex items-center gap-4 z-30">
        {step > 1 && (
          <button 
            onClick={handlePrev} 
            className="px-8 py-4 rounded-2xl border border-gray-200 text-gray-400 font-bold hover:bg-gray-50 active:scale-95 transition-all"
          >
            Back
          </button>
        )}
        <button 
            onClick={handleNext} 
            className="flex-1 bg-brand-primary text-white font-black py-4 rounded-2xl text-lg hover:bg-brand-secondary transition-all shadow-xl shadow-brand-primary/20 active:scale-95 flex items-center justify-center gap-2"
        >
          <span>{step === totalSteps ? 'Complete Registry' : 'Continue'}</span>
          {step < totalSteps && (
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M10.293 3.293a1 1 0 011.414 0l6 6a1 1 0 010 1.414l-6 6a1 1 0 01-1.414-1.414L14.586 11H3a1 1 0 110-2h11.586l-4.293-4.293a1 1 0 010-1.414z" clipRule="evenodd" />
              </svg>
          )}
        </button>
      </div>

      <style>{`
        .animate-slide-in { animation: slideIn 0.5s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        @keyframes slideIn { from { opacity: 0; transform: translateX(20px); } to { opacity: 1; transform: translateX(0); } }
      `}</style>
    </div>
  );
};

export default OnboardingFlow;

import React, { useState, useEffect, useCallback } from 'react';
import { User, Match, Screen, FilterState, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from './types';
import { INITIAL_FILTERS, CURRENT_USER } from './constants';
import { db } from './services/databaseService';
import { queryGlobalRegistry } from './services/matchingService';
import Header from './components/Header';
import BottomNav from './components/BottomNav';
import MatchCard from './components/MatchCard';
import ProfileDetailScreen from './components/ProfileDetailScreen';
import ChatScreen from './components/ChatScreen';
import VideoCallScreen from './components/VideoCallScreen';
import ProfileCard from './components/ProfileCard';
import VerificationScreen from './components/VerificationScreen';
import EditProfileScreen from './components/EditProfileScreen';
import PhotoManagerScreen from './components/PhotoManagerScreen';
import AuthScreen from './components/AuthScreen';
import LikesScreen from './components/LikesScreen';
import PremiumModal from './components/PremiumModal';
import MessagesScreen from './components/MessagesScreen';
import ResourceCard from './components/ResourceCard';
import FilterModal from './components/FilterModal';
import PaymentScreen from './components/PaymentScreen';
import GlobalActivityTicker from './components/GlobalActivityTicker';
import OnboardingFlow from './components/OnboardingFlow';
import { FilterIcon } from './components/icons/FilterIcon';
import { SparklesIcon } from './components/icons/SparklesIcon';
import { RESOURCES_DATA } from './constants';
import { ToastProvider, useToast } from './components/feedback/useToast';

const AppContent: React.FC = () => {
    const [user, setUser] = useState<User | null>(null);
    const [matches, setMatches] = useState<Match[]>([]);
    const [isLoggedIn, setIsLoggedIn] = useState(false);
    const [activeScreen, setActiveScreen] = useState<Screen>('home');
    const [selectedMatch, setSelectedMatch] = useState<Match | null>(null);
    const [filters, setFilters] = useState<FilterState>(INITIAL_FILTERS);
    const [isFilterModalOpen, setIsFilterModalOpen] = useState(false);
    const [isPremiumModalOpen, setIsPremiumModalOpen] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);
    const { addToast } = useToast();

    // Initial load from "backend"
    useEffect(() => {
        const loadData = async () => {
            const userData = await db.getUser();
            const matchesData = await db.getMatches();
            setUser(userData);
            setMatches(matchesData);
        };
        loadData();
    }, []);

    const fetchMoreFromGlobalRegistry = useCallback(async (isSilent = false) => {
        if (isSyncing) return;
        setIsSyncing(true);
        if (!isSilent) addToast("Updating from Global Registry...", "info");

        try {
            const newMatches = await queryGlobalRegistry(3);
            if (newMatches.length > 0) {
                await db.addGlobalMatches(newMatches);
                const updatedMatches = await db.getMatches();
                setMatches(updatedMatches);
                if (!isSilent) addToast(`Found ${newMatches.length} new profiles.`, "success");
            }
        } catch (e) {
            if (!isSilent) addToast("Registry sync failed.", "error");
        } finally {
            setIsSyncing(false);
        }
    }, [isSyncing, addToast]);

    const handleLogin = (isNewUser: boolean = false, name?: string) => {
        if (isNewUser) {
            const newUserTemplate: User = {
                ...CURRENT_USER,
                id: `user_${Date.now()}`,
                name: name || 'New User',
                bio: '',
                age: 25,
                isVerified: false,
                isPremium: false,
                profileImageUrls: ['https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=800&auto=format&fit=crop'],
                personalValues: [],
                occupation: '',
                marriageTimeline: '1-2 years',
                maritalStatus: MaritalStatus.NeverMarried,
                childrenPreference: ChildrenPreference.OpenToChildren,
                willingToRelocate: WillingToRelocate.Maybe,
            };
            setUser(newUserTemplate);
            db.saveUser(newUserTemplate);
            setIsLoggedIn(true);
            setActiveScreen('onboarding');
        } else {
            setIsLoggedIn(true);
            setActiveScreen('home');
            setTimeout(() => fetchMoreFromGlobalRegistry(true), 500);
        }
    };

    const handleNavigate = (screen: Screen) => {
        if (screen === 'likes' && user && !user.isPremium) {
            setIsPremiumModalOpen(true);
        } else {
            setActiveScreen(screen);
        }
    };

    const handleCardClick = (match: Match) => {
        setSelectedMatch(match);
        setActiveScreen('profileDetail');
    };

    const handleStartChat = (match: Match) => {
        if (user && !user.isPremium) {
            setIsPremiumModalOpen(true);
            return;
        }
        setSelectedMatch(match);
        setActiveScreen('chat');
    };

    const handleStartCall = (match: Match) => {
        if (user && !user.isPremium) {
            setIsPremiumModalOpen(true);
            return;
        }
        setSelectedMatch(match);
        setActiveScreen('videoCall');
    };

    const handleBack = () => {
        if (activeScreen === 'chat' || activeScreen === 'videoCall') {
            setActiveScreen('profileDetail');
        } else if (activeScreen === 'profileDetail' || activeScreen === 'payment') {
            setActiveScreen('home');
            setSelectedMatch(null);
        } else if (['verification', 'editProfile', 'managePhotos'].includes(activeScreen)) {
            setActiveScreen('profile');
            setSelectedMatch(null);
        } else {
            setActiveScreen('home');
            setSelectedMatch(null);
        }
    };

    const handleUpgradeClick = () => {
        setIsPremiumModalOpen(false);
        setActiveScreen('payment');
    };

    const handleSubscribe = () => {
        if (user) {
            const updated = { ...user, isPremium: true };
            setUser(updated);
            db.saveUser(updated);
        }
        addToast('Welcome to Premium!', 'success');
        setActiveScreen('likes'); 
    };

    const handleSaveProfile = (updatedUser: User) => {
        setUser(updatedUser);
        db.saveUser(updatedUser);
        addToast('Knot Registry updated!', 'success');
        if (activeScreen === 'onboarding') {
            setActiveScreen('home');
            setTimeout(() => fetchMoreFromGlobalRegistry(true), 500);
        } else {
            handleBack();
        }
    };

    const handleVerificationComplete = () => {
        if (user) {
            const updated = {...user, isVerified: true};
            setUser(updated);
            db.saveUser(updated);
        }
        setActiveScreen('profile');
    };

    const handleUpdatePhotos = (photos: string[]) => {
        if (user) {
            const updated = {...user, profileImageUrls: photos};
            setUser(updated);
            db.saveUser(updated);
        }
        addToast('Photos updated!', 'success');
        handleBack();
    };

    const filteredMatches = matches.filter(match => {
        const ageMatch = match.age >= filters.ageRange[0] && match.age <= filters.ageRange[1];
        const locationMatch = filters.location ? (match.city?.toLowerCase().includes(filters.location.toLowerCase()) || match.country?.toLowerCase().includes(filters.location.toLowerCase())) : true;
        const verifiedMatch = filters.showVerifiedOnly ? match.isVerified : true;
        return ageMatch && locationMatch && verifiedMatch;
    });

    if (!isLoggedIn) {
        return <AuthScreen onLogin={(name) => handleLogin(false, name)} onSignUp={(name) => handleLogin(true, name)} />;
    }

    if (!user) return <div className="h-screen flex items-center justify-center">Accessing Knot Registry...</div>;

    const renderScreen = () => {
        if (selectedMatch) {
            switch(activeScreen) {
                case 'profileDetail':
                    return <ProfileDetailScreen match={selectedMatch} user={user} onBack={handleBack} onStartChat={handleStartChat} onStartCall={handleStartCall} />;
                case 'chat':
                    return <ChatScreen match={selectedMatch} user={user} onBack={handleBack} onStartCall={handleStartCall} />;
                case 'videoCall':
                    return <VideoCallScreen match={selectedMatch} user={user} onEndCall={handleBack} />;
            }
        }

        switch (activeScreen) {
            case 'onboarding':
                return <OnboardingFlow user={user} onComplete={handleSaveProfile} />;
            case 'home':
                return (
                    <div className="p-4 space-y-4 pb-32">
                        {filteredMatches.map(match => (
                            <MatchCard key={match.id} match={match} onCardClick={handleCardClick} />
                        ))}

                        <div className="pt-8 pb-4 flex flex-col items-center">
                            <button 
                                onClick={() => fetchMoreFromGlobalRegistry(false)} 
                                disabled={isSyncing}
                                className="flex items-center gap-2 bg-white border border-brand-primary/20 text-brand-primary font-bold px-8 py-3 rounded-full shadow-sm hover:shadow-md transition-all active:scale-95 disabled:opacity-50"
                            >
                                {isSyncing ? (
                                    <div className="w-5 h-5 border-2 border-brand-primary border-t-transparent rounded-full animate-spin"></div>
                                ) : (
                                    <SparklesIcon className="w-5 h-5" />
                                )}
                                <span>{isSyncing ? 'Synchronizing Registry...' : 'Discover More Globally'}</span>
                            </button>
                        </div>
                    </div>
                );
            case 'likes':
                 return <LikesScreen likedMatches={[]} onMatchClick={handleCardClick} />;
            case 'messages':
                return <MessagesScreen onChatSelect={handleStartChat} user={user} />;
            case 'resources':
                return (
                    <div className="p-4 space-y-4 pb-24">
                        <h1 className="text-2xl font-bold text-brand-dark text-center py-4">Marriage & Commitment</h1>
                        {RESOURCES_DATA.map(resource => (
                           <ResourceCard key={resource.id} resource={resource} />
                        ))}
                    </div>
                );
            case 'profile':
                return <ProfileCard 
                    user={user} 
                    onEditProfile={() => setActiveScreen('editProfile')} 
                    onManagePhotos={() => setActiveScreen('managePhotos')}
                    onVerifyProfile={() => setActiveScreen('verification')}
                />;
            case 'verification':
                return <VerificationScreen onVerificationComplete={handleVerificationComplete} onBack={handleBack} />;
            case 'editProfile':
                return <EditProfileScreen user={user} onBack={handleBack} onSave={handleSaveProfile} />;
            case 'managePhotos':
                return <PhotoManagerScreen user={user} onBack={handleBack} onUpdatePhotos={handleUpdatePhotos} />;
            case 'payment':
                return <PaymentScreen onBack={handleBack} onSubscribe={handleSubscribe} />;
            default:
                return <div>Home</div>;
        }
    };

    const showHeader = ['home', 'likes', 'messages', 'resources', 'profile'].includes(activeScreen);
    const showBottomNav = ['home', 'likes', 'messages', 'resources', 'profile'].includes(activeScreen);

    return (
        <div className="max-w-md mx-auto bg-gray-50 min-h-screen font-sans">
            {showHeader && (
                <div className="fixed top-0 left-0 right-0 max-w-md mx-auto z-20">
                    <GlobalActivityTicker />
                    <Header />
                    {isSyncing && (
                        <div className="h-0.5 w-full bg-brand-light relative overflow-hidden">
                            <div className="absolute inset-0 bg-brand-primary animate-progress-ind"></div>
                        </div>
                    )}
                </div>
            )}

            {activeScreen === 'home' && (
                <div className="fixed top-[5.75rem] left-0 right-0 max-w-md mx-auto z-10 bg-white p-2 border-b h-[3.25rem] flex items-center shadow-sm">
                    <button onClick={() => setIsFilterModalOpen(true)} className="flex items-center gap-2 text-sm text-gray-600 font-semibold p-2 rounded-md hover:bg-gray-100">
                        <FilterIcon className="w-5 h-5" />
                        <span>Filter Matches</span>
                    </button>
