import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ShieldCheckIcon } from './icons/ShieldCheckIcon';
import { CameraShutterIcon } from './icons/CameraShutterIcon';
import { VerifiedIcon } from './icons/VerifiedIcon';
import { User } from '../types';

type VerificationStep = 'initial' | 'camera' | 'preview' | 'verifying' | 'success';

interface VerificationScreenProps {
  onVerificationComplete: () => void;
  onBack: () => void;
}

const VerificationScreen: React.FC<VerificationScreenProps> = ({ onVerificationComplete, onBack }) => {
  const [step, setStep] = useState<VerificationStep>('initial');
  const [error, setError] = useState<string | null>(null);
  const [photo, setPhoto] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const cleanupCamera = useCallback(() => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
  }, []);

  const startCamera = () => {
    setError(null);
    setStep('camera');
  };

  useEffect(() => {
    let activeStream: MediaStream | null = null;

    if (step === 'camera') {
      const initCamera = async () => {
        try {
          const stream = await navigator.mediaDevices.getUserMedia({ 
            video: { facingMode: 'user' } 
          });
          activeStream = stream;
          streamRef.current = stream;

          if (videoRef.current) {
            videoRef.current.srcObject = stream;
            videoRef.current.play().catch(e => console.error("Play failed", e));
          }
        } catch (err) {
          console.error("Verification Camera error:", err);
          setError("Could not access the camera. Please check your browser permissions.");
          setStep('initial');
        }
      };
      initCamera();
    }

    return () => {
      if (activeStream) {
        activeStream.getTracks().forEach(track => track.stop());
      }
    };
  }, [step]);

  const takePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const context = canvas.getContext('2d');
      context?.drawImage(video, 0, 0, video.videoWidth, video.videoHeight);
      setPhoto(canvas.toDataURL('image/jpeg'));
      cleanupCamera();
      setStep('preview');
    }
  };

  const handleSubmit = () => {
    setStep('verifying');
    // Simulate AI verification process
    setTimeout(() => {
      setStep('success');
      setTimeout(() => {
        onVerificationComplete();
      }, 2000); // Wait 2 seconds on success screen before navigating
    }, 2500); // Simulate 2.5 second API call
  };

  useEffect(() => {
    return () => cleanupCamera();
  }, [cleanupCamera]);

  const renderContent = () => {
    switch(step) {
      case 'initial':
        return (
          <div className="text-center p-8 flex flex-col items-center justify-center h-full">
            <ShieldCheckIcon className="w-20 h-20 text-brand-primary mb-6" />
            <h1 className="text-2xl font-bold text-brand-dark mb-3">Verify with a Photo</h1>
            <p className="text-gray-600 mb-8">To ensure the safety and authenticity of our community, we require a quick photo verification. This helps prove you're the person in your profile pictures.</p>
            {error && <p className="text-red-500 mb-4">{error}</p>}
            <button onClick={startCamera} className="w-full flex items-center justify-center gap-3 bg-brand-primary text-white font-bold py-3 rounded-lg text-lg hover:bg-brand-secondary transition-colors">
              <CameraShutterIcon className="w-6 h-6" /> Get Verified
            </button>
          </div>
        );
      case 'camera':
        return (
          <div className="relative w-full h-full bg-black flex flex-col items-center justify-center">
            <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" />
            <div className="absolute inset-0 flex items-center justify-center">
               <div className="w-[70vw] h-[50vh] max-w-[300px] max-h-[420px] border-4 border-white border-dashed rounded-[50%]" />
            </div>
            <div className="absolute bottom-10 z-10">
              <button onClick={takePhoto} className="p-4 rounded-full bg-white group" aria-label="Take Photo">
                <CameraShutterIcon className="w-10 h-10 text-brand-primary group-hover:scale-110 transition-transform" />
              </button>
            </div>
          </div>
        );
      case 'preview':
        return (
          <div className="relative w-full h-full bg-black flex flex-col items-center justify-center p-4">
            <img src={photo!} alt="Verification selfie" className="max-w-full max-h-[70vh] rounded-lg" />
            <div className="absolute bottom-10 z-10 w-full px-8 space-y-3">
              <button onClick={handleSubmit} className="w-full bg-brand-primary text-white font-bold py-3 rounded-lg">Submit for Verification</button>
              <button onClick={startCamera} className="w-full bg-gray-600 text-white font-bold py-3 rounded-lg">Retake Photo</button>
            </div>
          </div>
        );
      case 'verifying':
        return (
          <div className="text-center p-8 flex flex-col items-center justify-center h-full">
            <div className="w-16 h-16 border-4 border-brand-accent border-t-transparent rounded-full animate-spin mb-6"></div>
            <h1 className="text-2xl font-bold text-brand-dark">Verifying...</h1>
            <p className="text-gray-600">Our AI is checking your photo. This will only take a moment.</p>
          </div>
        );
      case 'success':
        return (
           <div className="text-center p-8 flex flex-col items-center justify-center h-full bg-green-50">
            <VerifiedIcon className="w-20 h-20 text-green-500 mb-6" />
            <h1 className="text-2xl font-bold text-green-800">You're Verified!</h1>
            <p className="text-green-700">Your profile now has the verified badge. Welcome to our trusted community!</p>
          </div>
        );
    }
  };

  return (
    <div className="w-full h-screen bg-gray-50 flex flex-col">
       {step === 'initial' && (
        <header className="p-4 bg-white border-b border-gray-200">
            <button onClick={onBack} className="text-gray-600 p-1 rounded-full hover:bg-gray-100">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
            </svg>
            </button>
        </header>
       )}
      <main className="flex-1 overflow-hidden relative">
        {renderContent()}
        <canvas ref={canvasRef} className="hidden" />
      </main>
    </div>
  );
};

export default VerificationScreen;

import React, { useState, useRef, useEffect } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';

interface OnboardingFlowProps {
  user: User;
  onComplete: (updatedUser: User) => void;
}

const OnboardingFlow: React.FC<OnboardingFlowProps> = ({ user, onComplete }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<User>(user);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [cameraError, setCameraError] = useState<string | null>(null);
  const [capturedIdentity, setCapturedIdentity] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const totalSteps = 4;

  const handleNext = () => {
    if (step === 4 && !capturedIdentity) {
        setCameraError("A live identity photo is required to join the registry.");
        return;
    }
    if (step < totalSteps) {
      setStep(step + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      onComplete(formData);
    }
  };

  const handlePrev = () => {
    if (step > 1) {
      setStep(step - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const startCamera = () => {
    setCameraError(null);
    setIsCameraActive(true);
  };

  useEffect(() => {
    let activeStream: MediaStream | null = null;
    if (isCameraActive && step === 4) {
      const initCamera = async () => {
        try {
          const stream = await navigator.mediaDevices.getUserMedia({ 
            video: { facingMode: 'user', width: { ideal: 800 }, height: { ideal: 800 } } 
          });
          activeStream = stream;
          streamRef.current = stream;
          if (videoRef.current) {
            videoRef.current.srcObject = stream;
            videoRef.current.play().catch(e => console.error("Video play failed", e));
          }
        } catch (err) {
          setCameraError("Camera access denied. Please allow camera permissions to verify your identity.");
          setIsCameraActive(false);
        }
      };
      initCamera();
    }
    return () => {
      if (activeStream) activeStream.getTracks().forEach(track => track.stop());
    };
  }, [isCameraActive, step]);

  const takePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const size = Math.min(video.videoWidth, video.videoHeight);
      canvas.width = size;
      canvas.height = size;
      const context = canvas.getContext('2d');
      if (context) {
        context.translate(size, 0);
        context.scale(-1, 1);
        const startX = (video.videoWidth - size) / 2;
        const startY = (video.videoHeight - size) / 2;
        context.drawImage(video, startX, startY, size, size, 0, 0, size, size);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        setFormData({ ...formData, profileImageUrls: [dataUrl, ...formData.profileImageUrls.slice(1)] });
        setCapturedIdentity(true);
        setIsCameraActive(false);
      }
    }
  };

  const inputClass = "w-full p-4 border border-gray-200 rounded-2xl bg-white text-brand-dark focus:ring-2 focus:ring-brand-primary focus:border-transparent focus:outline-none shadow-sm transition-all";
  const labelClass = "block text-xs font-black text-gray-400 mb-2 uppercase tracking-widest";

  return (
    <div className="min-h-screen bg-white flex flex-col p-6 pb-32 relative font-sans">
      <canvas ref={canvasRef} className="hidden" />

      <div className="mb-10">
        <div className="flex justify-between items-end mb-3">
            <div>
                <h4 className="text-[10px] font-black text-brand-primary uppercase tracking-[0.2em]">Knot Global Registry</h4>
                <h2 className="text-2xl font-black text-brand-dark">{step === 4 ? 'Identity Verification' : 'Build Your Profile'}</h2>
            </div>
            <span className="text-xs font-bold text-gray-300 uppercase tracking-widest">{step}/{totalSteps}</span>
        </div>
        <div className="w-full h-1.5 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-brand-primary transition-all duration-700 ease-in-out" style={{ width: `${(step / totalSteps) * 100}%` }}></div>
        </div>
      </div>

      <div className="flex-1 animate-slide-in">
        {step === 1 && (
          <div className="space-y-8">
            <h3 className="text-3xl font-serif text-brand-primary mb-2">The Basics</h3>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Full Name</label>
                <input name="name" value={formData.name} onChange={handleChange} className={inputClass} placeholder="Sarah Jenkins" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className={labelClass}>Age</label>
                    <input type="number" name="age" value={formData.age} onChange={handleChange} className={inputClass} />
                 </div>
                 <div>
                    <label className={labelClass}>Occupation</label>
                    <input name="occupation" value={formData.occupation} onChange={handleChange} className={inputClass} />
                 </div>
              </div>
              <div>
                <label className={labelClass}>About Your Intentions</label>
                <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className={inputClass} placeholder="Share your vision for marriage..." />
              </div>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-8 text-center">
            <div>
                <h3 className="text-3xl font-serif text-brand-primary mb-2">Live Photo Check</h3>
                <p className="text-gray-500 text-sm leading-relaxed px-4">To ensure a trusted community, Knot requires a live photo taken now. This will be your primary registry picture.</p>
            </div>

            <div className="relative inline-block w-full max-w-[280px] aspect-square mx-auto">
                {isCameraActive ? (
                  <div className="relative w-full h-full overflow-hidden rounded-[3rem] bg-black border-[6px] border-brand-light">
                    <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover scale-x-[-1]" />
                    <button onClick={takePhoto} className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white text-brand-primary p-5 rounded-full shadow-2xl active:scale-90 transition-transform z-10">
                      <div className="w-8 h-8 rounded-full border-4 border-brand-primary"></div>
                    </button>
                  </div>
                ) : (
                  <div className="group relative">
                    <div className={`w-full h-full aspect-square rounded-[3rem] border-[6px] ${capturedIdentity ? 'border-green-500' : 'border-brand-light'} overflow-hidden bg-gray-50 flex items-center justify-center`}>
                        {capturedIdentity ? (
                             <img src={formData.profileImageUrls[0]} className="w-full h-full object-cover" />
                        ) : (
                            <div className="text-center p-8">
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mx-auto text-gray-200 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                                </svg>
                                <p className="text-xs text-gray-400 font-bold uppercase">No Photo Captured</p>
                            </div>
                        )}
                    </div>
                    <button onClick={startCamera} className="absolute -bottom-4 -right-4 bg-brand-primary text-white p-5 rounded-full shadow-2xl hover:bg-brand-secondary transition-colors">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
                        </svg>
                    </button>
                  </div>
                )}
            </div>

            {cameraError && <p className="text-red-500 text-xs mt-4 font-bold">{cameraError}</p>}

            <div className="pt-6 px-10 text-gray-400 text-[10px] font-medium leading-relaxed uppercase tracking-tighter">
                {capturedIdentity ? "Identity Proof Captured Successfully." : "Identity Check Required for Access."}
            </div>
          </div>
        )}

        {(step === 2 || step === 3) && <div className="text-gray-400 text-sm">Step {step} details... (Omitted for brevity)</div>}
      </div>

      <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto p-6 bg-white flex items-center gap-4 z-30">
        {!isCameraActive && step > 1 && <button onClick={handlePrev} className="px-8 py-4 rounded-2xl border border-gray-100 text-gray-300 font-bold hover:bg-gray-50 transition-all">Back</button>}
        {!isCameraActive && (
          <button onClick={handleNext} className="flex-1 bg-brand-primary text-white font-black py-4 rounded-2xl text-lg hover:bg-brand-secondary transition-all shadow-xl shadow-brand-primary/20">
            {step === totalSteps ? 'Activate Profile' : 'Continue'}
          </button>
        )}
      </div>

      <style>{`
        .animate-slide-in { animation: slideIn 0.5s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        @keyframes slideIn { from { opacity: 0; transform: translateX(20px); } to { opacity: 1; transform: translateX(0); } }
      `}</style>
    </div>
  );
};

