    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const size = Math.min(video.videoWidth, video.videoHeight);
      canvas.width = size;
      canvas.height = size;
      const context = canvas.getContext('2d');
      if (context) {
        // Mirror for front camera selfie
        context.translate(size, 0);
        context.scale(-1, 1);
        const startX = (video.videoWidth - size) / 2;
        const startY = (video.videoHeight - size) / 2;
        context.drawImage(video, startX, startY, size, size, 0, 0, size, size);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        setFormData({ ...formData, profileImageUrls: [dataUrl, ...formData.profileImageUrls.slice(1)] });
        setCapturedIdentity(true);
        setIsCameraActive(false);
      }
    }
  };

  const inputClass = "w-full p-4 border border-gray-200 rounded-2xl bg-white text-brand-dark focus:ring-2 focus:ring-brand-primary focus:border-transparent focus:outline-none shadow-sm transition-all";
  const labelClass = "block text-xs font-black text-gray-400 mb-2 uppercase tracking-widest";

  return (
    <div className="min-h-screen bg-white flex flex-col p-6 pb-32 relative font-sans">
      <canvas ref={canvasRef} className="hidden" />

      <div className="mb-10">
        <div className="flex justify-between items-end mb-3">
            <div>
                <h4 className="text-[10px] font-black text-brand-primary uppercase tracking-[0.2em]">Knot Global Registry</h4>
                <h2 className="text-2xl font-black text-brand-dark">{step === 4 ? 'Identity Proof' : 'Build Your Profile'}</h2>
            </div>
            <span className="text-xs font-bold text-gray-300 uppercase tracking-widest">{step}/{totalSteps}</span>
        </div>
        <div className="w-full h-1.5 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-brand-primary transition-all duration-700 ease-in-out" style={{ width: `${(step / totalSteps) * 100}%` }}></div>
        </div>
      </div>

      <div className="flex-1 animate-slide-in">
        {step === 1 && (
          <div className="space-y-8">
            <h3 className="text-3xl font-serif text-brand-primary mb-2">The Basics</h3>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Full Name</label>
                <input name="name" value={formData.name} onChange={handleChange} className={inputClass} placeholder="Sarah Jenkins" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className={labelClass}>Age</label>
                    <input type="number" name="age" value={formData.age} onChange={handleChange} className={inputClass} />
                 </div>
                 <div>
                    <label className={labelClass}>Occupation</label>
                    <input name="occupation" value={formData.occupation} onChange={handleChange} className={inputClass} />
                 </div>
              </div>
              <div>
                <label className={labelClass}>Your Intentions</label>
                <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className={inputClass} placeholder="Share your vision for marriage..." />
              </div>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-8 text-center">
            <div>
                <h3 className="text-3xl font-serif text-brand-primary mb-2">Live Photo Shutter</h3>
                <p className="text-gray-500 text-sm leading-relaxed px-4">To join the Knot Registry, we require a live capture. This helps ensure every member is genuine.</p>
            </div>

            <div className="relative inline-block w-full max-w-[280px] aspect-square mx-auto">
                {isCameraActive ? (
                  <div className="relative w-full h-full overflow-hidden rounded-[3rem] bg-black border-[6px] border-brand-light shadow-2xl">
                    <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover scale-x-[-1]" />
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                        <div className="w-[80%] h-[80%] border-2 border-white/20 border-dashed rounded-[40%]"></div>
                    </div>
                    <button onClick={takePhoto} className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white text-brand-primary p-5 rounded-full shadow-2xl active:scale-90 transition-transform z-10">
                      <div className="w-8 h-8 rounded-full border-4 border-brand-primary animate-pulse"></div>
                    </button>
                  </div>
                ) : (
                  <div className="group relative">
                    <div className={`w-full h-full aspect-square rounded-[3rem] border-[6px] ${capturedIdentity ? 'border-green-500' : 'border-brand-light'} overflow-hidden bg-gray-50 flex items-center justify-center shadow-xl`}>
                        {capturedIdentity ? (
                             <img src={formData.profileImageUrls[0]} className="w-full h-full object-cover" />
                        ) : (
                            <div className="text-center p-8">
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mx-auto text-gray-200 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                                </svg>
                                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Awaiting Capture</p>
                            </div>
                        )}
                    </div>
                    {!capturedIdentity && (
                        <button onClick={startCamera} className="absolute -bottom-4 -right-4 bg-brand-primary text-white p-5 rounded-full shadow-2xl hover:bg-brand-secondary transition-colors">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
                            </svg>
                        </button>
                    )}
                    {capturedIdentity && (
                         <button onClick={startCamera} className="absolute -bottom-4 -right-4 bg-white text-brand-primary p-3 rounded-full shadow-lg border border-gray-100">
                             <p className="text-[10px] font-black uppercase">Retake</p>
                         </button>
                    )}
                  </div>
                )}
            </div>

            {cameraError && <p className="text-red-500 text-xs mt-4 font-bold">{cameraError}</p>}

            <div className="pt-6 px-10 text-gray-400 text-[10px] font-medium leading-relaxed uppercase tracking-widest">
                {capturedIdentity ? "Liveness check passed." : "Access restricted until identity confirmed."}
            </div>
          </div>
        )}

        {(step === 2 || step === 3) && (
            <div className="space-y-8">
                <h3 className="text-3xl font-serif text-brand-primary mb-2">{step === 2 ? 'Values & Faith' : 'Commitment Timeline'}</h3>
                <p className="text-gray-500 text-sm">Sharing your core values is the first step toward compatibility.</p>
                <div className="h-32 bg-gray-50 rounded-2xl border-2 border-dashed border-gray-100 flex items-center justify-center text-gray-300 text-sm italic">
                    Step {step} fields are configured...
                </div>
            </div>
        )}
      </div>

      <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto p-6 bg-white/90 backdrop-blur-sm flex items-center gap-4 z-30">
        {!isCameraActive && step > 1 && <button onClick={handlePrev} className="px-8 py-4 rounded-2xl border border-gray-100 text-gray-300 font-bold hover:bg-gray-50 transition-all">Back</button>}
        {!isCameraActive && (
          <button onClick={handleNext} className="flex-1 bg-brand-primary text-white font-black py-4 rounded-2xl text-lg hover:bg-brand-secondary transition-all shadow-xl shadow-brand-primary/20 active:scale-95">
            {step === totalSteps ? 'Activate Profile' : 'Continue'}
          </button>
        )}
      </div>

      <style>{`
        .animate-slide-in { animation: slideIn 0.5s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        @keyframes slideIn { from { opacity: 0; transform: translateX(20px); } to { opacity: 1; transform: translateX(0); } }
      `}</style>
    </div>
  );
};

export default OnboardingFlow;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ShieldCheckIcon } from './icons/ShieldCheckIcon';
import { CameraShutterIcon } from './icons/CameraShutterIcon';
import { VerifiedIcon } from './icons/VerifiedIcon';

type VerificationStep = 'initial' | 'camera' | 'preview' | 'verifying' | 'success';

interface VerificationScreenProps {
  onVerificationComplete: () => void;
  onBack: () => void;
}

const VerificationScreen: React.FC<VerificationScreenProps> = ({ onVerificationComplete, onBack }) => {
  const [step, setStep] = useState<VerificationStep>('initial');
  const [error, setError] = useState<string | null>(null);
  const [docPhoto, setDocPhoto] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const startCamera = () => {
    setError(null);
    setStep('camera');
  };

  useEffect(() => {
    let activeStream: MediaStream | null = null;
    if (step === 'camera') {
      const initCamera = async () => {
        try {
          // Use environment camera (back) for document scanning
          const stream = await navigator.mediaDevices.getUserMedia({ 
            video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } } 
          });
          activeStream = stream;
          streamRef.current = stream;
          if (videoRef.current) {
            videoRef.current.srcObject = stream;
            videoRef.current.play().catch(e => console.error("Play failed", e));
          }
        } catch (err) {
          setError("Access to back camera denied. Please check permissions.");
          setStep('initial');
        }
      };
      initCamera();
    }
    return () => { if (activeStream) activeStream.getTracks().forEach(track => track.stop()); };
  }, [step]);

  const takePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const context = canvas.getContext('2d');
      if (context) {
        context.drawImage(video, 0, 0, video.videoWidth, video.videoHeight);
        setDocPhoto(canvas.toDataURL('image/jpeg', 0.9));
        setStep('preview');
      }
    }
  };

  const handleSubmit = () => {
    setStep('verifying');
    // Simulate AI document parsing and validation
    setTimeout(() => {
      setStep('success');
      setTimeout(() => onVerificationComplete(), 2000);
    }, 3500);
  };

  const renderContent = () => {
    switch(step) {
      case 'initial':
        return (
          <div className="text-center p-8 flex flex-col items-center justify-center h-full space-y-8 bg-white">
            <div className="bg-brand-light p-8 rounded-[2rem] shadow-inner">
                <ShieldCheckIcon className="w-20 h-20 text-brand-primary" />
            </div>
            <div>
                <h1 className="text-2xl font-black text-brand-dark mb-2">Trusted Registry Status</h1>
                <p className="text-gray-500 text-sm leading-relaxed px-4">
                    Since you've completed the <b>Live Check</b>, you can now apply for full verification. Please scan your <b>Government ID</b> or <b>Passport</b>.
                </p>
            </div>
            <div className="w-full space-y-3">
                <button onClick={startCamera} className="w-full bg-brand-primary text-white font-black py-4 rounded-2xl shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3">
                   <span>Scan Official Document</span>
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z" />
                   </svg>
                </button>
                <button onClick={onBack} className="w-full text-gray-400 font-bold py-3 text-sm">Maybe Later</button>
            </div>
            {error && <p className="text-red-500 font-bold text-xs bg-red-50 p-2 rounded-lg">{error}</p>}
          </div>
        );
      case 'camera':
        return (
          <div className="relative w-full h-full bg-black flex flex-col items-center justify-center">
            <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" />

            {/* Document Frame Overlay */}
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                <div className="w-[85%] aspect-[1.6/1] border-2 border-brand-accent rounded-xl shadow-[0_0_0_9999px_rgba(0,0,0,0.6)]">
                    <div className="absolute top-4 left-0 right-0 text-center">
                        <span className="bg-brand-accent text-brand-dark px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest">Align Document Within Frame</span>
                    </div>
                </div>
            </div>

            <div className="absolute bottom-10 z-10 w-full px-8 flex justify-between items-center">
              <button onClick={() => setStep('initial')} className="text-white bg-white/10 p-3 rounded-full backdrop-blur-md">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
              <button onClick={takePhoto} className="p-6 rounded-full bg-white shadow-2xl active:scale-90 transition-transform">
                <div className="w-10 h-10 border-4 border-brand-primary rounded-full"></div>
              </button>
              <div className="w-12 h-12"></div> {/* Spacer */}
            </div>
          </div>
        );
      case 'preview':
        return (
          <div className="relative w-full h-full bg-brand-dark flex flex-col p-6 overflow-y-auto">
            <h2 className="text-white text-xl font-black mb-6 text-center pt-8 uppercase tracking-widest">Review Scan</h2>
            <div className="bg-white p-2 rounded-2xl shadow-2xl mb-8">
                <img src={docPhoto!} alt="Document Scan" className="w-full rounded-xl" />
            </div>
            <div className="space-y-4">
                <button onClick={handleSubmit} className="w-full bg-brand-primary text-white font-black py-4 rounded-2xl shadow-xl active:scale-95 transition-all">
                    Verify Document
                </button>
                <button onClick={startCamera} className="w-full bg-white/10 text-white font-bold py-4 rounded-2xl hover:bg-white/20">
                    Retake Scan
                </button>
            </div>
            <p className="text-white/40 text-[10px] text-center mt-6 uppercase leading-relaxed font-bold tracking-tighter">
                By submitting, you consent to Knot Registry's processing of your identity document for authentication purposes only.
            </p>
          </div>
        );
      case 'verifying':
        return (
          <div className="text-center p-8 flex flex-col items-center justify-center h-full bg-white">
            <div className="w-20 h-20 border-8 border-brand-light border-t-brand-primary rounded-full animate-spin mb-8 shadow-inner"></div>
            <h1 className="text-2xl font-black text-brand-dark">Registry Authentication</h1>
            <p className="text-gray-500 text-sm font-medium mt-2 animate-pulse">Our AI is validating your document metadata...</p>
          </div>
        );
      case 'success':
        return (
           <div className="text-center p-8 flex flex-col items-center justify-center h-full bg-brand-primary text-white animate-fade-in">
            <div className="bg-white p-6 rounded-full mb-8 shadow-2xl">
                <VerifiedIcon className="w-24 h-24 text-brand-primary" />
            </div>
            <h1 className="text-3xl font-black mb-2">Trusted Registry Status</h1>
            <p className="text-brand-light/80 text-sm px-8 font-medium">Your identity has been officially authenticated. You now carry the Trusted Registry badge.</p>
          </div>
        );
    }
  };

  return (
    <div className="w-full h-screen bg-gray-50 flex flex-col overflow-hidden">
      <main className="flex-1 relative">
        {renderContent()}
        <canvas ref={canvasRef} className="hidden" />
      </main>
      <style>{`
        .animate-fade-in { animation: fadeIn 0.5s ease-out; }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
      `}</style>
    </div>
  );
};

export default VerificationScreen;

import React, { useState, useRef, useEffect } from 'react';
