                  {Object.values(ChildrenPreference).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
              <div>
                <label className={labelClass}>Relocation Willingness</label>
                <select name="willingToRelocate" value={formData.willingToRelocate} onChange={handleChange} className={inputClass}>
                  {Object.values(WillingToRelocate).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-8 text-center">
            <div>
                <h3 className="text-3xl font-serif text-brand-primary mb-2">Live Photo Shutter</h3>
                <p className="text-gray-500 text-sm leading-relaxed px-4">To join the Knot Registry, we require a live capture. This helps ensure every member is genuine.</p>
            </div>

            <div className="relative inline-block w-full max-w-[280px] aspect-square mx-auto">
                {isCameraActive ? (
                  <div className="relative w-full h-full overflow-hidden rounded-[3rem] bg-black border-[6px] border-brand-light shadow-2xl">
                    <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover scale-x-[-1]" />
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                        <div className="w-[80%] h-[80%] border-2 border-white/20 border-dashed rounded-[40%]"></div>
                    </div>
                    <button onClick={takePhoto} className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white text-brand-primary p-5 rounded-full shadow-2xl active:scale-90 transition-transform z-10">
                      <div className="w-8 h-8 rounded-full border-4 border-brand-primary animate-pulse"></div>
                    </button>
                  </div>
                ) : (
                  <div className="group relative">
                    <div className={`w-full h-full aspect-square rounded-[3rem] border-[6px] ${capturedIdentity ? 'border-green-500' : 'border-brand-light'} overflow-hidden bg-gray-50 flex items-center justify-center shadow-xl`}>
                        {capturedIdentity ? (
                             <img src={formData.profileImageUrls[0]} className="w-full h-full object-cover" />
                        ) : (
                            <div className="text-center p-8">
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mx-auto text-gray-200 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                                </svg>
                                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Awaiting Capture</p>
                            </div>
                        )}
                    </div>
                    {!capturedIdentity && (
                        <button onClick={startCamera} className="absolute -bottom-4 -right-4 bg-brand-primary text-white p-5 rounded-full shadow-2xl hover:bg-brand-secondary transition-colors">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
                            </svg>
                        </button>
                    )}
                    {capturedIdentity && (
                         <button onClick={startCamera} className="absolute -bottom-4 -right-4 bg-white text-brand-primary p-3 rounded-full shadow-lg border border-gray-100">
                             <p className="text-[10px] font-black uppercase">Retake</p>
                         </button>
                    )}
                  </div>
                )}
            </div>

            {cameraError && <p className="text-red-500 text-xs mt-4 font-bold">{cameraError}</p>}

            <div className="pt-6 px-10 text-gray-400 text-[10px] font-medium leading-relaxed uppercase tracking-widest text-center">
                {capturedIdentity ? "Liveness check passed." : "Access restricted until identity confirmed."}
            </div>
          </div>
        )}
      </div>

      <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto p-6 bg-white flex items-center gap-4 z-30">
        {!isCameraActive && step > 1 && <button onClick={handlePrev} className="px-8 py-4 rounded-2xl border border-gray-100 text-gray-300 font-bold hover:bg-gray-50 transition-all">Back</button>}
        {!isCameraActive && (
          <button onClick={handleNext} className="flex-1 bg-brand-primary text-white font-black py-4 rounded-2xl text-lg hover:bg-brand-secondary transition-all shadow-xl shadow-brand-primary/20 active:scale-95">
            {step === totalSteps ? 'Activate Profile' : 'Continue'}
          </button>
        )}
      </div>

      <style>{`
        .animate-slide-in { animation: slideIn 0.5s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        @keyframes slideIn { from { opacity: 0; transform: translateX(20px); } to { opacity: 1; transform: translateX(0); } }
      `}</style>
    </div>
  );
};

