import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ShieldCheckIcon } from './icons/ShieldCheckIcon';
import { CameraShutterIcon } from './icons/CameraShutterIcon';
import { VerifiedIcon } from './icons/VerifiedIcon';

type VerificationStep = 'initial' | 'camera' | 'preview' | 'verifying' | 'success';

interface VerificationScreenProps {
  onVerificationComplete: () => void;
  onBack: () => void;
}

const VerificationScreen: React.FC<VerificationScreenProps> = ({ onVerificationComplete, onBack }) => {
  const [step, setStep] = useState<VerificationStep>('initial');
  const [error, setError] = useState<string | null>(null);
  const [docPhoto, setDocPhoto] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const startCamera = () => {
    setError(null);
    setStep('camera');
  };

  useEffect(() => {
    let activeStream: MediaStream | null = null;
    if (step === 'camera') {
      const initCamera = async () => {
        try {
          // Use environment camera (back) for document scanning
          const stream = await navigator.mediaDevices.getUserMedia({ 
            video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } } 
          });
          activeStream = stream;
          streamRef.current = stream;
          if (videoRef.current) {
            videoRef.current.srcObject = stream;
            videoRef.current.play().catch(e => console.error("Play failed", e));
          }
        } catch (err) {
          setError("Access to back camera denied. Please check permissions.");
          setStep('initial');
        }
      };
      initCamera();
    }
    return () => { if (activeStream) activeStream.getTracks().forEach(track => track.stop()); };
  }, [step]);

  const takePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const context = canvas.getContext('2d');
      if (context) {
        context.drawImage(video, 0, 0, video.videoWidth, video.videoHeight);
        setDocPhoto(canvas.toDataURL('image/jpeg', 0.9));
        setStep('preview');
      }
    }
  };

  const handleSubmit = () => {
    setStep('verifying');
    // Simulate AI document parsing and validation
    setTimeout(() => {
      setStep('success');
      setTimeout(() => onVerificationComplete(), 2000);
    }, 3500);
  };

  const renderContent = () => {
    switch(step) {
      case 'initial':
        return (
          <div className="text-center p-8 flex flex-col items-center justify-center h-full space-y-8 bg-white">
            <div className="bg-brand-light p-8 rounded-[2rem] shadow-inner">
                <ShieldCheckIcon className="w-20 h-20 text-brand-primary" />
            </div>
            <div>
                <h1 className="text-2xl font-black text-brand-dark mb-2">Trusted Registry Status</h1>
                <p className="text-gray-500 text-sm leading-relaxed px-4 mb-6">
                    Since you've completed the <b>Live Check</b>, you can now apply for full verification. We accept the following valid documents:
                </p>
                <div className="space-y-3 px-6 mb-8">
                    <div className="flex items-center gap-3 bg-gray-50 p-4 rounded-2xl border border-gray-100">
                        <div className="w-2 h-2 bg-brand-primary rounded-full"></div>
                        <span className="text-xs font-bold text-brand-dark uppercase tracking-tight">International Passport</span>
                    </div>
                    <div className="flex items-center gap-3 bg-gray-50 p-4 rounded-2xl border border-gray-100">
                        <div className="w-2 h-2 bg-brand-primary rounded-full"></div>
                        <span className="text-xs font-bold text-brand-dark uppercase tracking-tight">National ID Card</span>
                    </div>
                    <div className="flex items-center gap-3 bg-gray-50 p-4 rounded-2xl border border-gray-100">
                        <div className="w-2 h-2 bg-brand-primary rounded-full"></div>
                        <span className="text-xs font-bold text-brand-dark uppercase tracking-tight">Driver's Licence</span>
                    </div>
                </div>
            </div>
            <div className="w-full space-y-3 pt-4">
                <button onClick={startCamera} className="w-full bg-brand-primary text-white font-black py-4 rounded-2xl shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3">
                   <span>Scan Official Document</span>
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z" />
                   </svg>
                </button>
                <button onClick={onBack} className="w-full text-gray-400 font-bold py-3 text-sm">Maybe Later</button>
            </div>
            {error && <p className="text-red-500 font-bold text-xs bg-red-50 p-2 rounded-lg">{error}</p>}
          </div>
        );
      case 'camera':
        return (
          <div className="relative w-full h-full bg-black flex flex-col items-center justify-center">
            <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" />

            {/* Document Frame Overlay */}
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                <div className="w-[85%] aspect-[1.6/1] border-2 border-brand-accent rounded-xl shadow-[0_0_0_9999px_rgba(0,0,0,0.6)]">
                    <div className="absolute top-4 left-0 right-0 text-center">
                        <span className="bg-brand-accent text-brand-dark px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest">Align Document Within Frame</span>
                    </div>
