            </div>

            <div className="absolute bottom-10 z-10 w-full px-8 flex justify-between items-center">
              <button onClick={() => setStep('initial')} className="text-white bg-white/10 p-3 rounded-full backdrop-blur-md">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
              <button onClick={takePhoto} className="p-6 rounded-full bg-white shadow-2xl active:scale-90 transition-transform">
                <div className="w-10 h-10 border-4 border-brand-primary rounded-full"></div>
              </button>
              <div className="w-12 h-12"></div> {/* Spacer */}
            </div>
