      case 'preview':
        return (
          <div className="relative w-full h-full bg-brand-dark flex flex-col p-6 overflow-y-auto">
            <h2 className="text-white text-xl font-black mb-6 text-center pt-8 uppercase tracking-widest">Review Scan</h2>
            <div className="bg-white p-2 rounded-2xl shadow-2xl mb-8">
                <img src={docPhoto!} alt="Document Scan" className="w-full rounded-xl" />
            </div>
            <div className="space-y-4">
                <button onClick={handleSubmit} className="w-full bg-brand-primary text-white font-black py-4 rounded-2xl shadow-xl active:scale-95 transition-all">
                    Verify Document
                </button>
                <button onClick={startCamera} className="w-full bg-white/10 text-white font-bold py-4 rounded-2xl hover:bg-white/20">
                    Retake Scan
                </button>
            </div>
            <p className="text-white/40 text-[10px] text-center mt-6 uppercase leading-relaxed font-bold tracking-tighter">
                By submitting, you consent to Knot Registry's processing of your identity document for authentication purposes only.
            </p>
          </div>
        );
      case 'verifying':
        return (
          <div className="text-center p-8 flex flex-col items-center justify-center h-full bg-white">
            <div className="w-20 h-20 border-8 border-brand-light border-t-brand-primary rounded-full animate-spin mb-8 shadow-inner"></div>
            <h1 className="text-2xl font-black text-brand-dark">Registry Authentication</h1>
            <p className="text-gray-500 text-sm font-medium mt-2 animate-pulse">Our AI is validating your document metadata...</p>
          </div>
        );
      case 'success':
        return (
           <div className="text-center p-8 flex flex-col items-center justify-center h-full bg-brand-primary text-white animate-fade-in">
            <div className="bg-white p-6 rounded-full mb-8 shadow-2xl">
                <VerifiedIcon className="w-24 h-24 text-brand-primary" />
