import React, { useState, useRef } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';
import { PlusIcon } from './icons/PlusIcon';

interface OnboardingFlowProps {
  user: User;
  onComplete: (updatedUser: User) => void;
}

const OnboardingFlow: React.FC<OnboardingFlowProps> = ({ user, onComplete }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<User>(user);
  const [isProcessing, setIsProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const totalSteps = 4;

  const handleNext = () => {
    if (step === 4 && formData.profileImageUrls.length === 0) {
        alert("Please upload your best profile picture to continue.");
        return;
    }
    if (step < totalSteps) {
      setStep(step + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      onComplete(formData);
    }
  };

  const handlePrev = () => {
    if (step > 1) {
      setStep(step - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const result = event.target?.result as string;
      if (result) {
        setFormData({ ...formData, profileImageUrls: [result] });
      }
      setIsProcessing(false);
    };
    reader.readAsDataURL(file);
  };

  const inputClass = "w-full p-4 border border-gray-200 rounded-2xl bg-white text-brand-dark focus:ring-2 focus:ring-brand-primary focus:border-transparent focus:outline-none shadow-sm transition-all";
  const labelClass = "block text-xs font-black text-gray-400 mb-2 uppercase tracking-widest";

  return (
    <div className="min-h-screen bg-white flex flex-col p-6 pb-32 relative font-sans">
      <div className="mb-10">
        <div className="flex justify-between items-end mb-3">
            <div>
                <h4 className="text-[10px] font-black text-brand-primary uppercase tracking-[0.2em]">Knot Global Registry</h4>
                <h2 className="text-2xl font-black text-brand-dark">
                  {step === 1 && 'The Basics'}
                  {step === 2 && 'Lifestyle & Values'}
                  {step === 3 && 'Commitment'}
                  {step === 4 && 'Your Best Look'}
                </h2>
            </div>
            <span className="text-xs font-bold text-gray-300 uppercase tracking-widest">{step}/{totalSteps}</span>
        </div>
        <div className="w-full h-1.5 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-brand-primary transition-all duration-700 ease-in-out" style={{ width: `${(step / totalSteps) * 100}%` }}></div>
        </div>
      </div>

      <div className="flex-1 animate-slide-in">
        {step === 1 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Tell the registry about your identity. Clear information leads to better compatibility scores.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Full Name</label>
                <input name="name" value={formData.name} onChange={handleChange} className={inputClass} placeholder="Sarah Jenkins" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className={labelClass}>Age</label>
                    <input type="number" name="age" value={formData.age} onChange={handleChange} className={inputClass} />
                 </div>
                 <div>
                    <label className={labelClass}>Occupation</label>
                    <input name="occupation" value={formData.occupation} onChange={handleChange} className={inputClass} placeholder="e.g. Architect" />
                 </div>
              </div>
              <div>
                <label className={labelClass}>Marriage-Oriented Bio</label>
                <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className={inputClass} placeholder="What are you looking for in a life partner? Share your values..." />
              </div>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Shared values are the foundation of a lasting marriage. Be honest about your way of life.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Religion / Faith</label>
                <input name="religion" value={formData.religion} onChange={handleChange} className={inputClass} placeholder="e.g. Christian, Muslim, Secular" />
              </div>
              <div>
                <label className={labelClass}>Cultural / Ethnic Roots</label>
                <input name="culturalBackground" value={formData.culturalBackground} onChange={handleChange} className={inputClass} placeholder="e.g. South Asian, Hispanic" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelClass}>Smoking</label>
                  <select name="smoking" value={formData.smoking} onChange={handleChange} className={inputClass}>
                    {Object.values(SmokingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelClass}>Drinking</label>
                  <select name="drinking" value={formData.drinking} onChange={handleChange} className={inputClass}>
                    {Object.values(DrinkingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Knot matches users based on their marriage timeline and relocation readiness.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Ideal Marriage Timeline</label>
                <select name="marriageTimeline" value={formData.marriageTimeline} onChange={handleChange} className={inputClass}>
                    <option value="ASAP">As soon as I find the one</option>
                    <option value="1-2 years">Within 1-2 years</option>
                    <option value="3+ years">3+ years</option>
                    <option value="Not sure">Not sure yet</option>
                </select>
              </div>
              <div>
                <label className={labelClass}>Future Children</label>
                <select name="childrenPreference" value={formData.childrenPreference} onChange={handleChange} className={inputClass}>
                  {Object.values(ChildrenPreference).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
              <div>
                <label className={labelClass}>Relocation Willingness</label>
                <select name="willingToRelocate" value={formData.willingToRelocate} onChange={handleChange} className={inputClass}>
                  {Object.values(WillingToRelocate).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-8 text-center">
            <div>
                <h3 className="text-3xl font-serif text-brand-primary mb-2">First Impressions</h3>
                <p className="text-gray-500 text-sm leading-relaxed px-4">Upload your favorite picture. This is the first thing potential matches will see in the registry.</p>
            </div>

            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileChange} 
              accept="image/*" 
              className="hidden" 
            />

            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`relative inline-block w-full max-w-[280px] aspect-[4/5] mx-auto cursor-pointer group`}
            >
                <div className={`w-full h-full rounded-[2rem] border-4 border-dashed ${formData.profileImageUrls.length > 0 ? 'border-brand-primary' : 'border-gray-200'} overflow-hidden bg-gray-50 flex items-center justify-center shadow-xl transition-all hover:bg-brand-light`}>
                    {formData.profileImageUrls.length > 0 ? (
                         <img src={formData.profileImageUrls[0]} className="w-full h-full object-cover" />
                    ) : (
                        <div className="text-center p-8">
                            {isProcessing ? (
                                <div className="w-10 h-10 border-4 border-brand-primary border-t-transparent rounded-full animate-spin mx-auto"></div>
                            ) : (
                                <>
                                    <PlusIcon className="h-16 w-16 mx-auto text-gray-300 mb-4" />
                                    <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Select From Gallery</p>
                                </>
                            )}
                        </div>
                    )}
                </div>
                {formData.profileImageUrls.length > 0 && (
                    <div className="absolute inset-0 bg-brand-primary/20 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity rounded-[2rem]">
                        <span className="text-white font-black text-xs uppercase tracking-widest bg-brand-primary px-4 py-2 rounded-full shadow-lg">Change Photo</span>
                    </div>
                )}
            </div>

            <div className="pt-6 px-10 text-gray-400 text-[10px] font-medium leading-relaxed uppercase tracking-widest text-center">
                High-quality, clear photos receive 4x more engagement.
            </div>
          </div>
        )}
      </div>

      <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto p-6 bg-white flex items-center gap-4 z-30">
        {step > 1 && <button onClick={handlePrev} className="px-8 py-4 rounded-2xl border border-gray-100 text-gray-300 font-bold hover:bg-gray-50 transition-all">Back</button>}
        <button onClick={handleNext} className="flex-1 bg-brand-primary text-white font-black py-4 rounded-2xl text-lg hover:bg-brand-secondary transition-all shadow-xl shadow-brand-primary/20 active:scale-95">
            {step === totalSteps ? 'Activate Profile' : 'Continue'}
        </button>
      </div>

      <style>{`
        .animate-slide-in { animation: slideIn 0.5s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        @keyframes slideIn { from { opacity: 0; transform: translateX(20px); } to { opacity: 1; transform: translateX(0); } }
      `}</style>
    </div>
  );
};

export default OnboardingFlow;

import React, { useState, useRef, useEffect } from 'react';
import { ShieldCheckIcon } from './icons/ShieldCheckIcon';
import { VerifiedIcon } from './icons/VerifiedIcon';

type VerificationStep = 'initial' | 'selfie_intro' | 'selfie_camera' | 'id_intro' | 'id_scan' | 'verifying' | 'success';

interface VerificationScreenProps {
  onVerificationComplete: () => void;
  onBack: () => void;
}

const VerificationScreen: React.FC<VerificationScreenProps> = ({ onVerificationComplete, onBack }) => {
  const [step, setStep] = useState<VerificationStep>('initial');
  const [error, setError] = useState<string | null>(null);
  const [selfiePhoto, setSelfiePhoto] = useState<string | null>(null);
  const [idPhoto, setIdPhoto] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    let activeStream: MediaStream | null = null;
    if (step === 'selfie_camera' || step === 'id_scan') {
      const initCamera = async () => {
        try {
          const facingMode = step === 'selfie_camera' ? 'user' : 'environment';
          const stream = await navigator.mediaDevices.getUserMedia({ 
            video: { facingMode, width: { ideal: 1280 }, height: { ideal: 720 } } 
          });
          activeStream = stream;
          streamRef.current = stream;
          if (videoRef.current) {
            videoRef.current.srcObject = stream;
            videoRef.current.play().catch(e => console.error("Play failed", e));
          }
        } catch (err) {
          setError("Camera access denied. Verification requires live captures.");
          setStep('initial');
        }
      };
      initCamera();
    }
    return () => { if (activeStream) activeStream.getTracks().forEach(track => track.stop()); };
  }, [step]);

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const context = canvas.getContext('2d');
      if (context) {
        if (step === 'selfie_camera') {
            context.translate(canvas.width, 0);
            context.scale(-1, 1);
        }
        context.drawImage(video, 0, 0, video.videoWidth, video.videoHeight);
        const data = canvas.toDataURL('image/jpeg', 0.9);

        if (step === 'selfie_camera') {
            setSelfiePhoto(data);
            setStep('id_intro');
        } else {
            setIdPhoto(data);
            handleVerify();
        }
      }
    }
  };

  const handleVerify = () => {
    setStep('verifying');
    setTimeout(() => {
      setStep('success');
      setTimeout(() => onVerificationComplete(), 2000);
    }, 4000);
  };

  const renderContent = () => {
    switch(step) {
      case 'initial':
        return (
          <div className="text-center p-8 flex flex-col items-center justify-center h-full space-y-8 bg-white">
            <div className="bg-brand-light p-8 rounded-[2rem] shadow-inner">
                <ShieldCheckIcon className="w-20 h-20 text-brand-primary" />
            </div>
            <div>
                <h1 className="text-2xl font-black text-brand-dark mb-2">Registry Authentication</h1>
                <p className="text-gray-500 text-sm leading-relaxed px-4 mb-6">
                    Knot maintains the highest safety standards. Complete two simple steps to verify your identity.
                </p>
                <div className="flex flex-col gap-3 w-full max-w-[280px] mx-auto">
                    <div className="flex items-center gap-3 p-4 bg-gray-50 rounded-2xl border border-gray-100">
                        <div className="w-8 h-8 rounded-full bg-brand-primary/10 flex items-center justify-center text-brand-primary font-black text-xs">1</div>
                        <span className="text-xs font-bold text-gray-600 uppercase tracking-tight">Live Selfie Check</span>
                    </div>
                    <div className="flex items-center gap-3 p-4 bg-gray-50 rounded-2xl border border-gray-100">
                        <div className="w-8 h-8 rounded-full bg-brand-primary/10 flex items-center justify-center text-brand-primary font-black text-xs">2</div>
                        <span className="text-xs font-bold text-gray-600 uppercase tracking-tight">Official ID Scan</span>
                    </div>
                </div>
            </div>
            <div className="w-full pt-4">
                <button onClick={() => setStep('selfie_intro')} className="w-full bg-brand-primary text-white font-black py-4 rounded-2xl shadow-xl active:scale-95 transition-all">
                   Start Verification
                </button>
                <button onClick={onBack} className="w-full text-gray-400 font-bold py-3 text-sm mt-2">Go Back</button>
            </div>
          </div>
        );

      case 'selfie_intro':
        return (
            <div className="text-center p-8 flex flex-col items-center justify-center h-full space-y-6 bg-white">
                <div className="w-24 h-24 bg-brand-light rounded-full flex items-center justify-center">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-brand-primary" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.828 14.828a4 4 0 01-5.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                </div>
                <h2 className="text-2xl font-black text-brand-dark">Step 1: Live Selfie</h2>
                <p className="text-gray-500 text-sm px-6">We'll use your front camera to ensure you match your registry profile. Ensure good lighting.</p>
                <button onClick={() => setStep('selfie_camera')} className="w-full bg-brand-primary text-white font-black py-4 rounded-2xl shadow-xl mt-4">
                    Open Selfie Camera
                </button>
            </div>
        );

      case 'selfie_camera':
        return (
          <div className="relative w-full h-full bg-black flex flex-col items-center justify-center">
            <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover scale-x-[-1]" />
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                <div className="w-[75%] aspect-square border-2 border-white/50 rounded-full border-dashed shadow-[0_0_0_9999px_rgba(0,0,0,0.4)]"></div>
            </div>
            <div className="absolute bottom-10 z-10 w-full flex justify-center">
              <button onClick={capturePhoto} className="p-6 rounded-full bg-white shadow-2xl active:scale-90 transition-transform">
                <div className="w-10 h-10 border-4 border-brand-primary rounded-full"></div>
              </button>
            </div>
          </div>
        );

      case 'id_intro':
        return (
            <div className="text-center p-8 flex flex-col items-center justify-center h-full space-y-6 bg-white">
                <div className="w-24 h-24 bg-brand-light rounded-full flex items-center justify-center">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-brand-primary" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z" />
                    </svg>
                </div>
                <h2 className="text-2xl font-black text-brand-dark">Step 2: Legal Identity</h2>
                <p className="text-gray-500 text-sm px-6">Prepare one of the following official documents:</p>
                <ul className="text-xs font-bold text-gray-400 space-y-2 uppercase tracking-widest">
                    <li>• International Passport</li>
                    <li>• National ID Card</li>
                    <li>• Driver's Licence</li>
                </ul>
                <button onClick={() => setStep('id_scan')} className="w-full bg-brand-primary text-white font-black py-4 rounded-2xl shadow-xl mt-4">
                    Scan Official ID
                </button>
            </div>
        );

      case 'id_scan':
        return (
            <div className="relative w-full h-full bg-black flex flex-col items-center justify-center">
              <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" />
              <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                  <div className="w-[85%] aspect-[1.6/1] border-2 border-brand-accent rounded-xl shadow-[0_0_0_9999px_rgba(0,0,0,0.6)]"></div>
              </div>
              <div className="absolute bottom-10 z-10 w-full flex justify-center">
                <button onClick={capturePhoto} className="p-6 rounded-full bg-white shadow-2xl active:scale-90 transition-transform">
                  <div className="w-10 h-10 border-4 border-brand-accent rounded-full"></div>
                </button>
              </div>
            </div>
          );

      case 'verifying':
        return (
          <div className="text-center p-8 flex flex-col items-center justify-center h-full bg-white">
            <div className="w-20 h-20 border-8 border-brand-light border-t-brand-primary rounded-full animate-spin mb-8 shadow-inner"></div>
            <h1 className="text-2xl font-black text-brand-dark">Registry Authentication</h1>
            <p className="text-gray-500 text-sm font-medium mt-2 animate-pulse">Our AI is cross-referencing your selfie with your ID document...</p>
          </div>
        );

      case 'success':
        return (
           <div className="text-center p-8 flex flex-col items-center justify-center h-full bg-brand-primary text-white animate-fade-in">
            <div className="bg-white p-6 rounded-full mb-8 shadow-2xl">
                <VerifiedIcon className="w-24 h-24 text-brand-primary" />
            </div>
            <h1 className="text-3xl font-black mb-2">Verified Status</h1>
            <p className="text-brand-light/80 text-sm px-8 font-medium">Identity authenticated. You now carry the Trusted Registry badge on your profile.</p>
          </div>
        );
    }
  };

  return (
    <div className="w-full h-screen bg-gray-50 flex flex-col overflow-hidden">
      <main className="flex-1 relative">
        {renderContent()}
        <canvas ref={canvasRef} className="hidden" />
      </main>
      <style>{`
        .animate-fade-in { animation: fadeIn 0.5s ease-out; }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
      `}</style>
    </div>
  );
};

export default VerificationScreen;

import React, { useState, useRef, useEffect } from 'react';
import { ShieldCheckIcon } from './icons/ShieldCheckIcon';
import { VerifiedIcon } from './icons/VerifiedIcon';
import { CloseIcon } from './icons/CloseIcon';

type IDType = 'Passport' | 'NationalID' | 'DriversLicence';
type VerificationStep = 
  | 'initial' 
  | 'selfie_camera' 
  | 'selfie_review' 
  | 'id_selection' 
  | 'id_scan' 
  | 'verifying' 
  | 'success';

interface VerificationScreenProps {
  onVerificationComplete: () => void;
  onBack: () => void;
}

const VerificationScreen: React.FC<VerificationScreenProps> = ({ onVerificationComplete, onBack }) => {
  const [step, setStep] = useState<VerificationStep>('initial');
  const [selectedIdType, setSelectedIdType] = useState<IDType | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [selfiePhoto, setSelfiePhoto] = useState<string | null>(null);
  const [idPhoto, setIdPhoto] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    let activeStream: MediaStream | null = null;
    if (step === 'selfie_camera' || step === 'id_scan') {
      const initCamera = async () => {
        try {
          const facingMode = step === 'selfie_camera' ? 'user' : 'environment';
          const stream = await navigator.mediaDevices.getUserMedia({ 
            video: { facingMode, width: { ideal: 1280 }, height: { ideal: 720 } } 
          });
          activeStream = stream;
          streamRef.current = stream;
          if (videoRef.current) {
            videoRef.current.srcObject = stream;
            videoRef.current.play().catch(e => console.error("Play failed", e));
          }
        } catch (err) {
          setError("Camera access denied. Verification requires live captures for security.");
          setStep('initial');
        }
      };
      initCamera();
    }
    return () => { if (activeStream) activeStream.getTracks().forEach(track => track.stop()); };
  }, [step]);

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const context = canvas.getContext('2d');
      if (context) {
        if (step === 'selfie_camera') {
            context.translate(canvas.width, 0);
            context.scale(-1, 1);
        }
        context.drawImage(video, 0, 0, video.videoWidth, video.videoHeight);
        const data = canvas.toDataURL('image/jpeg', 0.9);

        if (step === 'selfie_camera') {
            setSelfiePhoto(data);
            setStep('selfie_review');
        } else {
            setIdPhoto(data);
            handleVerify();
        }
      }
    }
  };

  const handleVerify = () => {
    setStep('verifying');
    // Simulate biometric matching and OCR
    setTimeout(() => {
      setStep('success');
      setTimeout(() => onVerificationComplete(), 2500);
    }, 4500);
  };

  const renderContent = () => {
    switch(step) {
      case 'initial':
        return (
          <div className="text-center p-8 flex flex-col items-center justify-center h-full space-y-8 bg-white">
            <div className="bg-brand-light p-8 rounded-[2.5rem] shadow-inner">
                <ShieldCheckIcon className="w-20 h-20 text-brand-primary" />
            </div>
            <div>
                <h1 className="text-2xl font-black text-brand-dark mb-2">Trusted Registry Verification</h1>
                <p className="text-gray-500 text-sm leading-relaxed px-4 mb-6">
                    Knot maintains a high-trust environment. Verifying your identity grants you the <b>Trusted Badge</b> and increases match quality by 300%.
                </p>
                <div className="grid grid-cols-2 gap-4 w-full">
                    <div className="p-4 bg-gray-50 rounded-2xl border border-gray-100 flex flex-col items-center">
                        <span className="text-brand-primary font-black text-xl mb-1">01</span>
                        <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest text-center leading-tight">Biometric Selfie</span>
                    </div>
                    <div className="p-4 bg-gray-50 rounded-2xl border border-gray-100 flex flex-col items-center">
                        <span className="text-brand-primary font-black text-xl mb-1">02</span>
                        <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest text-center leading-tight">Identity Document</span>
                    </div>
                </div>
            </div>
            <div className="w-full pt-4">
                <button onClick={() => setStep('selfie_camera')} className="w-full bg-brand-primary text-white font-black py-4 rounded-2xl shadow-xl active:scale-95 transition-all">
                   Start Verification
                </button>
                <button onClick={onBack} className="w-full text-gray-400 font-bold py-3 text-sm mt-2">Maybe Later</button>
            </div>
          </div>
        );

      case 'selfie_camera':
        return (
          <div className="relative w-full h-full bg-black flex flex-col items-center justify-center">
            <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover scale-x-[-1]" />
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                <div className="w-[75%] aspect-square border-4 border-brand-accent/50 rounded-full border-dashed shadow-[0_0_0_9999px_rgba(0,0,0,0.6)]"></div>
            </div>
            <div className="absolute top-12 left-0 right-0 text-center px-10">
                <p className="text-white font-black uppercase tracking-[0.2em] text-xs">Selfie Check</p>
                <p className="text-white/60 text-[10px] mt-1">Position your face inside the circle</p>
            </div>
            <div className="absolute bottom-10 z-10 w-full flex justify-center">
              <button onClick={capturePhoto} className="p-6 rounded-full bg-white shadow-2xl active:scale-90 transition-transform">
                <div className="w-10 h-10 border-4 border-brand-primary rounded-full"></div>
              </button>
            </div>
          </div>
        );

      case 'selfie_review':
        return (
            <div className="text-center p-8 flex flex-col items-center justify-center h-full bg-white">
                <h2 className="text-2xl font-black text-brand-dark mb-6">Review Selfie</h2>
                <div className="w-64 h-64 rounded-full overflow-hidden border-4 border-brand-primary mb-8 shadow-2xl">
                    <img src={selfiePhoto!} className="w-full h-full object-cover" />
                </div>
                <p className="text-gray-500 text-sm px-6 mb-8 italic">"Make sure your face is clearly visible and well-lit."</p>
                <div className="w-full space-y-3">
                    <button onClick={() => setStep('id_selection')} className="w-full bg-brand-primary text-white font-black py-4 rounded-2xl">
                        Looks Good, Next Step
                    </button>
                    <button onClick={() => setStep('selfie_camera')} className="w-full text-gray-400 font-bold py-3">
                        Retake Selfie
                    </button>
                </div>
            </div>
        );

      case 'id_selection':
        return (
            <div className="p-8 flex flex-col h-full bg-white">
                <div className="mt-8 mb-10">
                    <h2 className="text-2xl font-black text-brand-dark leading-tight">Choose Identification Type</h2>
                    <p className="text-gray-500 text-sm mt-2 leading-relaxed">Select the valid government-issued document you wish to scan for the registry.</p>
                </div>

                <div className="space-y-4 flex-1">
                    {[
                        { id: 'Passport', label: 'International Passport', sub: 'Bio-data page only' },
                        { id: 'NationalID', label: 'National ID Card', sub: 'Smart cards preferred' },
                        { id: 'DriversLicence', label: "Driver's Licence", sub: 'Front of card' }
                    ].map((type) => (
                        <button 
                            key={type.id}
                            onClick={() => {
                                setSelectedIdType(type.id as IDType);
                                setStep('id_scan');
                            }}
                            className="w-full p-6 bg-gray-50 border border-gray-100 rounded-2xl text-left hover:border-brand-primary transition-all flex items-center justify-between group active:scale-[0.98]"
                        >
                            <div>
                                <p className="font-black text-brand-dark uppercase tracking-tight text-sm">{type.label}</p>
                                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-1">{type.sub}</p>
                            </div>
                            <div className="w-8 h-8 rounded-full border border-gray-200 flex items-center justify-center group-hover:bg-brand-primary group-hover:border-brand-primary transition-all">
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-gray-300 group-hover:text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M9 5l7 7-7 7" />
                                </svg>
                            </div>
                        </button>
                    ))}
                </div>

                <button onClick={() => setStep('initial')} className="text-gray-400 font-bold py-4 text-sm uppercase tracking-widest">Cancel</button>
            </div>
        );

      case 'id_scan':
        return (
            <div className="relative w-full h-full bg-black flex flex-col items-center justify-center">
              <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" />
              <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                  <div className="w-[90%] aspect-[1.6/1] border-2 border-brand-accent/70 rounded-2xl shadow-[0_0_0_9999px_rgba(0,0,0,0.7)]">
                    <div className="absolute top-[-40px] left-0 right-0 text-center">
                        <span className="bg-brand-accent text-brand-dark px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest">Scan {selectedIdType}</span>
                    </div>
                  </div>
              </div>
              <div className="absolute bottom-10 z-10 w-full flex justify-center gap-6">
                <button onClick={() => setStep('id_selection')} className="p-5 rounded-full bg-white/20 backdrop-blur-md text-white">
                    <CloseIcon className="w-6 h-6" />
                </button>
                <button onClick={capturePhoto} className="p-6 rounded-full bg-white shadow-2xl active:scale-90 transition-transform">
                  <div className="w-10 h-10 border-4 border-brand-primary rounded-full"></div>
                </button>
              </div>
            </div>
          );

      case 'verifying':
        return (
          <div className="text-center p-8 flex flex-col items-center justify-center h-full bg-white">
            <div className="relative w-32 h-32 mb-8">
                <div className="absolute inset-0 border-8 border-brand-light rounded-full"></div>
                <div className="absolute inset-0 border-8 border-brand-primary border-t-transparent rounded-full animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                    <ShieldCheckIcon className="w-12 h-12 text-brand-primary" />
                </div>
            </div>
            <h1 className="text-2xl font-black text-brand-dark uppercase tracking-tight">AI Secure Matching</h1>
            <p className="text-gray-500 text-sm font-medium mt-3 px-10 animate-pulse text-center leading-relaxed">
                Analyzing document security features and cross-referencing your biometric selfie...
            </p>
          </div>
        );

      case 'success':
        return (
           <div className="text-center p-8 flex flex-col items-center justify-center h-full bg-brand-primary text-white animate-fade-in">
            <div className="bg-white p-6 rounded-full mb-8 shadow-2xl scale-125">
                <VerifiedIcon className="w-20 h-20 text-brand-primary" />
            </div>
            <h1 className="text-3xl font-black mb-2 uppercase tracking-tighter">Verified Registry Member</h1>
            <p className="text-brand-light/80 text-sm px-8 font-medium leading-relaxed">
                Identity authenticated. Your profile now features the Trusted Badge for all registry searches.
            </p>
          </div>
        );
    }
  };

  return (
    <div className="w-full h-screen bg-gray-50 flex flex-col overflow-hidden">
      <main className="flex-1 relative">
        {renderContent()}
        <canvas ref={canvasRef} className="hidden" />
      </main>
      <style>{`
        .animate-fade-in { animation: fadeIn 0.5s ease-out; }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
      `}</style>
    </div>
  );
};

export default VerificationScreen;

import React, { useState, useRef } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';
import { PlusIcon } from './icons/PlusIcon';
import { SparklesIcon } from './icons/SparklesIcon';

interface OnboardingFlowProps {
  user: User;
  onComplete: (updatedUser: User) => void;
}

const OnboardingFlow: React.FC<OnboardingFlowProps> = ({ user, onComplete }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<User>(user);
  const [isProcessing, setIsProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const totalSteps = 4;

  const handleNext = () => {
    if (step === 4 && formData.profileImageUrls.length === 0) {
        alert("Please upload your best profile picture to continue.");
        return;
    }
    if (step < totalSteps) {
      setStep(step + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      onComplete(formData);
    }
  };

  const handlePrev = () => {
    if (step > 1) {
      setStep(step - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const result = event.target?.result as string;
      if (result) {
        setFormData({ ...formData, profileImageUrls: [result] });
      }
      setIsProcessing(false);
    };
    reader.readAsDataURL(file);
  };

  const inputClass = "w-full p-4 border border-gray-200 rounded-2xl bg-white text-brand-dark focus:ring-2 focus:ring-brand-primary focus:border-transparent focus:outline-none shadow-sm transition-all";
  const labelClass = "block text-xs font-black text-gray-400 mb-2 uppercase tracking-widest";

  return (
    <div className="min-h-screen bg-white flex flex-col p-6 pb-32 relative font-sans">
      <div className="mb-10">
        <div className="flex justify-between items-end mb-3">
            <div>
                <h4 className="text-[10px] font-black text-brand-primary uppercase tracking-[0.2em]">Knot Global Registry</h4>
                <h2 className="text-2xl font-black text-brand-dark">
                  {step === 1 && 'The Basics'}
                  {step === 2 && 'Lifestyle & Values'}
                  {step === 3 && 'Commitment'}
                  {step === 4 && 'Your Best Look'}
                </h2>
            </div>
            <span className="text-xs font-bold text-gray-300 uppercase tracking-widest">{step}/{totalSteps}</span>
        </div>
        <div className="w-full h-1.5 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-brand-primary transition-all duration-700 ease-in-out" style={{ width: `${(step / totalSteps) * 100}%` }}></div>
        </div>
      </div>

      <div className="flex-1 animate-slide-in">
        {step === 1 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Tell the registry about your identity. Clear information leads to better compatibility scores.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Full Name</label>
                <input name="name" value={formData.name} onChange={handleChange} className={inputClass} placeholder="Sarah Jenkins" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className={labelClass}>Age</label>
                    <input type="number" name="age" value={formData.age} onChange={handleChange} className={inputClass} />
                 </div>
                 <div>
                    <label className={labelClass}>Occupation</label>
                    <input name="occupation" value={formData.occupation} onChange={handleChange} className={inputClass} placeholder="e.g. Architect" />
                 </div>
              </div>
              <div>
                <label className={labelClass}>Marriage-Oriented Bio</label>
                <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className={inputClass} placeholder="What are you looking for in a life partner? Share your values..." />
              </div>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Shared values are the foundation of a lasting marriage. Be honest about your way of life.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Religion / Faith</label>
                <input name="religion" value={formData.religion} onChange={handleChange} className={inputClass} placeholder="e.g. Christian, Muslim, Secular" />
              </div>
              <div>
                <label className={labelClass}>Cultural / Ethnic Roots</label>
                <input name="culturalBackground" value={formData.culturalBackground} onChange={handleChange} className={inputClass} placeholder="e.g. South Asian, Hispanic" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelClass}>Smoking</label>
                  <select name="smoking" value={formData.smoking} onChange={handleChange} className={inputClass}>
                    {Object.values(SmokingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelClass}>Drinking</label>
                  <select name="drinking" value={formData.drinking} onChange={handleChange} className={inputClass}>
                    {Object.values(DrinkingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Knot matches users based on their marriage timeline and relocation readiness.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Ideal Marriage Timeline</label>
                <select name="marriageTimeline" value={formData.marriageTimeline} onChange={handleChange} className={inputClass}>
                    <option value="ASAP">As soon as I find the one</option>
                    <option value="1-2 years">Within 1-2 years</option>
                    <option value="3+ years">3+ years</option>
                    <option value="Not sure">Not sure yet</option>
                </select>
              </div>
              <div>
                <label className={labelClass}>Future Children</label>
                <select name="childrenPreference" value={formData.childrenPreference} onChange={handleChange} className={inputClass}>
                  {Object.values(ChildrenPreference).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
              <div>
                <label className={labelClass}>Relocation Willingness</label>
                <select name="willingToRelocate" value={formData.willingToRelocate} onChange={handleChange} className={inputClass}>
                  {Object.values(WillingToRelocate).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-8 text-center px-4">
            <div className="animate-fade-in">
                <div className="flex justify-center mb-2">
                    <SparklesIcon className="w-6 h-6 text-brand-accent animate-pulse" />
                </div>
                <h3 className="text-3xl font-serif text-brand-primary mb-2">First Impressions</h3>
                <p className="text-gray-500 text-sm leading-relaxed">Select your most authentic and clear portrait. High-quality photos receive much more engagement.</p>
            </div>

            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileChange} 
              accept="image/*" 
              className="hidden" 
            />

            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`relative inline-block w-full max-w-[280px] aspect-[4/5] mx-auto cursor-pointer group animate-scale-in`}
            >
                <div className={`w-full h-full rounded-[2.5rem] border-4 border-dashed ${formData.profileImageUrls.length > 0 ? 'border-brand-primary border-solid' : 'border-gray-200'} overflow-hidden bg-gray-50 flex items-center justify-center shadow-2xl transition-all hover:bg-brand-light active:scale-[0.98]`}>
                    {formData.profileImageUrls.length > 0 ? (
                         <img src={formData.profileImageUrls[0]} className="w-full h-full object-cover animate-fade-in" />
                    ) : (
                        <div className="text-center p-8">
                            {isProcessing ? (
                                <div className="w-12 h-12 border-4 border-brand-primary border-t-transparent rounded-full animate-spin mx-auto"></div>
                            ) : (
                                <>
                                    <div className="w-20 h-20 bg-brand-light rounded-full flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                                        <PlusIcon className="h-10 w-10 text-brand-primary" />
                                    </div>
                                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest leading-relaxed px-4">Tap to upload your best picture from gallery</p>
                                </>
                            )}
                        </div>
                    )}
                </div>
                {formData.profileImageUrls.length > 0 && (
                    <div className="absolute inset-0 bg-brand-primary/20 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity rounded-[2.5rem] backdrop-blur-[2px]">
                        <span className="text-white font-black text-xs uppercase tracking-widest bg-brand-primary px-6 py-3 rounded-full shadow-xl">Change Photo</span>
                    </div>
                )}
            </div>

            <div className="pt-6 px-10 text-gray-400 text-[10px] font-bold leading-relaxed uppercase tracking-widest text-center opacity-60">
                You can add up to 5 more photos later in your profile settings.
            </div>
          </div>
        )}
      </div>

      <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto p-6 bg-white flex items-center gap-4 z-30 border-t border-gray-50">
        {step > 1 && <button onClick={handlePrev} className="px-8 py-4 rounded-2xl border border-gray-100 text-gray-400 font-bold hover:bg-gray-50 transition-all">Back</button>}
        <button onClick={handleNext} className="flex-1 bg-brand-primary text-white font-black py-4 rounded-2xl text-lg hover:bg-brand-secondary transition-all shadow-xl shadow-brand-primary/30 active:scale-95">
            {step === totalSteps ? 'Complete Registry' : 'Continue'}
        </button>
      </div>

      <style>{`
        .animate-slide-in { animation: slideIn 0.5s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        .animate-scale-in { animation: scaleIn 0.6s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        @keyframes slideIn { from { opacity: 0; transform: translateX(20px); } to { opacity: 1; transform: translateX(0); } }
        @keyframes scaleIn { from { opacity: 0; transform: scale(0.9); } to { opacity: 1; transform: scale(1); } }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
      `}</style>
    </div>
  );
};

export default OnboardingFlow;

import React, { useState } from 'react';
import { User } from '../types';
import { PencilIcon } from './icons/PencilIcon';
import { CameraIcon } from './icons/CameraIcon';
import { ShieldCheckIcon } from './icons/ShieldCheckIcon';
import { VerifiedIcon } from './icons/VerifiedIcon';
import { ChevronDownIcon } from './icons/ChevronDownIcon';

interface ProfileCardProps {
  user: User;
  onEditProfile: () => void;
  onManagePhotos: () => void;
  onVerifyProfile: () => void;
}

interface ProfileSectionProps {
    title: string;
    children: React.ReactNode;
    isOpen: boolean;
    onToggle: () => void;
}

const ProfileSection: React.FC<ProfileSectionProps> = ({ title, children, isOpen, onToggle }) => (
    <div className="border-b border-gray-200">
        <button onClick={onToggle} className="w-full flex justify-between items-center py-4 text-left">
            <h3 className="font-semibold text-lg text-brand-dark">{title}</h3>
            <ChevronDownIcon className={`w-5 h-5 text-gray-500 transform transition-transform ${isOpen ? 'rotate-180' : ''}`} />
        </button>
        {isOpen && <div className="pb-4 space-y-4 text-sm text-gray-700">{children}</div>}
    </div>
);

const ProfileDataItem: React.FC<{ label: string; value: React.ReactNode }> = ({ label, value }) => (
    <div>
        <p className="text-xs text-gray-500 font-semibold uppercase tracking-wider">{label}</p>
        <div className="text-md text-gray-900 mt-1">{value || 'Not specified'}</div>
    </div>
);


const ProfileCard: React.FC<ProfileCardProps> = ({ user, onEditProfile, onManagePhotos, onVerifyProfile }) => {
  const [openSections, setOpenSections] = useState<Record<string, boolean>>({
    about: true,
    lifestyle: false,
    marriage: false,
  });

  const toggleSection = (section: string) => {
