import { SparklesIcon } from './icons/SparklesIcon';
import { getCompatibilityInsight } from '../services/matchingService';

interface ProfileDetailScreenProps {
  match: Match;
  user: User;
  onBack: () => void;
  onStartChat: (match: Match) => void;
  onStartCall: (match: Match) => void;
