                {matchReason}
            </div>
        </div>

        {/* Global Registry Badge */}
        {isGlobal && (
            <div className="absolute top-14 left-3 z-20 flex items-center gap-1 bg-brand-secondary/80 backdrop-blur-sm text-[8px] text-white px-2 py-0.5 rounded-full font-bold uppercase tracking-widest border border-white/20">
                <SparklesIcon className="w-3 h-3" />
