      <div
        className="relative aspect-[4/5] bg-gray-200 cursor-pointer"
        onClick={() => onCardClick(match)}
      >
        <img
          src={photos[currentPhotoIndex]}
          alt={`${match.name}'s photo`}
          className="w-full h-full object-cover"
