        <div className="flex justify-between items-center mt-4">
          <div className="text-[10px] text-gray-400 font-bold uppercase tracking-tighter">{match.marriageTimeline} Timeline</div>
          <button 
            onClick={() => onCardClick(match)}
            className="bg-brand-primary text-white font-black px-6 py-2 rounded-lg text-xs hover:bg-brand-secondary transition-all shadow active:scale-95"
          >
            Review Profile
          </button>
        </div>
      </div>
    </div>
  );
};

