import React, { useState, useRef, useEffect } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';
import { PlusIcon } from './icons/PlusIcon';
import { SparklesIcon } from './icons/SparklesIcon';
import { COUNTRIES, STATES_BY_COUNTRY, CITIES_BY_STATE, MANUAL_ENTRY_OPTION } from '../services/locationData';

interface OnboardingFlowProps {
  user: User;
  onComplete: (updatedUser: User) => void;
}

const OnboardingFlow: React.FC<OnboardingFlowProps> = ({ user, onComplete }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<User>(user);
  const [isProcessing, setIsProcessing] = useState(false);

  // Manual entry states
  const [resStateManual, setResStateManual] = useState('');
  const [resCityManual, setResCityManual] = useState('');
  const [origStateManual, setOrigStateManual] = useState('');
  const [origCityManual, setOrigCityManual] = useState('');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const totalSteps = 4;

  const handleNext = () => {
    if (step === 1) {
        // Validation for location
        if (!formData.residenceCountry || !formData.originCountry) {
            alert("Please complete the location details to ensure a high-trust registry profile.");
            return;
        }
    }
    if (step === 4 && formData.profileImageUrls.length === 0) {
        alert("Please upload your best profile picture to continue.");
        return;
    }
    if (step < totalSteps) {
      setStep(step + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      onComplete(formData);
    }
  };

  const handlePrev = () => {
    if (step > 1) {
      setStep(step - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));

    // Cascading logic: Reset children when parent changes
    if (name === 'residenceCountry') {
        setFormData(prev => ({ ...prev, residenceState: '', residenceCity: '', country: value }));
    } else if (name === 'residenceState') {
        setFormData(prev => ({ ...prev, residenceCity: '' }));
    } else if (name === 'originCountry') {
        setFormData(prev => ({ ...prev, originState: '', originCity: '' }));
    } else if (name === 'originState') {
        setFormData(prev => ({ ...prev, originCity: '' }));
    }
  };

  const handleManualChange = (type: 'resState' | 'resCity' | 'origState' | 'origCity', value: string) => {
    if (type === 'resState') {
        setResStateManual(value);
        setFormData(prev => ({ ...prev, residenceState: value }));
    } else if (type === 'resCity') {
        setResCityManual(value);
        setFormData(prev => ({ ...prev, residenceCity: value, city: value }));
    } else if (type === 'origState') {
        setOrigStateManual(value);
        setFormData(prev => ({ ...prev, originState: value }));
    } else if (type === 'origCity') {
        setOrigCityManual(value);
        setFormData(prev => ({ ...prev, originCity: value }));
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const result = event.target?.result as string;
      if (result) {
        setFormData({ ...formData, profileImageUrls: [result] });
      }
      setIsProcessing(false);
    };
    reader.readAsDataURL(file);
  };

  const inputClass = "w-full p-4 border border-gray-200 rounded-2xl bg-white text-black focus:ring-2 focus:ring-brand-primary focus:border-transparent focus:outline-none shadow-sm transition-all text-sm";
  const labelClass = "block text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest";
  const sectionTitleClass = "text-xs font-black text-brand-primary uppercase tracking-widest border-b pb-2 mb-4";

  return (
    <div className="min-h-screen bg-white flex flex-col p-6 pb-32 relative font-sans">
      <div className="mb-10">
        <div className="flex justify-between items-end mb-3">
            <div>
                <h4 className="text-[10px] font-black text-brand-primary uppercase tracking-[0.2em]">Knot Global Registry</h4>
                <h2 className="text-2xl font-black text-brand-dark">
                  {step === 1 && 'Identity & Roots'}
                  {step === 2 && 'Lifestyle & Values'}
                  {step === 3 && 'Commitment'}
                  {step === 4 && 'First Impressions'}
                </h2>
            </div>
            <span className="text-xs font-bold text-gray-300 uppercase tracking-widest">{step}/{totalSteps}</span>
        </div>
        <div className="w-full h-1.5 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-brand-primary transition-all duration-700 ease-in-out" style={{ width: `${(step / totalSteps) * 100}%` }}></div>
        </div>
      </div>

      <div className="flex-1 animate-slide-in">
        {step === 1 && (
          <div className="space-y-8">
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Full Name</label>
                <input name="name" value={formData.name} onChange={handleChange} className={inputClass} placeholder="Enter your name" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className={labelClass}>Age</label>
                    <input type="number" name="age" value={formData.age} onChange={handleChange} className={inputClass} />
                 </div>
                 <div>
                    <label className={labelClass}>Occupation</label>
                    <input name="occupation" value={formData.occupation} onChange={handleChange} className={inputClass} placeholder="e.g. Architect" />
                 </div>
              </div>
            </div>

            {/* Current Residence Section */}
            <div className="space-y-4 pt-4">
                <h3 className={sectionTitleClass}>Current Residence</h3>
                <div className="space-y-4">
                    <div>
                        <label className={labelClass}>Country of Residence</label>
                        <select name="residenceCountry" value={formData.residenceCountry} onChange={handleChange} className={inputClass}>
                            <option value="">Select Country</option>
                            {COUNTRIES.map(c => <option key={c} value={c}>{c}</option>)}
                            <option value={MANUAL_ENTRY_OPTION}>Not Listed...</option>
                        </select>
                    </div>

                    {formData.residenceCountry && (
                        <div>
                            <label className={labelClass}>State / Province of Residence</label>
                            <select 
                                name="residenceState" 
                                value={STATES_BY_COUNTRY[formData.residenceCountry]?.includes(formData.residenceState) ? formData.residenceState : (formData.residenceState ? MANUAL_ENTRY_OPTION : '')} 
                                onChange={handleChange} 
                                className={inputClass}
                            >
                                <option value="">Select State</option>
                                {(STATES_BY_COUNTRY[formData.residenceCountry] || []).map(s => <option key={s} value={s}>{s}</option>)}
                                <option value={MANUAL_ENTRY_OPTION}>Other / Not Listed</option>
                            </select>
                            {/* Manual Entry for State */}
                            {(formData.residenceState === MANUAL_ENTRY_OPTION || !STATES_BY_COUNTRY[formData.residenceCountry]?.includes(formData.residenceState) && formData.residenceState !== '') && (
                                <input 
                                    type="text" 
                                    placeholder="Enter your state manually" 
                                    className={`${inputClass} mt-2 border-brand-accent`} 
                                    value={resStateManual} 
                                    onChange={(e) => handleManualChange('resState', e.target.value)}
                                />
                            )}
                        </div>
                    )}

                    {formData.residenceState && (
                        <div>
                            <label className={labelClass}>City / Town of Residence</label>
                            <select 
                                name="residenceCity" 
                                value={CITIES_BY_STATE[formData.residenceState]?.includes(formData.residenceCity) ? formData.residenceCity : (formData.residenceCity ? MANUAL_ENTRY_OPTION : '')} 
                                onChange={handleChange} 
                                className={inputClass}
                            >
                                <option value="">Select City</option>
                                {(CITIES_BY_STATE[formData.residenceState] || []).map(c => <option key={c} value={c}>{c}</option>)}
                                <option value={MANUAL_ENTRY_OPTION}>Other / Not Listed</option>
                            </select>
                            {/* Manual Entry for City */}
                            {(formData.residenceCity === MANUAL_ENTRY_OPTION || !CITIES_BY_STATE[formData.residenceState]?.includes(formData.residenceCity) && formData.residenceCity !== '') && (
                                <input 
                                    type="text" 
                                    placeholder="Enter your city manually" 
                                    className={`${inputClass} mt-2 border-brand-accent`} 
                                    value={resCityManual} 
                                    onChange={(e) => handleManualChange('resCity', e.target.value)}
                                />
                            )}
                        </div>
                    )}
                </div>
            </div>

            {/* Country of Origin Section */}
            <div className="space-y-4 pt-4">
                <h3 className={sectionTitleClass}>Heritage & Origin</h3>
                <div className="space-y-4">
                    <div>
                        <label className={labelClass}>Country of Origin</label>
                        <select name="originCountry" value={formData.originCountry} onChange={handleChange} className={inputClass}>
                            <option value="">Select Country</option>
                            {COUNTRIES.map(c => <option key={c} value={c}>{c}</option>)}
                            <option value={MANUAL_ENTRY_OPTION}>Not Listed...</option>
                        </select>
                    </div>

                    {formData.originCountry && (
                        <div>
                            <label className={labelClass}>State / Province of Origin</label>
                            <select 
                                name="originState" 
                                value={STATES_BY_COUNTRY[formData.originCountry]?.includes(formData.originState) ? formData.originState : (formData.originState ? MANUAL_ENTRY_OPTION : '')} 
                                onChange={handleChange} 
                                className={inputClass}
                            >
                                <option value="">Select State</option>
                                {(STATES_BY_COUNTRY[formData.originCountry] || []).map(s => <option key={s} value={s}>{s}</option>)}
                                <option value={MANUAL_ENTRY_OPTION}>Other / Not Listed</option>
                            </select>
                            {/* Manual Entry */}
                            {(formData.originState === MANUAL_ENTRY_OPTION || !STATES_BY_COUNTRY[formData.originCountry]?.includes(formData.originState) && formData.originState !== '') && (
                                <input 
                                    type="text" 
                                    placeholder="Enter origin state manually" 
                                    className={`${inputClass} mt-2 border-brand-accent`} 
                                    value={origStateManual} 
                                    onChange={(e) => handleManualChange('origState', e.target.value)}
                                />
                            )}
                        </div>
                    )}

                    {formData.originState && (
                        <div>
                            <label className={labelClass}>City / Town of Origin</label>
                            <select 
                                name="originCity" 
                                value={CITIES_BY_STATE[formData.originState]?.includes(formData.originCity) ? formData.originCity : (formData.originCity ? MANUAL_ENTRY_OPTION : '')} 
                                onChange={handleChange} 
                                className={inputClass}
                            >
                                <option value="">Select City</option>
                                {(CITIES_BY_STATE[formData.originState] || []).map(c => <option key={c} value={c}>{c}</option>)}
                                <option value={MANUAL_ENTRY_OPTION}>Other / Not Listed</option>
                            </select>
                            {/* Manual Entry */}
                            {(formData.originCity === MANUAL_ENTRY_OPTION || !CITIES_BY_STATE[formData.originState]?.includes(formData.originCity) && formData.originCity !== '') && (
                                <input 
                                    type="text" 
                                    placeholder="Enter origin city manually" 
                                    className={`${inputClass} mt-2 border-brand-accent`} 
                                    value={origCityManual} 
                                    onChange={(e) => handleManualChange('origCity', e.target.value)}
                                />
                            )}
                        </div>
                    )}
                </div>
            </div>

            <div className="pt-4">
                <label className={labelClass}>Marriage-Oriented Bio</label>
                <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className={inputClass} placeholder="What are you looking for in a life partner?" />
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Shared values are the foundation of a lasting marriage. Be honest about your way of life.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Religion / Faith</label>
                <input name="religion" value={formData.religion} onChange={handleChange} className={inputClass} placeholder="e.g. Christian, Muslim, Secular" />
              </div>
              <div>
                <label className={labelClass}>Cultural / Ethnic Roots</label>
                <input name="culturalBackground" value={formData.culturalBackground} onChange={handleChange} className={inputClass} placeholder="e.g. South Asian, Hispanic" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelClass}>Smoking</label>
                  <select name="smoking" value={formData.smoking} onChange={handleChange} className={inputClass}>
                    {Object.values(SmokingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelClass}>Drinking</label>
                  <select name="drinking" value={formData.drinking} onChange={handleChange} className={inputClass}>
                    {Object.values(DrinkingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Knot matches users based on their marriage timeline and relocation readiness.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Ideal Marriage Timeline</label>
                <select name="marriageTimeline" value={formData.marriageTimeline} onChange={handleChange} className={inputClass}>
                    <option value="ASAP">As soon as I find the one</option>
                    <option value="1-2 years">Within 1-2 years</option>
                    <option value="3+ years">3+ years</option>
                    <option value="Not sure">Not sure yet</option>
                </select>
              </div>
              <div>
                <label className={labelClass}>Future Children</label>
                <select name="childrenPreference" value={formData.childrenPreference} onChange={handleChange} className={inputClass}>
                  {Object.values(ChildrenPreference).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
              <div>
                <label className={labelClass}>Relocation Willingness</label>
                <select name="willingToRelocate" value={formData.willingToRelocate} onChange={handleChange} className={inputClass}>
                  {Object.values(WillingToRelocate).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-8 text-center px-4">
            <div className="animate-fade-in">
                <div className="flex justify-center mb-2">
                    <SparklesIcon className="w-6 h-6 text-brand-accent animate-pulse" />
                </div>
                <h3 className="text-3xl font-serif text-brand-primary mb-2">First Impressions</h3>
                <p className="text-gray-500 text-sm leading-relaxed">Select your most authentic and clear portrait.</p>
            </div>

            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileChange} 
              accept="image/*" 
              className="hidden" 
            />

            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`relative inline-block w-full max-w-[280px] aspect-[4/5] mx-auto cursor-pointer group animate-scale-in`}
            >
                <div className={`w-full h-full rounded-[2.5rem] border-4 border-dashed ${formData.profileImageUrls.length > 0 ? 'border-brand-primary border-solid' : 'border-gray-200'} overflow-hidden bg-gray-50 flex items-center justify-center shadow-2xl transition-all hover:bg-brand-light active:scale-[0.98]`}>
                    {formData.profileImageUrls.length > 0 ? (
                         <img src={formData.profileImageUrls[0]} className="w-full h-full object-cover animate-fade-in" />
                    ) : (
                        <div className="text-center p-8">
                            {isProcessing ? (
                                <div className="w-12 h-12 border-4 border-brand-primary border-t-transparent rounded-full animate-spin mx-auto"></div>
                            ) : (
                                <>
                                    <div className="w-20 h-20 bg-brand-light rounded-full flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                                        <PlusIcon className="h-10 w-10 text-brand-primary" />
                                    </div>
                                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest leading-relaxed px-4">Tap to upload your best picture</p>
                                </>
                            )}
                        </div>
                    )}
                </div>
            </div>
          </div>
        )}
      </div>

      <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto p-6 bg-white flex items-center gap-4 z-30 border-t border-gray-50">
        {step > 1 && <button onClick={handlePrev} className="px-8 py-4 rounded-2xl border border-gray-100 text-gray-400 font-bold hover:bg-gray-50 transition-all">Back</button>}
        <button onClick={handleNext} className="flex-1 bg-brand-primary text-white font-black py-4 rounded-2xl text-lg hover:bg-brand-secondary transition-all shadow-xl shadow-brand-primary/30 active:scale-95">
            {step === totalSteps ? 'Complete Registry' : 'Continue'}
        </button>
      </div>

      <style>{`
        .animate-slide-in { animation: slideIn 0.5s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        .animate-scale-in { animation: scaleIn 0.6s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        @keyframes slideIn { from { opacity: 0; transform: translateX(20px); } to { opacity: 1; transform: translateX(0); } }
        @keyframes scaleIn { from { opacity: 0; transform: scale(0.9); } to { opacity: 1; transform: scale(1); } }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
      `}</style>
    </div>
  );
};

export default OnboardingFlow;

import React, { useState } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';
