      <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto p-6 bg-white flex items-center gap-4 z-30 border-t border-gray-50">
        {step > 1 && <button onClick={handlePrev} className="px-8 py-4 rounded-2xl border border-gray-100 text-gray-400 font-bold hover:bg-gray-50 transition-all">Back</button>}
        <button onClick={handleNext} className="flex-1 bg-brand-primary text-white font-black py-4 rounded-2xl text-lg hover:bg-brand-secondary transition-all shadow-xl shadow-brand-primary/30 active:scale-95">
            {step === totalSteps ? 'Complete Registry' : 'Continue'}
        </button>
      </div>

      <style>{`
        .animate-slide-in { animation: slideIn 0.5s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        .animate-scale-in { animation: scaleIn 0.6s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        @keyframes slideIn { from { opacity: 0; transform: translateX(20px); } to { opacity: 1; transform: translateX(0); } }
        @keyframes scaleIn { from { opacity: 0; transform: scale(0.9); } to { opacity: 1; transform: scale(1); } }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
      `}</style>
    </div>
  );
};

export default OnboardingFlow;

import React, { useState } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';
import { CloseIcon } from './icons/CloseIcon';
import { COUNTRIES, STATES_BY_COUNTRY, CITIES_BY_STATE, MANUAL_ENTRY_OPTION } from '../services/locationData';

interface EditProfileScreenProps {
  user: User;
  onBack: () => void;
  onSave: (updatedUser: User) => void;
}

const EditProfileScreen: React.FC<EditProfileScreenProps> = ({ user, onBack, onSave }) => {
  const [formData, setFormData] = useState<User>(user);

  // Manual entry states
  const [resCountryManual, setResCountryManual] = useState(!COUNTRIES.includes(user.residenceCountry) ? user.residenceCountry : '');
  const [resStateManual, setResStateManual] = useState(user.residenceState && (!user.residenceCountry || !STATES_BY_COUNTRY[user.residenceCountry]?.includes(user.residenceState)) ? user.residenceState : '');
  const [resCityManual, setResCityManual] = useState(user.residenceCity && (!user.residenceState || !CITIES_BY_STATE[user.residenceState]?.includes(user.residenceCity)) ? user.residenceCity : '');

  const [origCountryManual, setOrigCountryManual] = useState(!COUNTRIES.includes(user.originCountry) ? user.originCountry : '');
  const [origStateManual, setOrigStateManual] = useState(user.originState && (!user.originCountry || !STATES_BY_COUNTRY[user.originCountry]?.includes(user.originState)) ? user.originState : '');
  const [origCityManual, setOrigCityManual] = useState(user.originCity && (!user.originState || !CITIES_BY_STATE[user.originState]?.includes(user.originCity)) ? user.originCity : '');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    if (name === 'residenceCountry') {
        setFormData(prev => ({ ...prev, residenceCountry: value, residenceState: '', residenceCity: '', country: value }));
        setResStateManual('');
        setResCityManual('');
    } else if (name === 'residenceState') {
        setFormData(prev => ({ ...prev, residenceState: value, residenceCity: '' }));
        setResCityManual('');
    } else if (name === 'originCountry') {
        setFormData(prev => ({ ...prev, originCountry: value, originState: '', originCity: '' }));
        setOrigStateManual('');
        setOrigCityManual('');
    } else if (name === 'originState') {
        setFormData(prev => ({ ...prev, originState: value, originCity: '' }));
        setOrigCityManual('');
    } else {
        setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleManualChange = (type: string, value: string) => {
    switch(type) {
        case 'resCountry': setResCountryManual(value); setFormData(p => ({...p, residenceCountry: value, country: value})); break;
        case 'resState': setResStateManual(value); setFormData(p => ({...p, residenceState: value})); break;
        case 'resCity': setResCityManual(value); setFormData(p => ({...p, residenceCity: value, city: value})); break;
        case 'origCountry': setOrigCountryManual(value); setFormData(p => ({...p, originCountry: value})); break;
        case 'origState': setOrigStateManual(value); setFormData(p => ({...p, originState: value})); break;
        case 'origCity': setOrigCityManual(value); setFormData(p => ({...p, originCity: value})); break;
    }
  };

  const handleSave = () => {
    onSave(formData);
  };

  const inputClass = "w-full p-2 border border-gray-300 rounded-lg bg-gray-50 text-black focus:bg-white focus:ring-2 focus:ring-brand-secondary focus:outline-none text-sm";
  const labelClass = "block text-[10px] font-black text-gray-400 mb-1 uppercase tracking-widest";
  const sectionClass = "p-4 bg-white rounded-lg shadow-sm border border-gray-200";

  const renderLocationInputs = (prefix: 'residence' | 'origin', sectionTitle: string) => {
    const isResidence = prefix === 'residence';
    const countryVal = isResidence ? formData.residenceCountry : formData.originCountry;
    const stateVal = isResidence ? formData.residenceState : formData.originState;
    const cityVal = isResidence ? formData.residenceCity : formData.originCity;

    const isCountryManual = countryVal === MANUAL_ENTRY_OPTION || (countryVal && !COUNTRIES.includes(countryVal));
    const isStateManual = stateVal === MANUAL_ENTRY_OPTION || (stateVal && countryVal && STATES_BY_COUNTRY[countryVal] && !STATES_BY_COUNTRY[countryVal].includes(stateVal));
    const isCityManual = cityVal === MANUAL_ENTRY_OPTION || (cityVal && stateVal && CITIES_BY_STATE[stateVal] && !CITIES_BY_STATE[stateVal].includes(cityVal));

    return (
        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">{sectionTitle}</h2>
          <div className="space-y-4">
            <div>
              <label className={labelClass}>Country</label>
              <select 
                name={`${prefix}Country`} 
                value={COUNTRIES.includes(countryVal) ? countryVal : (countryVal ? MANUAL_ENTRY_OPTION : '')} 
                onChange={handleChange} 
                className={inputClass}
              >
                  <option value="">Select Country</option>
                  {COUNTRIES.map(c => <option key={c} value={c}>{c}</option>)}
                  <option value={MANUAL_ENTRY_OPTION}>Not Listed...</option>
              </select>
              {isCountryManual && (
                  <input type="text" value={isResidence ? resCountryManual : origCountryManual} onChange={(e) => handleManualChange(isResidence ? 'resCountry' : 'origCountry', e.target.value)} className={`${inputClass} mt-2`} placeholder="Enter country manually" />
              )}
            </div>

            {countryVal && !isCountryManual && (
              <div>
                <label className={labelClass}>State / Province</label>
                <select 
                    name={`${prefix}State`} 
                    value={(STATES_BY_COUNTRY[countryVal] || []).includes(stateVal) ? stateVal : (stateVal ? MANUAL_ENTRY_OPTION : '')} 
                    onChange={handleChange} 
                    className={inputClass}
                >
                    <option value="">Select State</option>
                    {(STATES_BY_COUNTRY[countryVal] || []).map(s => <option key={s} value={s}>{s}</option>)}
                    <option value={MANUAL_ENTRY_OPTION}>Manual Entry...</option>
                </select>
                {isStateManual && (
                    <input type="text" value={isResidence ? resStateManual : origStateManual} onChange={(e) => handleManualChange(isResidence ? 'resState' : 'origState', e.target.value)} className={`${inputClass} mt-2`} placeholder="Enter state manually" />
                )}
              </div>
            )}

            {stateVal && !isStateManual && (
              <div>
                <label className={labelClass}>City / Town</label>
                <select 
                    name={`${prefix}City`} 
                    value={(CITIES_BY_STATE[stateVal] || []).includes(cityVal) ? cityVal : (cityVal ? MANUAL_ENTRY_OPTION : '')} 
                    onChange={handleChange} 
                    className={inputClass}
                >
                    <option value="">Select City</option>
                    {(CITIES_BY_STATE[stateVal] || []).map(c => <option key={c} value={c}>{c}</option>)}
                    <option value={MANUAL_ENTRY_OPTION}>Manual Entry...</option>
                </select>
                {isCityManual && (
                    <input type="text" value={isResidence ? resCityManual : origCityManual} onChange={(e) => handleManualChange(isResidence ? 'resCity' : 'origCity', e.target.value)} className={`${inputClass} mt-2`} placeholder="Enter city manually" />
                )}
              </div>
            )}
          </div>
        </div>
    );
  };

  return (
    <div className="w-full h-screen bg-gray-100 flex flex-col">
      <header className="flex items-center justify-between p-4 bg-white border-b border-gray-200 sticky top-0 z-10">
        <h1 className="text-xl font-bold text-brand-dark">Edit Registry</h1>
        <button onClick={onBack} className="p-1 rounded-full text-gray-400 hover:bg-gray-100">
          <CloseIcon className="w-6 h-6" />
        </button>
      </header>

      <main className="flex-1 p-4 space-y-4 overflow-y-auto pb-24">
        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">Basic Identity</h2>
          <div className="space-y-4">
            <div>
              <label className={labelClass}>Name</label>
              <input name="name" type="text" value={formData.name} onChange={handleChange} className={inputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className={labelClass}>Age</label>
                <input name="age" type="number" value={formData.age} onChange={handleChange} className={inputClass} />
              </div>
              <div>
                <label className={labelClass}>Marital Status</label>
                <select name="maritalStatus" value={formData.maritalStatus} onChange={handleChange} className={inputClass}>
                    {Object.values(MaritalStatus).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        </div>

        {renderLocationInputs('residence', 'Current Residence')}
        {renderLocationInputs('origin', 'Heritage & Origin')}

        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">Bio & Life</h2>
          <div className="space-y-4">
             <div>
              <label className={labelClass}>Occupation</label>
              <input name="occupation" type="text" value={formData.occupation} onChange={handleChange} className={inputClass} />
            </div>
            <div>
              <label className={labelClass}>Bio</label>
              <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className={inputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className={labelClass}>Smoking</label>
                <select name="smoking" value={formData.smoking} onChange={handleChange} className={inputClass}>
                  {Object.values(SmokingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
               <div>
                <label className={labelClass}>Drinking</label>
                <select name="drinking" value={formData.drinking} onChange={handleChange} className={inputClass}>
                  {Object.values(DrinkingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        </div>

        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">Expectations</h2>
          <div className="space-y-4">
             <div>
              <label className={labelClass}>Timeline</label>
              <input name="marriageTimeline" type="text" value={formData.marriageTimeline} onChange={handleChange} className={inputClass} />
            </div>
             <div>
              <label className={labelClass}>Children Intent</label>
              <select name="childrenPreference" value={formData.childrenPreference} onChange={handleChange} className={inputClass}>
                  {Object.values(ChildrenPreference).map(v => <option key={v} value={v}>{v}</option>)}
              </select>
            </div>
            <div>
              <label className={labelClass}>Relocate?</label>
              <select name="willingToRelocate" value={formData.willingToRelocate} onChange={handleChange} className={inputClass}>
                  {Object.values(WillingToRelocate).map(v => <option key={v} value={v}>{v}</option>)}
              </select>
            </div>
          </div>
        </div>
      </main>

      <footer className="p-4 bg-white border-t border-gray-200 sticky bottom-0">
        <button onClick={handleSave} className="w-full bg-brand-primary text-white font-bold py-3 rounded-lg hover:bg-brand-secondary transition-colors shadow-lg">
          Save Registry Updates
        </button>
      </footer>
    </div>
  );
};

export default EditProfileScreen;

import React, { useState, useRef } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';
import { PlusIcon } from './icons/PlusIcon';
import { SparklesIcon } from './icons/SparklesIcon';
import { COUNTRIES, STATES_BY_COUNTRY, CITIES_BY_STATE } from '../services/locationData';

interface OnboardingFlowProps {
  user: User;
  onComplete: (updatedUser: User) => void;
}

const OnboardingFlow: React.FC<OnboardingFlowProps> = ({ user, onComplete }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<User>(user);
  const [isProcessing, setIsProcessing] = useState(false);

  // Manual Entry Toggles
  const [manualStates, setManualStates] = useState<Record<string, boolean>>({});
  const [manualCities, setManualCities] = useState<Record<string, boolean>>({});

  const fileInputRef = useRef<HTMLInputElement>(null);
  const totalSteps = 4;

  const handleNext = () => {
    if (step === 1) {
        if (!formData.residenceCountry || !formData.originCountry || !formData.residenceCity || !formData.originCity) {
            alert("Accurate location data is required for matching. Please complete your residence and origin details.");
            return;
        }
    }
    if (step === 4 && formData.profileImageUrls.length === 0) {
        alert("A profile picture is mandatory for verification.");
        return;
    }
    if (step < totalSteps) {
      setStep(step + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      onComplete(formData);
    }
  };

  const handlePrev = () => {
    if (step > 1) {
      setStep(step - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    // Cascading reset logic
    if (name === 'residenceCountry') {
        setFormData(prev => ({ ...prev, residenceCountry: value, residenceState: '', residenceCity: '', country: value }));
        setManualStates(p => ({ ...p, residence: false }));
        setManualCities(p => ({ ...p, residence: false }));
    } else if (name === 'residenceState') {
        setFormData(prev => ({ ...prev, residenceState: value, residenceCity: '' }));
        setManualCities(p => ({ ...p, residence: false }));
    } else if (name === 'originCountry') {
        setFormData(prev => ({ ...prev, originCountry: value, originState: '', originCity: '' }));
        setManualStates(p => ({ ...p, origin: false }));
        setManualCities(p => ({ ...p, origin: false }));
    } else if (name === 'originState') {
        setFormData(prev => ({ ...prev, originState: value, originCity: '' }));
        setManualCities(p => ({ ...p, origin: false }));
    } else if (name === 'residenceCity') {
        setFormData(prev => ({ ...prev, residenceCity: value, city: value }));
    } else {
        setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const toggleManual = (type: 'state' | 'city', prefix: 'residence' | 'origin') => {
    if (type === 'state') {
        const isNowManual = !manualStates[prefix];
        setManualStates(p => ({ ...p, [prefix]: isNowManual }));
        if (isNowManual) setFormData(p => ({ ...p, [`${prefix}State`]: '', [`${prefix}City`]: '' }));
    } else {
        const isNowManual = !manualCities[prefix];
        setManualCities(p => ({ ...p, [prefix]: isNowManual }));
        if (isNowManual) setFormData(p => ({ ...p, [`${prefix}City`]: '' }));
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const result = event.target?.result as string;
      if (result) setFormData({ ...formData, profileImageUrls: [result] });
      setIsProcessing(false);
    };
    reader.readAsDataURL(file);
  };

  const inputClass = "w-full p-4 border border-gray-200 rounded-2xl bg-white text-black focus:ring-2 focus:ring-brand-primary focus:border-transparent focus:outline-none shadow-sm transition-all text-sm";
  const labelClass = "block text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest";
  const sectionTitleClass = "text-xs font-black text-brand-primary uppercase tracking-widest border-b pb-2 mb-4 mt-6";
  const manualToggleClass = "text-[10px] text-brand-secondary font-bold uppercase tracking-tighter cursor-pointer hover:underline mt-1 block text-right";

  const renderLocationGroup = (prefix: 'residence' | 'origin', title: string) => {
    const countryVal = formData[`${prefix}Country` as keyof User] as string;
    const stateVal = formData[`${prefix}State` as keyof User] as string;
    const cityVal = formData[`${prefix}City` as keyof User] as string;

    const availableStates = STATES_BY_COUNTRY[countryVal] || [];
    const availableCities = CITIES_BY_STATE[stateVal] || [];

    return (
      <div className="space-y-4">
        <h3 className={sectionTitleClass}>{title}</h3>

        {/* Country */}
        <div>
          <label className={labelClass}>Country</label>
          <select name={`${prefix}Country`} value={countryVal} onChange={handleChange} className={inputClass}>
            <option value="">Select Country</option>
            {COUNTRIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>

        {/* State */}
        {countryVal && (
          <div>
            <label className={labelClass}>State / Province</label>
            {manualStates[prefix] ? (
               <input 
                 name={`${prefix}State`} 
                 value={stateVal} 
                 onChange={handleChange} 
                 className={inputClass} 
                 placeholder="Type your state/province" 
               />
            ) : (
                <select name={`${prefix}State`} value={stateVal} onChange={handleChange} className={inputClass}>
                    <option value="">Select State</option>
                    {availableStates.map(s => <option key={s} value={s}>{s}</option>)}
                </select>
            )}
            <span onClick={() => toggleManual('state', prefix)} className={manualToggleClass}>
                {manualStates[prefix] ? 'Show List' : "Can't find state?"}
            </span>
          </div>
        )}

        {/* City */}
        {(stateVal || manualStates[prefix]) && (
          <div>
            <label className={labelClass}>City / Town</label>
            {manualCities[prefix] || manualStates[prefix] ? (
                <input 
                  name={`${prefix}City`} 
                  value={cityVal} 
                  onChange={handleChange} 
                  className={inputClass} 
                  placeholder="Type your city/town" 
                />
            ) : (
                <select name={`${prefix}City`} value={cityVal} onChange={handleChange} className={inputClass}>
                    <option value="">Select City</option>
                    {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
            )}
            {!manualStates[prefix] && (
                <span onClick={() => toggleManual('city', prefix)} className={manualToggleClass}>
                    {manualCities[prefix] ? 'Show List' : "Can't find city?"}
                </span>
            )}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-white flex flex-col p-6 pb-32 relative font-sans">
      <div className="mb-10">
        <div className="flex justify-between items-end mb-3">
            <div>
                <h4 className="text-[10px] font-black text-brand-primary uppercase tracking-[0.2em]">Knot Global Registry</h4>
                <h2 className="text-2xl font-black text-brand-dark">
                  {step === 1 && 'Identity & Roots'}
                  {step === 2 && 'Lifestyle & Values'}
                  {step === 3 && 'Commitment'}
                  {step === 4 && 'First Impressions'}
                </h2>
            </div>
            <span className="text-xs font-bold text-gray-300 uppercase tracking-widest">{step}/{totalSteps}</span>
        </div>
        <div className="w-full h-1.5 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-brand-primary transition-all duration-700 ease-in-out" style={{ width: `${(step / totalSteps) * 100}%` }}></div>
        </div>
      </div>

      <div className="flex-1 animate-slide-in">
        {step === 1 && (
          <div className="space-y-6">
            <div>
              <label className={labelClass}>Full Name</label>
              <input name="name" value={formData.name} onChange={handleChange} className={inputClass} placeholder="Enter your name" />
            </div>
            <div className="grid grid-cols-2 gap-4">
               <div>
                  <label className={labelClass}>Age</label>
                  <input type="number" name="age" value={formData.age} onChange={handleChange} className={inputClass} />
               </div>
               <div>
                  <label className={labelClass}>Occupation</label>
                  <input name="occupation" value={formData.occupation} onChange={handleChange} className={inputClass} placeholder="e.g. Architect" />
               </div>
            </div>

            {renderLocationGroup('residence', 'Current Residence')}
            {renderLocationGroup('origin', 'Heritage & Origin')}

            <div className="pt-4">
                <label className={labelClass}>Marriage-Oriented Bio</label>
                <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className={inputClass} placeholder="What are you looking for in a life partner?" />
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Honesty about your lifestyle ensures a more stable marriage match.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Religion / Faith</label>
                <input name="religion" value={formData.religion} onChange={handleChange} className={inputClass} placeholder="e.g. Christian, Muslim, Secular" />
              </div>
              <div>
                <label className={labelClass}>Cultural / Ethnic Roots</label>
                <input name="culturalBackground" value={formData.culturalBackground} onChange={handleChange} className={inputClass} placeholder="e.g. South Asian, Hispanic" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelClass}>Smoking</label>
                  <select name="smoking" value={formData.smoking} onChange={handleChange} className={inputClass}>
                    {Object.values(SmokingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelClass}>Drinking</label>
                  <select name="drinking" value={formData.drinking} onChange={handleChange} className={inputClass}>
                    {Object.values(DrinkingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Knot matches users based on their marriage timeline and relocation readiness.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Ideal Marriage Timeline</label>
                <select name="marriageTimeline" value={formData.marriageTimeline} onChange={handleChange} className={inputClass}>
                    <option value="ASAP">As soon as I find the one</option>
                    <option value="1-2 years">Within 1-2 years</option>
                    <option value="3+ years">3+ years</option>
                    <option value="Not sure">Not sure yet</option>
                </select>
              </div>
              <div>
                <label className={labelClass}>Future Children</label>
                <select name="childrenPreference" value={formData.childrenPreference} onChange={handleChange} className={inputClass}>
                  {Object.values(ChildrenPreference).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
              <div>
                <label className={labelClass}>Relocation Willingness</label>
                <select name="willingToRelocate" value={formData.willingToRelocate} onChange={handleChange} className={inputClass}>
                  {Object.values(WillingToRelocate).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-8 text-center px-4">
            <div className="animate-fade-in">
                <div className="flex justify-center mb-2">
                    <SparklesIcon className="w-6 h-6 text-brand-accent animate-pulse" />
                </div>
                <h3 className="text-3xl font-serif text-brand-primary mb-2">First Impressions</h3>
                <p className="text-gray-500 text-sm leading-relaxed">Registry members prefer authentic, high-quality portraits.</p>
            </div>
            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
            <div onClick={() => fileInputRef.current?.click()} className="relative inline-block w-full max-w-[280px] aspect-[4/5] mx-auto cursor-pointer group animate-scale-in">
                <div className={`w-full h-full rounded-[2.5rem] border-4 border-dashed ${formData.profileImageUrls.length > 0 ? 'border-brand-primary border-solid' : 'border-gray-200'} overflow-hidden bg-gray-50 flex items-center justify-center shadow-2xl transition-all hover:bg-brand-light active:scale-[0.98]`}>
                    {formData.profileImageUrls.length > 0 ? (
                         <img src={formData.profileImageUrls[0]} className="w-full h-full object-cover animate-fade-in" />
                    ) : (
                        <div className="text-center p-8">
                            {isProcessing ? (
                                <div className="w-12 h-12 border-4 border-brand-primary border-t-transparent rounded-full animate-spin mx-auto"></div>
                            ) : (
                                <>
                                    <div className="w-20 h-20 bg-brand-light rounded-full flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                                        <PlusIcon className="h-10 w-10 text-brand-primary" />
                                    </div>
                                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest leading-relaxed px-4">Tap to upload your registry photo</p>
                                </>
                            )}
                        </div>
                    )}
                </div>
            </div>
          </div>
        )}
      </div>

      <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto p-6 bg-white flex items-center gap-4 z-30 border-t border-gray-50">
        {step > 1 && <button onClick={handlePrev} className="px-8 py-4 rounded-2xl border border-gray-100 text-gray-400 font-bold hover:bg-gray-50 transition-all">Back</button>}
        <button onClick={handleNext} className="flex-1 bg-brand-primary text-white font-black py-4 rounded-2xl text-lg hover:bg-brand-secondary transition-all shadow-xl shadow-brand-primary/30 active:scale-95">
            {step === totalSteps ? 'Activate Registry' : 'Continue'}
        </button>
      </div>

      <style>{`
        .animate-slide-in { animation: slideIn 0.5s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        .animate-scale-in { animation: scaleIn 0.6s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        @keyframes slideIn { from { opacity: 0; transform: translateX(20px); } to { opacity: 1; transform: translateX(0); } }
        @keyframes scaleIn { from { opacity: 0; transform: scale(0.9); } to { opacity: 1; transform: scale(1); } }
      `}</style>
    </div>
  );
};

export default OnboardingFlow;

import React, { useState } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';
import { CloseIcon } from './icons/CloseIcon';
import { COUNTRIES, STATES_BY_COUNTRY, CITIES_BY_STATE } from '../services/locationData';

interface EditProfileScreenProps {
  user: User;
  onBack: () => void;
  onSave: (updatedUser: User) => void;
}

const EditProfileScreen: React.FC<EditProfileScreenProps> = ({ user, onBack, onSave }) => {
  const [formData, setFormData] = useState<User>(user);

  // Manual entry tracking
  const [manualStates, setManualStates] = useState<Record<string, boolean>>({
    residence: user.residenceState && !STATES_BY_COUNTRY[user.residenceCountry]?.includes(user.residenceState),
    origin: user.originState && !STATES_BY_COUNTRY[user.originCountry]?.includes(user.originState)
  });
  const [manualCities, setManualCities] = useState<Record<string, boolean>>({
    residence: user.residenceCity && !CITIES_BY_STATE[user.residenceState]?.includes(user.residenceCity),
    origin: user.originCity && !CITIES_BY_STATE[user.originState]?.includes(user.originCity)
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    if (name === 'residenceCountry') {
        setFormData(prev => ({ ...prev, residenceCountry: value, residenceState: '', residenceCity: '', country: value }));
        setManualStates(p => ({ ...p, residence: false }));
        setManualCities(p => ({ ...p, residence: false }));
    } else if (name === 'residenceState') {
        setFormData(prev => ({ ...prev, residenceState: value, residenceCity: '' }));
        setManualCities(p => ({ ...p, residence: false }));
    } else if (name === 'originCountry') {
        setFormData(prev => ({ ...prev, originCountry: value, originState: '', originCity: '' }));
        setManualStates(p => ({ ...p, origin: false }));
        setManualCities(p => ({ ...p, origin: false }));
    } else if (name === 'originState') {
        setFormData(prev => ({ ...prev, originState: value, originCity: '' }));
        setManualCities(p => ({ ...p, origin: false }));
    } else if (name === 'residenceCity') {
        setFormData(prev => ({ ...prev, residenceCity: value, city: value }));
    } else {
        setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const toggleManual = (type: 'state' | 'city', prefix: 'residence' | 'origin') => {
    if (type === 'state') {
        const isNowManual = !manualStates[prefix];
        setManualStates(p => ({ ...p, [prefix]: isNowManual }));
        if (isNowManual) setFormData(p => ({ ...p, [`${prefix}State`]: '', [`${prefix}City`]: '' }));
    } else {
        const isNowManual = !manualCities[prefix];
        setManualCities(p => ({ ...p, [prefix]: isNowManual }));
        if (isNowManual) setFormData(p => ({ ...p, [`${prefix}City`]: '' }));
    }
  };

  const handleSave = () => {
    onSave(formData);
  };

  const inputClass = "w-full p-2.5 border border-gray-300 rounded-lg bg-gray-50 text-black focus:bg-white focus:ring-2 focus:ring-brand-secondary focus:outline-none text-sm";
  const labelClass = "block text-[10px] font-black text-gray-400 mb-1 uppercase tracking-widest";
  const sectionClass = "p-4 bg-white rounded-lg shadow-sm border border-gray-200";
  const manualToggleClass = "text-[9px] text-brand-primary font-bold uppercase tracking-tighter cursor-pointer hover:underline mt-1 block text-right";

  const renderLocationInputs = (prefix: 'residence' | 'origin', sectionTitle: string) => {
    const countryVal = formData[`${prefix}Country` as keyof User] as string;
    const stateVal = formData[`${prefix}State` as keyof User] as string;
    const cityVal = formData[`${prefix}City` as keyof User] as string;

    const availableStates = STATES_BY_COUNTRY[countryVal] || [];
    const availableCities = CITIES_BY_STATE[stateVal] || [];

    return (
        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">{sectionTitle}</h2>
          <div className="space-y-4">
            <div>
              <label className={labelClass}>Country</label>
              <select name={`${prefix}Country`} value={countryVal} onChange={handleChange} className={inputClass}>
                  <option value="">Select Country</option>
                  {COUNTRIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>

            {countryVal && (
              <div>
                <label className={labelClass}>State / Province</label>
                {manualStates[prefix] ? (
                    <input 
                      name={`${prefix}State`} 
                      value={stateVal} 
                      onChange={handleChange} 
                      className={inputClass} 
                      placeholder="Type state name" 
                    />
                ) : (
                    <select name={`${prefix}State`} value={stateVal} onChange={handleChange} className={inputClass}>
                        <option value="">Select State</option>
                        {availableStates.map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                )}
                <span onClick={() => toggleManual('state', prefix)} className={manualToggleClass}>
                    {manualStates[prefix] ? 'Return to List' : "State not listed?"}
                </span>
              </div>
            )}

            {(stateVal || manualStates[prefix]) && (
              <div>
                <label className={labelClass}>City / Town</label>
                {manualCities[prefix] || manualStates[prefix] ? (
                    <input 
                      name={`${prefix}City`} 
                      value={cityVal} 
                      onChange={handleChange} 
                      className={inputClass} 
                      placeholder="Type city name" 
                    />
                ) : (
                    <select name={`${prefix}City`} value={cityVal} onChange={handleChange} className={inputClass}>
                        <option value="">Select City</option>
                        {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                )}
                {!manualStates[prefix] && (
                    <span onClick={() => toggleManual('city', prefix)} className={manualToggleClass}>
                        {manualCities[prefix] ? 'Return to List' : "City not listed?"}
                    </span>
                )}
              </div>
            )}
          </div>
        </div>
    );
  };

  return (
    <div className="w-full h-screen bg-gray-100 flex flex-col">
      <header className="flex items-center justify-between p-4 bg-white border-b border-gray-200 sticky top-0 z-10">
        <h1 className="text-xl font-bold text-brand-dark">Edit Registry</h1>
        <button onClick={onBack} className="p-1 rounded-full text-gray-400 hover:bg-gray-100">
          <CloseIcon className="w-6 h-6" />
        </button>
      </header>

      <main className="flex-1 p-4 space-y-4 overflow-y-auto pb-24">
        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">Identity</h2>
          <div className="space-y-4">
            <div>
              <label className={labelClass}>Name</label>
              <input name="name" type="text" value={formData.name} onChange={handleChange} className={inputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className={labelClass}>Age</label>
                <input name="age" type="number" value={formData.age} onChange={handleChange} className={inputClass} />
              </div>
              <div>
                <label className={labelClass}>Marital Status</label>
                <select name="maritalStatus" value={formData.maritalStatus} onChange={handleChange} className={inputClass}>
                    {Object.values(MaritalStatus).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        </div>

        {renderLocationInputs('residence', 'Current Residence')}
        {renderLocationInputs('origin', 'Heritage & Roots')}

        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">Bio & Lifestyle</h2>
          <div className="space-y-4">
             <div>
              <label className={labelClass}>Occupation</label>
              <input name="occupation" type="text" value={formData.occupation} onChange={handleChange} className={inputClass} />
            </div>
            <div>
              <label className={labelClass}>Registry Bio</label>
              <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className={inputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className={labelClass}>Smoking</label>
                <select name="smoking" value={formData.smoking} onChange={handleChange} className={inputClass}>
                  {Object.values(SmokingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
               <div>
                <label className={labelClass}>Drinking</label>
                <select name="drinking" value={formData.drinking} onChange={handleChange} className={inputClass}>
                  {Object.values(DrinkingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        </div>
      </main>

      <footer className="p-4 bg-white border-t border-gray-200 sticky bottom-0">
        <button onClick={handleSave} className="w-full bg-brand-primary text-white font-bold py-3 rounded-lg hover:bg-brand-secondary transition-colors shadow-lg">
          Save Registry Updates
        </button>
      </footer>
    </div>
  );
};

export default EditProfileScreen;

import React, { useState, useRef } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';
import { PlusIcon } from './icons/PlusIcon';
import { SparklesIcon } from './icons/SparklesIcon';
import { COUNTRIES, STATES_BY_COUNTRY, CITIES_BY_STATE } from '../services/locationData';

interface OnboardingFlowProps {
  user: User;
  onComplete: (updatedUser: User) => void;
}

const OnboardingFlow: React.FC<OnboardingFlowProps> = ({ user, onComplete }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<User>(user);
  const [isProcessing, setIsProcessing] = useState(false);

  // Manual Entry Tracking (Used for UI toggles if the user explicitly wants to type)
  const [manualStates, setManualStates] = useState<Record<string, boolean>>({});
  const [manualCities, setManualCities] = useState<Record<string, boolean>>({});

  const fileInputRef = useRef<HTMLInputElement>(null);
  const totalSteps = 4;

  const handleNext = () => {
    if (step === 1) {
        if (!formData.residenceCountry || !formData.originCountry || !formData.residenceCity || !formData.originCity) {
            alert("Accurate location data is required for matching. Please complete your residence and origin details.");
            return;
        }
    }
    if (step === 4 && formData.profileImageUrls.length === 0) {
        alert("A profile picture is mandatory for verification.");
        return;
    }
    if (step < totalSteps) {
      setStep(step + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      onComplete(formData);
    }
  };

  const handlePrev = () => {
    if (step > 1) {
      setStep(step - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    // Cascading reset logic
    if (name === 'residenceCountry') {
        setFormData(prev => ({ ...prev, residenceCountry: value, residenceState: '', residenceCity: '', country: value }));
        setManualStates(p => ({ ...p, residence: false }));
        setManualCities(p => ({ ...p, residence: false }));
    } else if (name === 'residenceState') {
        setFormData(prev => ({ ...prev, residenceState: value, residenceCity: '' }));
        setManualCities(p => ({ ...p, residence: false }));
    } else if (name === 'originCountry') {
        setFormData(prev => ({ ...prev, originCountry: value, originState: '', originCity: '' }));
        setManualStates(p => ({ ...p, origin: false }));
        setManualCities(p => ({ ...p, origin: false }));
    } else if (name === 'originState') {
        setFormData(prev => ({ ...prev, originState: value, originCity: '' }));
        setManualCities(p => ({ ...p, origin: false }));
    } else if (name === 'residenceCity') {
        setFormData(prev => ({ ...prev, residenceCity: value, city: value }));
    } else {
        setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const toggleManual = (type: 'state' | 'city', prefix: 'residence' | 'origin') => {
    if (type === 'state') {
        const isNowManual = !manualStates[prefix];
        setManualStates(p => ({ ...p, [prefix]: isNowManual }));
        if (isNowManual) setFormData(p => ({ ...p, [`${prefix}State`]: '', [`${prefix}City`]: '' }));
    } else {
        const isNowManual = !manualCities[prefix];
        setManualCities(p => ({ ...p, [prefix]: isNowManual }));
        if (isNowManual) setFormData(p => ({ ...p, [`${prefix}City`]: '' }));
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const result = event.target?.result as string;
      if (result) setFormData({ ...formData, profileImageUrls: [result] });
      setIsProcessing(false);
    };
    reader.readAsDataURL(file);
  };

  const inputClass = "w-full p-4 border border-gray-200 rounded-2xl bg-white text-black focus:ring-2 focus:ring-brand-primary focus:border-transparent focus:outline-none shadow-sm transition-all text-sm";
  const labelClass = "block text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest";
  const sectionTitleClass = "text-xs font-black text-brand-primary uppercase tracking-widest border-b pb-2 mb-4 mt-6";
  const manualToggleClass = "text-[10px] text-brand-secondary font-bold uppercase tracking-tighter cursor-pointer hover:underline mt-1 block text-right";

  const renderLocationGroup = (prefix: 'residence' | 'origin', title: string) => {
    const countryVal = formData[`${prefix}Country` as keyof User] as string;
    const stateVal = formData[`${prefix}State` as keyof User] as string;
    const cityVal = formData[`${prefix}City` as keyof User] as string;

    const availableStates = STATES_BY_COUNTRY[countryVal] || [];
    const availableCities = CITIES_BY_STATE[stateVal] || [];

    // Auto-detect if we should show input instead of dropdown
    const showStateInput = manualStates[prefix] || (countryVal && availableStates.length === 0);
    const showCityInput = manualCities[prefix] || manualStates[prefix] || (stateVal && availableCities.length === 0);

    return (
      <div className="space-y-4">
        <h3 className={sectionTitleClass}>{title}</h3>

        {/* Country */}
        <div>
          <label className={labelClass}>Country</label>
          <select name={`${prefix}Country`} value={countryVal} onChange={handleChange} className={inputClass}>
            <option value="">Select Country</option>
            {COUNTRIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>

        {/* State */}
        {countryVal && (
          <div>
            <label className={labelClass}>State / Province</label>
            {showStateInput ? (
               <input 
                 name={`${prefix}State`} 
                 value={stateVal} 
                 onChange={handleChange} 
                 className={inputClass} 
                 placeholder="Type your state/province" 
               />
            ) : (
                <select name={`${prefix}State`} value={stateVal} onChange={handleChange} className={inputClass}>
                    <option value="">Select State</option>
                    {availableStates.map(s => <option key={s} value={s}>{s}</option>)}
                </select>
            )}
            {availableStates.length > 0 && (
                <span onClick={() => toggleManual('state', prefix)} className={manualToggleClass}>
                    {manualStates[prefix] ? 'Show List' : "Can't find state?"}
                </span>
            )}
          </div>
        )}

        {/* City */}
        {(stateVal || showStateInput) && (
          <div>
            <label className={labelClass}>City / Town</label>
            {showCityInput ? (
                <input 
                  name={`${prefix}City`} 
                  value={cityVal} 
                  onChange={handleChange} 
                  className={inputClass} 
                  placeholder="Type your city/town" 
                />
            ) : (
                <select name={`${prefix}City`} value={cityVal} onChange={handleChange} className={inputClass}>
                    <option value="">Select City</option>
                    {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
            )}
            {!showStateInput && availableCities.length > 0 && (
                <span onClick={() => toggleManual('city', prefix)} className={manualToggleClass}>
                    {manualCities[prefix] ? 'Show List' : "Can't find city?"}
                </span>
            )}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-white flex flex-col p-6 pb-32 relative font-sans">
      <div className="mb-10">
        <div className="flex justify-between items-end mb-3">
            <div>
                <h4 className="text-[10px] font-black text-brand-primary uppercase tracking-[0.2em]">Knot Global Registry</h4>
                <h2 className="text-2xl font-black text-brand-dark">
                  {step === 1 && 'Identity & Roots'}
                  {step === 2 && 'Lifestyle & Values'}
                  {step === 3 && 'Commitment'}
                  {step === 4 && 'First Impressions'}
                </h2>
            </div>
            <span className="text-xs font-bold text-gray-300 uppercase tracking-widest">{step}/{totalSteps}</span>
        </div>
        <div className="w-full h-1.5 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-brand-primary transition-all duration-700 ease-in-out" style={{ width: `${(step / totalSteps) * 100}%` }}></div>
        </div>
      </div>

      <div className="flex-1 animate-slide-in">
        {step === 1 && (
          <div className="space-y-6">
            <div>
              <label className={labelClass}>Full Name</label>
              <input name="name" value={formData.name} onChange={handleChange} className={inputClass} placeholder="Enter your name" />
            </div>
            <div className="grid grid-cols-2 gap-4">
               <div>
                  <label className={labelClass}>Age</label>
                  <input type="number" name="age" value={formData.age} onChange={handleChange} className={inputClass} />
               </div>
               <div>
                  <label className={labelClass}>Occupation</label>
                  <input name="occupation" value={formData.occupation} onChange={handleChange} className={inputClass} placeholder="e.g. Architect" />
               </div>
            </div>

            {renderLocationGroup('residence', 'Current Residence')}
            {renderLocationGroup('origin', 'Heritage & Origin')}

            <div className="pt-4">
                <label className={labelClass}>Marriage-Oriented Bio</label>
                <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className={inputClass} placeholder="What are you looking for in a life partner?" />
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Honesty about your lifestyle ensures a more stable marriage match.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Religion / Faith</label>
                <input name="religion" value={formData.religion} onChange={handleChange} className={inputClass} placeholder="e.g. Christian, Muslim, Secular" />
              </div>
              <div>
                <label className={labelClass}>Cultural / Ethnic Roots</label>
                <input name="culturalBackground" value={formData.culturalBackground} onChange={handleChange} className={inputClass} placeholder="e.g. South Asian, Hispanic" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelClass}>Smoking</label>
                  <select name="smoking" value={formData.smoking} onChange={handleChange} className={inputClass}>
                    {Object.values(SmokingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelClass}>Drinking</label>
                  <select name="drinking" value={formData.drinking} onChange={handleChange} className={inputClass}>
                    {Object.values(DrinkingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Knot matches users based on their marriage timeline and relocation readiness.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Ideal Marriage Timeline</label>
                <select name="marriageTimeline" value={formData.marriageTimeline} onChange={handleChange} className={inputClass}>
                    <option value="ASAP">As soon as I find the one</option>
                    <option value="1-2 years">Within 1-2 years</option>
                    <option value="3+ years">3+ years</option>
                    <option value="Not sure">Not sure yet</option>
                </select>
              </div>
              <div>
                <label className={labelClass}>Future Children</label>
                <select name="childrenPreference" value={formData.childrenPreference} onChange={handleChange} className={inputClass}>
                  {Object.values(ChildrenPreference).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
              <div>
                <label className={labelClass}>Relocation Willingness</label>
                <select name="willingToRelocate" value={formData.willingToRelocate} onChange={handleChange} className={inputClass}>
                  {Object.values(WillingToRelocate).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-8 text-center px-4">
            <div className="animate-fade-in">
                <div className="flex justify-center mb-2">
                    <SparklesIcon className="w-6 h-6 text-brand-accent animate-pulse" />
                </div>
                <h3 className="text-3xl font-serif text-brand-primary mb-2">First Impressions</h3>
                <p className="text-gray-500 text-sm leading-relaxed">Registry members prefer authentic, high-quality portraits.</p>
            </div>
            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
            <div onClick={() => fileInputRef.current?.click()} className="relative inline-block w-full max-w-[280px] aspect-[4/5] mx-auto cursor-pointer group animate-scale-in">
                <div className={`w-full h-full rounded-[2.5rem] border-4 border-dashed ${formData.profileImageUrls.length > 0 ? 'border-brand-primary border-solid' : 'border-gray-200'} overflow-hidden bg-gray-50 flex items-center justify-center shadow-2xl transition-all hover:bg-brand-light active:scale-[0.98]`}>
                    {formData.profileImageUrls.length > 0 ? (
                         <img src={formData.profileImageUrls[0]} className="w-full h-full object-cover animate-fade-in" />
                    ) : (
                        <div className="text-center p-8">
                            {isProcessing ? (
                                <div className="w-12 h-12 border-4 border-brand-primary border-t-transparent rounded-full animate-spin mx-auto"></div>
                            ) : (
                                <>
                                    <div className="w-20 h-20 bg-brand-light rounded-full flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                                        <PlusIcon className="h-10 w-10 text-brand-primary" />
                                    </div>
                                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest leading-relaxed px-4">Tap to upload your registry photo</p>
                                </>
                            )}
                        </div>
                    )}
                </div>
            </div>
          </div>
        )}
      </div>

      <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto p-6 bg-white flex items-center gap-4 z-30 border-t border-gray-50">
        {step > 1 && <button onClick={handlePrev} className="px-8 py-4 rounded-2xl border border-gray-100 text-gray-400 font-bold hover:bg-gray-50 transition-all">Back</button>}
        <button onClick={handleNext} className="flex-1 bg-brand-primary text-white font-black py-4 rounded-2xl text-lg hover:bg-brand-secondary transition-all shadow-xl shadow-brand-primary/30 active:scale-95">
            {step === totalSteps ? 'Activate Registry' : 'Continue'}
        </button>
      </div>

      <style>{`
        .animate-slide-in { animation: slideIn 0.5s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        .animate-scale-in { animation: scaleIn 0.6s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        @keyframes slideIn { from { opacity: 0; transform: translateX(20px); } to { opacity: 1; transform: translateX(0); } }
        @keyframes scaleIn { from { opacity: 0; transform: scale(0.9); } to { opacity: 1; transform: scale(1); } }
      `}</style>
    </div>
  );
};

export default OnboardingFlow;

import React, { useState } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';
import { CloseIcon } from './icons/CloseIcon';
import { COUNTRIES, STATES_BY_COUNTRY, CITIES_BY_STATE } from '../services/locationData';

interface EditProfileScreenProps {
  user: User;
  onBack: () => void;
  onSave: (updatedUser: User) => void;
}

const EditProfileScreen: React.FC<EditProfileScreenProps> = ({ user, onBack, onSave }) => {
  const [formData, setFormData] = useState<User>(user);

  // Manual entry tracking
  const [manualStates, setManualStates] = useState<Record<string, boolean>>({
    residence: user.residenceState && (!user.residenceCountry || !STATES_BY_COUNTRY[user.residenceCountry]?.includes(user.residenceState)),
    origin: user.originState && (!user.originCountry || !STATES_BY_COUNTRY[user.originCountry]?.includes(user.originState))
  });
  const [manualCities, setManualCities] = useState<Record<string, boolean>>({
    residence: user.residenceCity && (!user.residenceState || !CITIES_BY_STATE[user.residenceState]?.includes(user.residenceCity)),
    origin: user.originCity && (!user.originState || !CITIES_BY_STATE[user.originState]?.includes(user.originCity))
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    if (name === 'residenceCountry') {
        setFormData(prev => ({ ...prev, residenceCountry: value, residenceState: '', residenceCity: '', country: value }));
        setManualStates(p => ({ ...p, residence: false }));
        setManualCities(p => ({ ...p, residence: false }));
    } else if (name === 'residenceState') {
        setFormData(prev => ({ ...prev, residenceState: value, residenceCity: '' }));
        setManualCities(p => ({ ...p, residence: false }));
    } else if (name === 'originCountry') {
        setFormData(prev => ({ ...prev, originCountry: value, originState: '', originCity: '' }));
        setManualStates(p => ({ ...p, origin: false }));
        setManualCities(p => ({ ...p, origin: false }));
    } else if (name === 'originState') {
        setFormData(prev => ({ ...prev, originState: value, originCity: '' }));
        setManualCities(p => ({ ...p, origin: false }));
    } else if (name === 'residenceCity') {
        setFormData(prev => ({ ...prev, residenceCity: value, city: value }));
    } else {
        setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const toggleManual = (type: 'state' | 'city', prefix: 'residence' | 'origin') => {
    if (type === 'state') {
        const isNowManual = !manualStates[prefix];
        setManualStates(p => ({ ...p, [prefix]: isNowManual }));
        if (isNowManual) setFormData(p => ({ ...p, [`${prefix}State`]: '', [`${prefix}City`]: '' }));
    } else {
        const isNowManual = !manualCities[prefix];
        setManualCities(p => ({ ...p, [prefix]: isNowManual }));
        if (isNowManual) setFormData(p => ({ ...p, [`${prefix}City`]: '' }));
    }
  };

  const handleSave = () => {
    onSave(formData);
  };

  const inputClass = "w-full p-2.5 border border-gray-300 rounded-lg bg-gray-50 text-black focus:bg-white focus:ring-2 focus:ring-brand-secondary focus:outline-none text-sm";
  const labelClass = "block text-[10px] font-black text-gray-400 mb-1 uppercase tracking-widest";
  const sectionClass = "p-4 bg-white rounded-lg shadow-sm border border-gray-200";
  const manualToggleClass = "text-[9px] text-brand-primary font-bold uppercase tracking-tighter cursor-pointer hover:underline mt-1 block text-right";

  const renderLocationInputs = (prefix: 'residence' | 'origin', sectionTitle: string) => {
    const countryVal = formData[`${prefix}Country` as keyof User] as string;
    const stateVal = formData[`${prefix}State` as keyof User] as string;
    const cityVal = formData[`${prefix}City` as keyof User] as string;

    const availableStates = STATES_BY_COUNTRY[countryVal] || [];
    const availableCities = CITIES_BY_STATE[stateVal] || [];

    // Auto-detect if we should show input instead of dropdown
    const showStateInput = manualStates[prefix] || (countryVal && availableStates.length === 0);
    const showCityInput = manualCities[prefix] || showStateInput || (stateVal && availableCities.length === 0);

    return (
        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">{sectionTitle}</h2>
          <div className="space-y-4">
            <div>
              <label className={labelClass}>Country</label>
              <select name={`${prefix}Country`} value={countryVal} onChange={handleChange} className={inputClass}>
                  <option value="">Select Country</option>
                  {COUNTRIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>

            {countryVal && (
              <div>
                <label className={labelClass}>State / Province</label>
                {showStateInput ? (
                    <input 
                      name={`${prefix}State`} 
                      value={stateVal} 
                      onChange={handleChange} 
                      className={inputClass} 
                      placeholder="Type state name" 
                    />
                ) : (
                    <select name={`${prefix}State`} value={stateVal} onChange={handleChange} className={inputClass}>
                        <option value="">Select State</option>
                        {availableStates.map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                )}
                {availableStates.length > 0 && (
                    <span onClick={() => toggleManual('state', prefix)} className={manualToggleClass}>
                        {manualStates[prefix] ? 'Return to List' : "State not listed?"}
                    </span>
                )}
              </div>
            )}

            {(stateVal || showStateInput) && (
              <div>
                <label className={labelClass}>City / Town</label>
                {showCityInput ? (
                    <input 
                      name={`${prefix}City`} 
                      value={cityVal} 
                      onChange={handleChange} 
                      className={inputClass} 
                      placeholder="Type city name" 
                    />
                ) : (
                    <select name={`${prefix}City`} value={cityVal} onChange={handleChange} className={inputClass}>
                        <option value="">Select City</option>
                        {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                )}
                {!showStateInput && availableCities.length > 0 && (
                    <span onClick={() => toggleManual('city', prefix)} className={manualToggleClass}>
                        {manualCities[prefix] ? 'Return to List' : "City not listed?"}
                    </span>
                )}
              </div>
            )}
          </div>
        </div>
    );
  };

  return (
    <div className="w-full h-screen bg-gray-100 flex flex-col">
      <header className="flex items-center justify-between p-4 bg-white border-b border-gray-200 sticky top-0 z-10">
        <h1 className="text-xl font-bold text-brand-dark">Edit Registry</h1>
        <button onClick={onBack} className="p-1 rounded-full text-gray-400 hover:bg-gray-100">
          <CloseIcon className="w-6 h-6" />
        </button>
      </header>

      <main className="flex-1 p-4 space-y-4 overflow-y-auto pb-24">
        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">Identity</h2>
          <div className="space-y-4">
            <div>
              <label className={labelClass}>Name</label>
              <input name="name" type="text" value={formData.name} onChange={handleChange} className={inputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className={labelClass}>Age</label>
                <input name="age" type="number" value={formData.age} onChange={handleChange} className={inputClass} />
              </div>
              <div>
                <label className={labelClass}>Marital Status</label>
                <select name="maritalStatus" value={formData.maritalStatus} onChange={handleChange} className={inputClass}>
                    {Object.values(MaritalStatus).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        </div>

        {renderLocationInputs('residence', 'Current Residence')}
        {renderLocationInputs('origin', 'Heritage & Roots')}

        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">Bio & Lifestyle</h2>
          <div className="space-y-4">
             <div>
              <label className={labelClass}>Occupation</label>
              <input name="occupation" type="text" value={formData.occupation} onChange={handleChange} className={inputClass} />
            </div>
            <div>
              <label className={labelClass}>Registry Bio</label>
              <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className={inputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className={labelClass}>Smoking</label>
                <select name="smoking" value={formData.smoking} onChange={handleChange} className={inputClass}>
                  {Object.values(SmokingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
               <div>
                <label className={labelClass}>Drinking</label>
                <select name="drinking" value={formData.drinking} onChange={handleChange} className={inputClass}>
                  {Object.values(DrinkingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        </div>
      </main>

      <footer className="p-4 bg-white border-t border-gray-200 sticky bottom-0">
        <button onClick={handleSave} className="w-full bg-brand-primary text-white font-bold py-3 rounded-lg hover:bg-brand-secondary transition-colors shadow-lg">
          Save Registry Updates
        </button>
      </footer>
    </div>
  );
};

export default EditProfileScreen;

import React, { useState, useRef } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';
import { PlusIcon } from './icons/PlusIcon';
import { SparklesIcon } from './icons/SparklesIcon';
import { COUNTRIES, STATES_BY_COUNTRY, CITIES_BY_STATE, MANUAL_ENTRY_VAL } from '../services/locationData';

interface OnboardingFlowProps {
  user: User;
  onComplete: (updatedUser: User) => void;
}

const OnboardingFlow: React.FC<OnboardingFlowProps> = ({ user, onComplete }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<User>(user);
  const [isProcessing, setIsProcessing] = useState(false);

  // Explicitly tracked manual text inputs (temp state)
  const [manualInputs, setManualInputs] = useState<Record<string, string>>({});

  const fileInputRef = useRef<HTMLInputElement>(null);
  const totalSteps = 4;

  const handleNext = () => {
    if (step === 1) {
        if (!formData.residenceCountry || !formData.originCountry || !formData.residenceCity || !formData.originCity) {
            alert("Accurate location data is required for matching. Please complete your residence and origin details.");
            return;
        }
    }
    if (step === 4 && formData.profileImageUrls.length === 0) {
        alert("A profile picture is mandatory for verification.");
        return;
    }
    if (step < totalSteps) {
      setStep(step + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      onComplete(formData);
    }
  };

  const handlePrev = () => {
    if (step > 1) {
      setStep(step - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    // Cascading reset logic
    if (name === 'residenceCountry') {
        setFormData(prev => ({ ...prev, residenceCountry: value, residenceState: '', residenceCity: '', country: value }));
        setManualInputs(p => ({ ...p, residenceState: '', residenceCity: '' }));
    } else if (name === 'residenceState') {
        setFormData(prev => ({ ...prev, residenceState: value, residenceCity: '' }));
        setManualInputs(p => ({ ...p, residenceCity: '' }));
    } else if (name === 'originCountry') {
        setFormData(prev => ({ ...prev, originCountry: value, originState: '', originCity: '' }));
        setManualInputs(p => ({ ...p, originState: '', originCity: '' }));
    } else if (name === 'originState') {
        setFormData(prev => ({ ...prev, originState: value, originCity: '' }));
        setManualInputs(p => ({ ...p, originCity: '' }));
    } else if (name === 'residenceCity') {
        setFormData(prev => ({ ...prev, residenceCity: value, city: value }));
    } else {
        setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleManualTextInput = (field: string, value: string) => {
    setManualInputs(p => ({ ...p, [field]: value }));
    setFormData(p => ({ ...p, [field]: value }));
    if (field === 'residenceCity') setFormData(p => ({ ...p, city: value }));
    if (field === 'residenceCountry') setFormData(p => ({ ...p, country: value }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const result = event.target?.result as string;
      if (result) setFormData({ ...formData, profileImageUrls: [result] });
      setIsProcessing(false);
    };
    reader.readAsDataURL(file);
  };

  const inputClass = "w-full p-4 border border-gray-200 rounded-2xl bg-white text-black focus:ring-2 focus:ring-brand-primary focus:border-transparent focus:outline-none shadow-sm transition-all text-sm";
  const labelClass = "block text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest";
  const sectionTitleClass = "text-xs font-black text-brand-primary uppercase tracking-widest border-b pb-2 mb-4 mt-6";

  const renderLocationGroup = (prefix: 'residence' | 'origin', title: string) => {
    const countryField = `${prefix}Country` as keyof User;
    const stateField = `${prefix}State` as keyof User;
    const cityField = `${prefix}City` as keyof User;

    const countryVal = formData[countryField] as string;
    const stateVal = formData[stateField] as string;
    const cityVal = formData[cityField] as string;

    const availableStates = STATES_BY_COUNTRY[countryVal] || [];
    const availableCities = CITIES_BY_STATE[stateVal] || [];

    // Check if we are currently in manual mode for state or city
    const isStateManual = stateVal && availableStates.length > 0 && !availableStates.includes(stateVal);
    const isCityManual = cityVal && availableCities.length > 0 && !availableCities.includes(cityVal);

    // Determine if we should show the text input directly (if no data exists for country/state)
    const forceStateManual = countryVal && availableStates.length === 0;
    const forceCityManual = stateVal && availableCities.length === 0;

    return (
      <div className="space-y-4">
        <h3 className={sectionTitleClass}>{title}</h3>

        {/* Country */}
        <div>
          <label className={labelClass}>Country</label>
          <select name={countryField} value={countryVal} onChange={handleChange} className={inputClass}>
            <option value="">Select Country</option>
            {COUNTRIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>

        {/* State */}
        {countryVal && (
          <div>
            <label className={labelClass}>State / Province</label>
            {forceStateManual ? (
               <input 
                 value={stateVal} 
                 onChange={(e) => handleManualTextInput(stateField, e.target.value)} 
                 className={inputClass} 
                 placeholder="Type your state/province" 
               />
            ) : (
                <>
                    <select 
                      name={stateField} 
                      value={availableStates.includes(stateVal) ? stateVal : (stateVal ? MANUAL_ENTRY_VAL : '')} 
                      onChange={(e) => {
                          if (e.target.value === MANUAL_ENTRY_VAL) {
                            handleManualTextInput(stateField, '');
                          } else {
                            handleChange(e);
                          }
                      }} 
                      className={inputClass}
                    >
                        <option value="">Select State</option>
                        {availableStates.map(s => <option key={s} value={s}>{s}</option>)}
                        <option value={MANUAL_ENTRY_VAL}>Other / Manual Entry...</option>
                    </select>
                    {(isStateManual || stateVal === MANUAL_ENTRY_VAL) && (
                         <input 
                            value={stateVal === MANUAL_ENTRY_VAL ? '' : stateVal} 
                            onChange={(e) => handleManualTextInput(stateField, e.target.value)} 
                            className={`${inputClass} mt-2 border-brand-accent`}
                            placeholder="Enter state name" 
                            autoFocus
                        />
                    )}
                </>
            )}
          </div>
        )}

        {/* City */}
        {stateVal && (
          <div>
            <label className={labelClass}>City / Town</label>
            {forceCityManual ? (
                <input 
                  value={cityVal} 
                  onChange={(e) => handleManualTextInput(cityField, e.target.value)} 
                  className={inputClass} 
                  placeholder="Type your city/town" 
                />
            ) : (
                <>
                    <select 
                      name={cityField} 
                      value={availableCities.includes(cityVal) ? cityVal : (cityVal ? MANUAL_ENTRY_VAL : '')} 
                      onChange={(e) => {
                        if (e.target.value === MANUAL_ENTRY_VAL) {
                          handleManualTextInput(cityField, '');
                        } else {
                          handleChange(e);
                        }
                      }} 
                      className={inputClass}
                    >
                        <option value="">Select City</option>
                        {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
                        <option value={MANUAL_ENTRY_VAL}>Other / Manual Entry...</option>
                    </select>
                    {(isCityManual || cityVal === MANUAL_ENTRY_VAL) && (
                         <input 
                            value={cityVal === MANUAL_ENTRY_VAL ? '' : cityVal} 
                            onChange={(e) => handleManualTextInput(cityField, e.target.value)} 
                            className={`${inputClass} mt-2 border-brand-accent`}
                            placeholder="Enter city/town name" 
                            autoFocus
                        />
                    )}
                </>
            )}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-white flex flex-col p-6 pb-32 relative font-sans">
      <div className="mb-10">
        <div className="flex justify-between items-end mb-3">
            <div>
                <h4 className="text-[10px] font-black text-brand-primary uppercase tracking-[0.2em]">Knot Global Registry</h4>
                <h2 className="text-2xl font-black text-brand-dark">
                  {step === 1 && 'Identity & Roots'}
                  {step === 2 && 'Lifestyle & Values'}
                  {step === 3 && 'Commitment'}
                  {step === 4 && 'First Impressions'}
                </h2>
            </div>
            <span className="text-xs font-bold text-gray-300 uppercase tracking-widest">{step}/{totalSteps}</span>
        </div>
        <div className="w-full h-1.5 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-brand-primary transition-all duration-700 ease-in-out" style={{ width: `${(step / totalSteps) * 100}%` }}></div>
        </div>
      </div>

      <div className="flex-1 animate-slide-in">
        {step === 1 && (
          <div className="space-y-6">
            <div>
              <label className={labelClass}>Full Name</label>
              <input name="name" value={formData.name} onChange={handleChange} className={inputClass} placeholder="Enter your name" />
            </div>
            <div className="grid grid-cols-2 gap-4">
               <div>
                  <label className={labelClass}>Age</label>
                  <input type="number" name="age" value={formData.age} onChange={handleChange} className={inputClass} />
               </div>
               <div>
                  <label className={labelClass}>Occupation</label>
                  <input name="occupation" value={formData.occupation} onChange={handleChange} className={inputClass} placeholder="e.g. Architect" />
               </div>
            </div>

            {renderLocationGroup('residence', 'Current Residence')}
            {renderLocationGroup('origin', 'Heritage & Origin')}

            <div className="pt-4">
                <label className={labelClass}>Marriage-Oriented Bio</label>
                <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className={inputClass} placeholder="What are you looking for in a life partner?" />
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Honesty about your lifestyle ensures a more stable marriage match.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Religion / Faith</label>
                <input name="religion" value={formData.religion} onChange={handleChange} className={inputClass} placeholder="e.g. Christian, Muslim, Secular" />
              </div>
              <div>
                <label className={labelClass}>Cultural / Ethnic Roots</label>
                <input name="culturalBackground" value={formData.culturalBackground} onChange={handleChange} className={inputClass} placeholder="e.g. South Asian, Hispanic" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelClass}>Smoking</label>
                  <select name="smoking" value={formData.smoking} onChange={handleChange} className={inputClass}>
                    {Object.values(SmokingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelClass}>Drinking</label>
                  <select name="drinking" value={formData.drinking} onChange={handleChange} className={inputClass}>
                    {Object.values(DrinkingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Knot matches users based on their marriage timeline and relocation readiness.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Ideal Marriage Timeline</label>
                <select name="marriageTimeline" value={formData.marriageTimeline} onChange={handleChange} className={inputClass}>
                    <option value="ASAP">As soon as I find the one</option>
                    <option value="1-2 years">Within 1-2 years</option>
                    <option value="3+ years">3+ years</option>
                    <option value="Not sure">Not sure yet</option>
                </select>
              </div>
              <div>
                <label className={labelClass}>Future Children</label>
                <select name="childrenPreference" value={formData.childrenPreference} onChange={handleChange} className={inputClass}>
                  {Object.values(ChildrenPreference).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
              <div>
                <label className={labelClass}>Relocation Willingness</label>
                <select name="willingToRelocate" value={formData.willingToRelocate} onChange={handleChange} className={inputClass}>
                  {Object.values(WillingToRelocate).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-8 text-center px-4">
            <div className="animate-fade-in">
                <div className="flex justify-center mb-2">
                    <SparklesIcon className="w-6 h-6 text-brand-accent animate-pulse" />
                </div>
                <h3 className="text-3xl font-serif text-brand-primary mb-2">First Impressions</h3>
                <p className="text-gray-500 text-sm leading-relaxed">Registry members prefer authentic, high-quality portraits.</p>
            </div>
            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
            <div onClick={() => fileInputRef.current?.click()} className="relative inline-block w-full max-w-[280px] aspect-[4/5] mx-auto cursor-pointer group animate-scale-in">
                <div className={`w-full h-full rounded-[2.5rem] border-4 border-dashed ${formData.profileImageUrls.length > 0 ? 'border-brand-primary border-solid' : 'border-gray-200'} overflow-hidden bg-gray-50 flex items-center justify-center shadow-2xl transition-all hover:bg-brand-light active:scale-[0.98]`}>
                    {formData.profileImageUrls.length > 0 ? (
                         <img src={formData.profileImageUrls[0]} className="w-full h-full object-cover animate-fade-in" />
                    ) : (
                        <div className="text-center p-8">
                            {isProcessing ? (
                                <div className="w-12 h-12 border-4 border-brand-primary border-t-transparent rounded-full animate-spin mx-auto"></div>
                            ) : (
                                <>
                                    <div className="w-20 h-20 bg-brand-light rounded-full flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                                        <PlusIcon className="h-10 w-10 text-brand-primary" />
                                    </div>
                                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest leading-relaxed px-4">Tap to upload your registry photo</p>
                                </>
                            )}
                        </div>
                    )}
                </div>
            </div>
          </div>
        )}
      </div>

      <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto p-6 bg-white flex items-center gap-4 z-30 border-t border-gray-50">
        {step > 1 && <button onClick={handlePrev} className="px-8 py-4 rounded-2xl border border-gray-100 text-gray-400 font-bold hover:bg-gray-50 transition-all">Back</button>}
        <button onClick={handleNext} className="flex-1 bg-brand-primary text-white font-black py-4 rounded-2xl text-lg hover:bg-brand-secondary transition-all shadow-xl shadow-brand-primary/30 active:scale-95">
            {step === totalSteps ? 'Activate Registry' : 'Continue'}
        </button>
      </div>

      <style>{`
        .animate-slide-in { animation: slideIn 0.5s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        .animate-scale-in { animation: scaleIn 0.6s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        @keyframes slideIn { from { opacity: 0; transform: translateX(20px); } to { opacity: 1; transform: translateX(0); } }
        @keyframes scaleIn { from { opacity: 0; transform: scale(0.9); } to { opacity: 1; transform: scale(1); } }
      `}</style>
    </div>
  );
};

export default OnboardingFlow;

import React, { useState } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';
import { CloseIcon } from './icons/CloseIcon';
import { COUNTRIES, STATES_BY_COUNTRY, CITIES_BY_STATE, MANUAL_ENTRY_VAL } from '../services/locationData';

interface EditProfileScreenProps {
  user: User;
  onBack: () => void;
  onSave: (updatedUser: User) => void;
}

const EditProfileScreen: React.FC<EditProfileScreenProps> = ({ user, onBack, onSave }) => {
  const [formData, setFormData] = useState<User>(user);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    if (name === 'residenceCountry') {
        setFormData(prev => ({ ...prev, residenceCountry: value, residenceState: '', residenceCity: '', country: value }));
    } else if (name === 'residenceState') {
        setFormData(prev => ({ ...prev, residenceState: value, residenceCity: '' }));
    } else if (name === 'originCountry') {
        setFormData(prev => ({ ...prev, originCountry: value, originState: '', originCity: '' }));
    } else if (name === 'originState') {
        setFormData(prev => ({ ...prev, originState: value, originCity: '' }));
    } else if (name === 'residenceCity') {
        setFormData(prev => ({ ...prev, residenceCity: value, city: value }));
    } else {
        setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleManualTextInput = (field: string, value: string) => {
    setFormData(p => ({ ...p, [field]: value }));
    if (field === 'residenceCity') setFormData(p => ({ ...p, city: value }));
  };

  const handleSave = () => {
    onSave(formData);
  };

  const inputClass = "w-full p-2.5 border border-gray-300 rounded-lg bg-gray-50 text-black focus:bg-white focus:ring-2 focus:ring-brand-secondary focus:outline-none text-sm";
  const labelClass = "block text-[10px] font-black text-gray-400 mb-1 uppercase tracking-widest";
  const sectionClass = "p-4 bg-white rounded-lg shadow-sm border border-gray-200";

  const renderLocationInputs = (prefix: 'residence' | 'origin', sectionTitle: string) => {
    const countryField = `${prefix}Country` as keyof User;
    const stateField = `${prefix}State` as keyof User;
    const cityField = `${prefix}City` as keyof User;

    const countryVal = formData[countryField] as string;
    const stateVal = formData[stateField] as string;
    const cityVal = formData[cityField] as string;

    const availableStates = STATES_BY_COUNTRY[countryVal] || [];
    const availableCities = CITIES_BY_STATE[stateVal] || [];

    const isStateManual = stateVal && availableStates.length > 0 && !availableStates.includes(stateVal);
    const isCityManual = cityVal && availableCities.length > 0 && !availableCities.includes(cityVal);

    const forceStateManual = countryVal && availableStates.length === 0;
    const forceCityManual = stateVal && availableCities.length === 0;

    return (
        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">{sectionTitle}</h2>
          <div className="space-y-4">
            <div>
              <label className={labelClass}>Country</label>
              <select name={countryField} value={countryVal} onChange={handleChange} className={inputClass}>
                  <option value="">Select Country</option>
                  {COUNTRIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>

            {countryVal && (
              <div>
                <label className={labelClass}>State / Province</label>
                {forceStateManual ? (
                    <input 
                      value={stateVal} 
                      onChange={(e) => handleManualTextInput(stateField, e.target.value)} 
                      className={inputClass} 
                      placeholder="Type state name" 
                    />
                ) : (
                    <>
                        <select 
                            name={stateField} 
                            value={availableStates.includes(stateVal) ? stateVal : (stateVal ? MANUAL_ENTRY_VAL : '')} 
                            onChange={(e) => {
                                if (e.target.value === MANUAL_ENTRY_VAL) {
                                    handleManualTextInput(stateField, '');
                                } else {
                                    handleChange(e);
                                }
                            }} 
                            className={inputClass}
                        >
                            <option value="">Select State</option>
                            {availableStates.map(s => <option key={s} value={s}>{s}</option>)}
                            <option value={MANUAL_ENTRY_VAL}>Other / Manual...</option>
                        </select>
                        {(isStateManual || stateVal === MANUAL_ENTRY_VAL) && (
                            <input 
                                value={stateVal === MANUAL_ENTRY_VAL ? '' : stateVal} 
                                onChange={(e) => handleManualTextInput(stateField, e.target.value)} 
                                className={`${inputClass} mt-2 border-brand-accent`}
                                placeholder="Enter state name" 
                            />
                        )}
                    </>
                )}
              </div>
            )}

            {(stateVal || forceStateManual) && (
              <div>
                <label className={labelClass}>City / Town</label>
                {forceCityManual ? (
                    <input 
                      value={cityVal} 
                      onChange={(e) => handleManualTextInput(cityField, e.target.value)} 
                      className={inputClass} 
                      placeholder="Type city name" 
                    />
                ) : (
                    <>
                        <select 
                            name={cityField} 
                            value={availableCities.includes(cityVal) ? cityVal : (cityVal ? MANUAL_ENTRY_VAL : '')} 
                            onChange={(e) => {
                                if (e.target.value === MANUAL_ENTRY_VAL) {
                                    handleManualTextInput(cityField, '');
                                } else {
                                    handleChange(e);
                                }
                            }} 
                            className={inputClass}
                        >
                            <option value="">Select City</option>
                            {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
                            <option value={MANUAL_ENTRY_VAL}>Other / Manual...</option>
                        </select>
                        {(isCityManual || cityVal === MANUAL_ENTRY_VAL) && (
                            <input 
                                value={cityVal === MANUAL_ENTRY_VAL ? '' : cityVal} 
                                onChange={(e) => handleManualTextInput(cityField, e.target.value)} 
                                className={`${inputClass} mt-2 border-brand-accent`}
                                placeholder="Enter city name" 
                            />
                        )}
                    </>
                )}
              </div>
            )}
          </div>
        </div>
    );
  };

  return (
    <div className="w-full h-screen bg-gray-100 flex flex-col">
      <header className="flex items-center justify-between p-4 bg-white border-b border-gray-200 sticky top-0 z-10">
        <h1 className="text-xl font-bold text-brand-dark">Edit Registry</h1>
        <button onClick={onBack} className="p-1 rounded-full text-gray-400 hover:bg-gray-100">
          <CloseIcon className="w-6 h-6" />
        </button>
      </header>

      <main className="flex-1 p-4 space-y-4 overflow-y-auto pb-24">
        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">Identity</h2>
          <div className="space-y-4">
            <div>
              <label className={labelClass}>Name</label>
              <input name="name" type="text" value={formData.name} onChange={handleChange} className={inputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className={labelClass}>Age</label>
                <input name="age" type="number" value={formData.age} onChange={handleChange} className={inputClass} />
              </div>
              <div>
                <label className={labelClass}>Marital Status</label>
                <select name="maritalStatus" value={formData.maritalStatus} onChange={handleChange} className={inputClass}>
                    {Object.values(MaritalStatus).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        </div>

        {renderLocationInputs('residence', 'Current Residence')}
        {renderLocationInputs('origin', 'Heritage & Roots')}

        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">Bio & Lifestyle</h2>
          <div className="space-y-4">
             <div>
              <label className={labelClass}>Occupation</label>
              <input name="occupation" type="text" value={formData.occupation} onChange={handleChange} className={inputClass} />
            </div>
            <div>
              <label className={labelClass}>Registry Bio</label>
              <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className={inputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className={labelClass}>Smoking</label>
                <select name="smoking" value={formData.smoking} onChange={handleChange} className={inputClass}>
                  {Object.values(SmokingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
               <div>
                <label className={labelClass}>Drinking</label>
                <select name="drinking" value={formData.drinking} onChange={handleChange} className={inputClass}>
                  {Object.values(DrinkingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        </div>
      </main>

      <footer className="p-4 bg-white border-t border-gray-200 sticky bottom-0">
        <button onClick={handleSave} className="w-full bg-brand-primary text-white font-bold py-3 rounded-lg hover:bg-brand-secondary transition-colors shadow-lg">
          Save Registry Updates
        </button>
      </footer>
    </div>
  );
};

export default EditProfileScreen;

import React, { useState, useRef } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';
import { PlusIcon } from './icons/PlusIcon';
import { SparklesIcon } from './icons/SparklesIcon';
import { COUNTRIES, STATES_BY_COUNTRY, CITIES_BY_STATE, MANUAL_ENTRY_VAL } from '../services/locationData';

interface OnboardingFlowProps {
  user: User;
  onComplete: (updatedUser: User) => void;
}

const OnboardingFlow: React.FC<OnboardingFlowProps> = ({ user, onComplete }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<User>(user);
  const [isProcessing, setIsProcessing] = useState(false);

  // Explicitly tracked manual text inputs (temp state)
  const [manualInputs, setManualInputs] = useState<Record<string, string>>({});

  const fileInputRef = useRef<HTMLInputElement>(null);
  const totalSteps = 4;

  const handleNext = () => {
    if (step === 1) {
        if (!formData.residenceCountry || !formData.originCountry || !formData.residenceCity || !formData.originCity) {
            alert("Accurate location data is required for matching. Please complete your residence and origin details.");
            return;
        }
    }
    if (step === 4 && formData.profileImageUrls.length === 0) {
        alert("A profile picture is mandatory for verification.");
        return;
    }
    if (step < totalSteps) {
      setStep(step + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      onComplete(formData);
    }
  };

  const handlePrev = () => {
    if (step > 1) {
      setStep(step - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    // Cascading reset logic
    if (name === 'residenceCountry') {
        setFormData(prev => ({ ...prev, residenceCountry: value, residenceState: '', residenceCity: '', country: value }));
        setManualInputs(p => ({ ...p, residenceState: '', residenceCity: '' }));
    } else if (name === 'residenceState') {
        setFormData(prev => ({ ...prev, residenceState: value, residenceCity: '' }));
        setManualInputs(p => ({ ...p, residenceCity: '' }));
    } else if (name === 'originCountry') {
        setFormData(prev => ({ ...prev, originCountry: value, originState: '', originCity: '' }));
        setManualInputs(p => ({ ...p, originState: '', originCity: '' }));
    } else if (name === 'originState') {
        setFormData(prev => ({ ...prev, originState: value, originCity: '' }));
        setManualInputs(p => ({ ...p, originCity: '' }));
    } else if (name === 'residenceCity') {
        setFormData(prev => ({ ...prev, residenceCity: value, city: value }));
    } else {
        setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleManualTextInput = (field: string, value: string) => {
    setManualInputs(p => ({ ...p, [field]: value }));
    setFormData(p => ({ ...p, [field]: value }));
    if (field === 'residenceCity') setFormData(p => ({ ...p, city: value }));
    if (field === 'residenceCountry') setFormData(p => ({ ...p, country: value }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const result = event.target?.result as string;
      if (result) setFormData({ ...formData, profileImageUrls: [result] });
      setIsProcessing(false);
    };
    reader.readAsDataURL(file);
  };

  const inputClass = "w-full p-4 border border-gray-200 rounded-2xl bg-white text-black focus:ring-2 focus:ring-brand-primary focus:border-transparent focus:outline-none shadow-sm transition-all text-sm";
  const labelClass = "block text-[10px] font-black text-gray-400 mb-2 uppercase tracking-widest";
  const sectionTitleClass = "text-xs font-black text-brand-primary uppercase tracking-widest border-b pb-2 mb-4 mt-6";

  const renderLocationGroup = (prefix: 'residence' | 'origin', title: string) => {
    const countryField = `${prefix}Country` as keyof User;
    const stateField = `${prefix}State` as keyof User;
    const cityField = `${prefix}City` as keyof User;

    const countryVal = formData[countryField] as string;
    const stateVal = formData[stateField] as string;
    const cityVal = formData[cityField] as string;

    const availableStates = STATES_BY_COUNTRY[countryVal] || [];
    const availableCities = CITIES_BY_STATE[stateVal] || [];

    // Check if we are currently in manual mode for state or city
    const isStateManual = stateVal && availableStates.length > 0 && !availableStates.includes(stateVal);
    const isCityManual = cityVal && availableCities.length > 0 && !availableCities.includes(cityVal);

    // Determine if we should show the text input directly (if no data exists for country/state)
    const forceStateManual = countryVal && availableStates.length === 0;
    const forceCityManual = stateVal && availableCities.length === 0;

    return (
      <div className="space-y-4">
        <h3 className={sectionTitleClass}>{title}</h3>

        {/* Country */}
        <div>
          <label className={labelClass}>Country</label>
          <select name={countryField} value={countryVal} onChange={handleChange} className={inputClass}>
            <option value="">Select Country</option>
            {COUNTRIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>

        {/* State */}
        {countryVal && (
          <div>
            <label className={labelClass}>State / Province</label>
            {forceStateManual ? (
               <input 
                 value={stateVal} 
                 onChange={(e) => handleManualTextInput(stateField, e.target.value)} 
                 className={inputClass} 
                 placeholder="Type your state/province" 
               />
            ) : (
                <>
                    <select 
                      name={stateField} 
                      value={availableStates.includes(stateVal) ? stateVal : (stateVal ? MANUAL_ENTRY_VAL : '')} 
                      onChange={(e) => {
                          if (e.target.value === MANUAL_ENTRY_VAL) {
                            handleManualTextInput(stateField, '');
                          } else {
                            handleChange(e);
                          }
                      }} 
                      className={inputClass}
                    >
                        <option value="">Select State</option>
                        {availableStates.map(s => <option key={s} value={s}>{s}</option>)}
                        <option value={MANUAL_ENTRY_VAL}>Other / Manual Entry...</option>
                    </select>
                    {(isStateManual || stateVal === MANUAL_ENTRY_VAL) && (
                         <input 
                            value={stateVal === MANUAL_ENTRY_VAL ? '' : stateVal} 
                            onChange={(e) => handleManualTextInput(stateField, e.target.value)} 
                            className={`${inputClass} mt-2 border-brand-accent`}
                            placeholder="Enter state name" 
                            autoFocus
                        />
                    )}
                </>
            )}
          </div>
        )}

        {/* City */}
        {(stateVal || forceStateManual) && (
          <div>
            <label className={labelClass}>City / Town</label>
            {forceCityManual ? (
                <input 
                  value={cityVal} 
                  onChange={(e) => handleManualTextInput(cityField, e.target.value)} 
                  className={inputClass} 
                  placeholder="Type your city/town" 
                />
            ) : (
                <>
                    <select 
                      name={cityField} 
                      value={availableCities.includes(cityVal) ? cityVal : (cityVal ? MANUAL_ENTRY_VAL : '')} 
                      onChange={(e) => {
                        if (e.target.value === MANUAL_ENTRY_VAL) {
                          handleManualTextInput(cityField, '');
                        } else {
                          handleChange(e);
                        }
                      }} 
                      className={inputClass}
                    >
                        <option value="">Select City</option>
                        {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
                        <option value={MANUAL_ENTRY_VAL}>Other / Manual Entry...</option>
                    </select>
                    {(isCityManual || cityVal === MANUAL_ENTRY_VAL) && (
                         <input 
                            value={cityVal === MANUAL_ENTRY_VAL ? '' : cityVal} 
                            onChange={(e) => handleManualTextInput(cityField, e.target.value)} 
                            className={`${inputClass} mt-2 border-brand-accent`}
                            placeholder="Enter city/town name" 
                            autoFocus
                        />
                    )}
                </>
            )}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-white flex flex-col p-6 pb-32 relative font-sans">
      <div className="mb-10">
        <div className="flex justify-between items-end mb-3">
            <div>
                <h4 className="text-[10px] font-black text-brand-primary uppercase tracking-[0.2em]">Knot Global Registry</h4>
                <h2 className="text-2xl font-black text-brand-dark">
                  {step === 1 && 'Identity & Roots'}
                  {step === 2 && 'Lifestyle & Values'}
                  {step === 3 && 'Commitment'}
                  {step === 4 && 'First Impressions'}
                </h2>
            </div>
            <span className="text-xs font-bold text-gray-300 uppercase tracking-widest">{step}/{totalSteps}</span>
        </div>
        <div className="w-full h-1.5 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-brand-primary transition-all duration-700 ease-in-out" style={{ width: `${(step / totalSteps) * 100}%` }}></div>
        </div>
      </div>

      <div className="flex-1 animate-slide-in">
        {step === 1 && (
          <div className="space-y-6">
            <div>
              <label className={labelClass}>Full Name</label>
              <input name="name" value={formData.name} onChange={handleChange} className={inputClass} placeholder="Enter your name" />
            </div>
            <div className="grid grid-cols-2 gap-4">
               <div>
                  <label className={labelClass}>Age</label>
                  <input type="number" name="age" value={formData.age} onChange={handleChange} className={inputClass} />
               </div>
               <div>
                  <label className={labelClass}>Occupation</label>
                  <input name="occupation" value={formData.occupation} onChange={handleChange} className={inputClass} placeholder="e.g. Architect" />
               </div>
            </div>

            {renderLocationGroup('residence', 'Current Residence')}

            <div className="space-y-4">
                {renderLocationGroup('origin', 'Heritage & Origin')}
                <div className="animate-fade-in">
                    <label className={labelClass}>Cultural / Ethnic Identity</label>
                    <input 
                        name="culturalBackground" 
                        value={formData.culturalBackground} 
                        onChange={handleChange} 
                        className={inputClass} 
                        placeholder="e.g. Yoruba, Punjabi, Ashkenazi, etc." 
                    />
                </div>
            </div>

            <div className="pt-4">
                <label className={labelClass}>Marriage-Oriented Bio</label>
                <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className={inputClass} placeholder="What are you looking for in a life partner?" />
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Honesty about your lifestyle ensures a more stable marriage match.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Religion / Faith</label>
                <input name="religion" value={formData.religion} onChange={handleChange} className={inputClass} placeholder="e.g. Christian, Muslim, Secular" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className={labelClass}>Smoking</label>
                  <select name="smoking" value={formData.smoking} onChange={handleChange} className={inputClass}>
                    {Object.values(SmokingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
                <div>
                  <label className={labelClass}>Drinking</label>
                  <select name="drinking" value={formData.drinking} onChange={handleChange} className={inputClass}>
                    {Object.values(DrinkingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-8">
            <p className="text-gray-500 text-sm leading-relaxed">Knot matches users based on their marriage timeline and relocation readiness.</p>
            <div className="space-y-5">
              <div>
                <label className={labelClass}>Ideal Marriage Timeline</label>
                <select name="marriageTimeline" value={formData.marriageTimeline} onChange={handleChange} className={inputClass}>
                    <option value="ASAP">As soon as I find the one</option>
                    <option value="1-2 years">Within 1-2 years</option>
                    <option value="3+ years">3+ years</option>
                    <option value="Not sure">Not sure yet</option>
                </select>
              </div>
              <div>
                <label className={labelClass}>Future Children</label>
                <select name="childrenPreference" value={formData.childrenPreference} onChange={handleChange} className={inputClass}>
                  {Object.values(ChildrenPreference).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
              <div>
                <label className={labelClass}>Relocation Willingness</label>
                <select name="willingToRelocate" value={formData.willingToRelocate} onChange={handleChange} className={inputClass}>
                  {Object.values(WillingToRelocate).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-8 text-center px-4">
            <div className="animate-fade-in">
                <div className="flex justify-center mb-2">
                    <SparklesIcon className="w-6 h-6 text-brand-accent animate-pulse" />
                </div>
                <h3 className="text-3xl font-serif text-brand-primary mb-2">First Impressions</h3>
                <p className="text-gray-500 text-sm leading-relaxed">Registry members prefer authentic, high-quality portraits.</p>
            </div>
            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
            <div onClick={() => fileInputRef.current?.click()} className="relative inline-block w-full max-w-[280px] aspect-[4/5] mx-auto cursor-pointer group animate-scale-in">
                <div className={`w-full h-full rounded-[2.5rem] border-4 border-dashed ${formData.profileImageUrls.length > 0 ? 'border-brand-primary border-solid' : 'border-gray-200'} overflow-hidden bg-gray-50 flex items-center justify-center shadow-2xl transition-all hover:bg-brand-light active:scale-[0.98]`}>
                    {formData.profileImageUrls.length > 0 ? (
                         <img src={formData.profileImageUrls[0]} className="w-full h-full object-cover animate-fade-in" />
                    ) : (
                        <div className="text-center p-8">
                            {isProcessing ? (
                                <div className="w-12 h-12 border-4 border-brand-primary border-t-transparent rounded-full animate-spin mx-auto"></div>
                            ) : (
                                <>
                                    <div className="w-20 h-20 bg-brand-light rounded-full flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                                        <PlusIcon className="h-10 w-10 text-brand-primary" />
                                    </div>
                                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest leading-relaxed px-4">Tap to upload your registry photo</p>
                                </>
                            )}
                        </div>
                    )}
                </div>
            </div>
          </div>
        )}
      </div>

      <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto p-6 bg-white flex items-center gap-4 z-30 border-t border-gray-50">
        {step > 1 && <button onClick={handlePrev} className="px-8 py-4 rounded-2xl border border-gray-100 text-gray-400 font-bold hover:bg-gray-50 transition-all">Back</button>}
        <button onClick={handleNext} className="flex-1 bg-brand-primary text-white font-black py-4 rounded-2xl text-lg hover:bg-brand-secondary transition-all shadow-xl shadow-brand-primary/30 active:scale-95">
            {step === totalSteps ? 'Activate Registry' : 'Continue'}
        </button>
      </div>

      <style>{`
        .animate-slide-in { animation: slideIn 0.5s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        .animate-scale-in { animation: scaleIn 0.6s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }
        @keyframes slideIn { from { opacity: 0; transform: translateX(20px); } to { opacity: 1; transform: translateX(0); } }
        @keyframes scaleIn { from { opacity: 0; transform: scale(0.9); } to { opacity: 1; transform: scale(1); } }
      `}</style>
    </div>
  );
};

export default OnboardingFlow;

import React, { useState } from 'react';
import { User, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';
import { CloseIcon } from './icons/CloseIcon';
import { COUNTRIES, STATES_BY_COUNTRY, CITIES_BY_STATE, MANUAL_ENTRY_VAL } from '../services/locationData';

interface EditProfileScreenProps {
  user: User;
  onBack: () => void;
  onSave: (updatedUser: User) => void;
}

const EditProfileScreen: React.FC<EditProfileScreenProps> = ({ user, onBack, onSave }) => {
  const [formData, setFormData] = useState<User>(user);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    if (name === 'residenceCountry') {
        setFormData(prev => ({ ...prev, residenceCountry: value, residenceState: '', residenceCity: '', country: value }));
    } else if (name === 'residenceState') {
        setFormData(prev => ({ ...prev, residenceState: value, residenceCity: '' }));
    } else if (name === 'originCountry') {
        setFormData(prev => ({ ...prev, originCountry: value, originState: '', originCity: '' }));
    } else if (name === 'originState') {
        setFormData(prev => ({ ...prev, originState: value, originCity: '' }));
    } else if (name === 'residenceCity') {
        setFormData(prev => ({ ...prev, residenceCity: value, city: value }));
    } else {
        setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleManualTextInput = (field: string, value: string) => {
    setFormData(p => ({ ...p, [field]: value }));
    if (field === 'residenceCity') setFormData(p => ({ ...p, city: value }));
  };

  const handleSave = () => {
    onSave(formData);
  };

  const inputClass = "w-full p-2.5 border border-gray-300 rounded-lg bg-gray-50 text-black focus:bg-white focus:ring-2 focus:ring-brand-secondary focus:outline-none text-sm";
  const labelClass = "block text-[10px] font-black text-gray-400 mb-1 uppercase tracking-widest";
  const sectionClass = "p-4 bg-white rounded-lg shadow-sm border border-gray-200";

  const renderLocationInputs = (prefix: 'residence' | 'origin', sectionTitle: string) => {
    const countryField = `${prefix}Country` as keyof User;
    const stateField = `${prefix}State` as keyof User;
    const cityField = `${prefix}City` as keyof User;

    const countryVal = formData[countryField] as string;
    const stateVal = formData[stateField] as string;
    const cityVal = formData[cityField] as string;

    const availableStates = STATES_BY_COUNTRY[countryVal] || [];
    const availableCities = CITIES_BY_STATE[stateVal] || [];

    const isStateManual = stateVal && availableStates.length > 0 && !availableStates.includes(stateVal);
    const isCityManual = cityVal && availableCities.length > 0 && !availableCities.includes(cityVal);

    const forceStateManual = countryVal && availableStates.length === 0;
    const forceCityManual = stateVal && availableCities.length === 0;

    return (
        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">{sectionTitle}</h2>
          <div className="space-y-4">
            <div>
              <label className={labelClass}>Country</label>
              <select name={countryField} value={countryVal} onChange={handleChange} className={inputClass}>
                  <option value="">Select Country</option>
                  {COUNTRIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>

            {countryVal && (
              <div>
                <label className={labelClass}>State / Province</label>
                {forceStateManual ? (
                    <input 
                      value={stateVal} 
                      onChange={(e) => handleManualTextInput(stateField, e.target.value)} 
                      className={inputClass} 
                      placeholder="Type state name" 
                    />
                ) : (
                    <>
                        <select 
                            name={stateField} 
                            value={availableStates.includes(stateVal) ? stateVal : (stateVal ? MANUAL_ENTRY_VAL : '')} 
                            onChange={(e) => {
                                if (e.target.value === MANUAL_ENTRY_VAL) {
                                    handleManualTextInput(stateField, '');
                                } else {
                                    handleChange(e);
                                }
                            }} 
                            className={inputClass}
                        >
                            <option value="">Select State</option>
                            {availableStates.map(s => <option key={s} value={s}>{s}</option>)}
                            <option value={MANUAL_ENTRY_VAL}>Other / Manual...</option>
                        </select>
                        {(isStateManual || stateVal === MANUAL_ENTRY_VAL) && (
                            <input 
                                value={stateVal === MANUAL_ENTRY_VAL ? '' : stateVal} 
                                onChange={(e) => handleManualTextInput(stateField, e.target.value)} 
                                className={`${inputClass} mt-2 border-brand-accent`}
                                placeholder="Enter state name" 
                            />
                        )}
                    </>
                )}
              </div>
            )}

            {(stateVal || forceStateManual) && (
              <div>
                <label className={labelClass}>City / Town</label>
                {forceCityManual ? (
                    <input 
                      value={cityVal} 
                      onChange={(e) => handleManualTextInput(cityField, e.target.value)} 
                      className={inputClass} 
                      placeholder="Type city name" 
                    />
                ) : (
                    <>
                        <select 
                            name={cityField} 
                            value={availableCities.includes(cityVal) ? cityVal : (cityVal ? MANUAL_ENTRY_VAL : '')} 
                            onChange={(e) => {
                                if (e.target.value === MANUAL_ENTRY_VAL) {
                                    handleManualTextInput(cityField, '');
                                } else {
                                    handleChange(e);
                                }
                            }} 
                            className={inputClass}
                        >
                            <option value="">Select City</option>
                            {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
                            <option value={MANUAL_ENTRY_VAL}>Other / Manual...</option>
                        </select>
                        {(isCityManual || cityVal === MANUAL_ENTRY_VAL) && (
                            <input 
                                value={cityVal === MANUAL_ENTRY_VAL ? '' : cityVal} 
                                onChange={(e) => handleManualTextInput(cityField, e.target.value)} 
                                className={`${inputClass} mt-2 border-brand-accent`}
                                placeholder="Enter city name" 
                            />
                        )}
                    </>
                )}
              </div>
            )}

            {prefix === 'origin' && (
                <div className="pt-2 animate-fade-in">
                    <label className={labelClass}>Cultural / Ethnic Identity</label>
                    <input 
                        name="culturalBackground" 
                        value={formData.culturalBackground} 
                        onChange={handleChange} 
                        className={inputClass} 
                        placeholder="e.g. Yoruba, Punjabi, Ashkenazi, etc." 
                    />
                </div>
            )}
          </div>
        </div>
    );
  };

  return (
    <div className="w-full h-screen bg-gray-100 flex flex-col">
      <header className="flex items-center justify-between p-4 bg-white border-b border-gray-200 sticky top-0 z-10">
        <h1 className="text-xl font-bold text-brand-dark">Edit Registry</h1>
        <button onClick={onBack} className="p-1 rounded-full text-gray-400 hover:bg-gray-100">
          <CloseIcon className="w-6 h-6" />
        </button>
      </header>

      <main className="flex-1 p-4 space-y-4 overflow-y-auto pb-24">
        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">Identity</h2>
          <div className="space-y-4">
            <div>
              <label className={labelClass}>Name</label>
              <input name="name" type="text" value={formData.name} onChange={handleChange} className={inputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className={labelClass}>Age</label>
                <input name="age" type="number" value={formData.age} onChange={handleChange} className={inputClass} />
              </div>
              <div>
                <label className={labelClass}>Marital Status</label>
                <select name="maritalStatus" value={formData.maritalStatus} onChange={handleChange} className={inputClass}>
                    {Object.values(MaritalStatus).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        </div>

        {renderLocationInputs('residence', 'Current Residence')}
        {renderLocationInputs('origin', 'Heritage & Roots')}

        <div className={sectionClass}>
          <h2 className="text-sm font-black mb-4 text-brand-primary uppercase tracking-widest border-b pb-1">Bio & Lifestyle</h2>
          <div className="space-y-4">
             <div>
              <label className={labelClass}>Occupation</label>
              <input name="occupation" type="text" value={formData.occupation} onChange={handleChange} className={inputClass} />
            </div>
            <div>
              <label className={labelClass}>Registry Bio</label>
              <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className={inputClass} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className={labelClass}>Smoking</label>
                <select name="smoking" value={formData.smoking} onChange={handleChange} className={inputClass}>
                  {Object.values(SmokingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
               <div>
                <label className={labelClass}>Drinking</label>
                <select name="drinking" value={formData.drinking} onChange={handleChange} className={inputClass}>
                  {Object.values(DrinkingHabits).map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>
          </div>
        </div>
      </main>

      <footer className="p-4 bg-white border-t border-gray-200 sticky bottom-0">
        <button onClick={handleSave} className="w-full bg-brand-primary text-white font-bold py-3 rounded-lg hover:bg-brand-secondary transition-colors shadow-lg">
          Save Registry Updates
        </button>
      </footer>
    </div>
  );
};

export default EditProfileScreen;

