// AI ACTIVATION STATUS: Set to true only after production testing is complete
const STAGING_MODE_ACTIVE = true; 

async function callGeminiWithRetry(
  ai: any, 
  params: any, 
  retries = 3, 
  delay = 1500
): Promise<GenerateContentResponse> {
  try {
    return await ai.models.generateContent(params);
  } catch (error: any) {
    const isRetryable = error?.status === 'UNKNOWN' || error?.code === 500 || error?.code === 503 || error?.code === 429;
    if (retries > 0 && isRetryable) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return callGeminiWithRetry(ai, params, retries - 1, delay * 2);
    }
    throw error;
  }
}

export const getCompatibilityInsight = async (user: User, match: Match): Promise<{ score: number, insight: string }> => {
    // BYPASS FOR TESTING/PRE-PRODUCTION
    if (STAGING_MODE_ACTIVE || !process.env.API_KEY) {
        const mockScores = [88, 92, 79, 84, 95];
        const mockInsights = [
            "Your shared values in heritage and commitment readiness create a strong foundation for a marriage-oriented connection.",
            "Both profiles show a deep commitment to family growth and professional stability, suggesting high long-term compatibility.",
            "Mutual interest in cultural identity and shared faith provides a meaningful basis for starting a life together.",
            "High alignment found in lifestyle choices and relocation willingness, which are critical for serious matchmaking.",
            "Your registry data points to a rare synchronicity in marriage timelines and future family goals."
        ];
        const index = Math.abs(match.id.length % mockInsights.length);
        return { 
            score: mockScores[index], 
            insight: mockInsights[index] 
        };
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-pro-preview';

    const prompt = `
        Act as a professional marriage matchmaker. Analyze compatibility.
        User: ${user.name}, Bio: ${user.bio}, Values: ${user.personalValues.join(', ')}
        Match: ${match.name}, Bio: ${match.bio}, Values: ${match.personalValues.join(', ')}
        Return JSON format: { "score": number, "insight": string }
    `;

    try {
        const response = await callGeminiWithRetry(ai, {
            model: model,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.INTEGER },
                        insight: { type: Type.STRING }
                    },
                    required: ["score", "insight"]
                }
            }
        });

        return JSON.parse(response.text || '{"score": 75, "insight": "Stable connection predicted."}');
    } catch (error) {
        return { score: 75, insight: "Shared values in family and growth make you a strong potential match." };
    }
};

