const STAGING_MODE_ACTIVE = false; 

async function callGeminiWithRetry(
  ai: any, 
  params: any, 
  retries = 3, 
  delay = 1500
): Promise<GenerateContentResponse> {
  try {
    return await ai.models.generateContent(params);
  } catch (error: any) {
    const isRetryable = error?.status === 'UNKNOWN' || error?.code === 500 || error?.code === 503 || error?.code === 429;
    if (retries > 0 && isRetryable) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return callGeminiWithRetry(ai, params, retries - 1, delay * 2);
    }
    throw error;
  }
}

export const getCompatibilityInsight = async (user: User, match: Match): Promise<{ score: number, insight: string }> => {
    if (STAGING_MODE_ACTIVE || !process.env.API_KEY) {
        const mockInsights = [
            "Your shared Nigerian/Yoruba heritage and mutual commitment to a 1-2 year marriage timeline create an exceptional foundation.",
            "High alignment found in your professional stability and shared desire for children. Your relocation values are compatible.",
            "Both registries indicate a deep respect for family traditions and spiritual growth, suggesting strong long-term harmony.",
            "Your career goals complement their path perfectly. Shared values: Honesty and Ambition.",
            "Analysis shows synchronicity in your 'Marriage Expectations'. Both seek a life partner based on mutual respect."
        ];
        const score = 85 + (match.name.length % 12);
        const insight = mockInsights[match.name.length % mockInsights.length];
        return { score, insight };
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-pro-preview';

    const prompt = `
        Act as a professional marriage matchmaker. Analyze compatibility.
        User: ${user.name}, Bio: ${user.bio}, Values: ${user.personalValues.join(', ')}
        Match: ${match.name}, Bio: ${match.bio}, Values: ${match.personalValues.join(', ')}
        Return JSON format: { "score": number, "insight": string }
    `;

    try {
        const response = await callGeminiWithRetry(ai, {
            model: model,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.INTEGER },
                        insight: { type: Type.STRING }
                    },
                    required: ["score", "insight"]
                }
            }
        });

        return JSON.parse(response.text || '{"score": 75, "insight": "Stable connection predicted."}');
    } catch (error) {
        return { score: 75, insight: "Shared values in family and growth make you a strong potential match." };
    }
};

