import { GoogleGenAI, Type } from "@google/genai";

export interface GlobalEvent {
    id: string;
    message: string;
    location: string;
    timestamp: Date;
}

// AI ACTIVATION STATUS: Now ACTIVE
const STAGING_MODE_ACTIVE = false;

const CACHE_KEY = 'knot_global_activity_cache';
const CACHE_EXPIRY = 1000 * 60 * 15; // 15 minutes

const FALLBACK_EVENTS: GlobalEvent[] = [
    { id: 'f1', message: "New marriage-minded match found", location: "London, UK", timestamp: new Date() },
    { id: 'f2', message: "User profile verified via Biometrics", location: "Toronto, CA", timestamp: new Date() },
    { id: 'f3', message: "Marriage timeline aligned for new couple", location: "Lagos, NG", timestamp: new Date() }
];

export const fetchRecentGlobalActivity = async (): Promise<GlobalEvent[]> => {
    if (STAGING_MODE_ACTIVE) {
        return FALLBACK_EVENTS;
    }

    const cached = localStorage.getItem(CACHE_KEY);
    if (cached) {
        const { timestamp, data } = JSON.parse(cached);
        if (Date.now() - timestamp < CACHE_EXPIRY) {
            return data.map((d: any) => ({ ...d, timestamp: new Date(d.timestamp) }));
        }
    }

    if (!process.env.API_KEY) return FALLBACK_EVENTS;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-flash-preview';

    const prompt = `
        Generate 5 "Live Community Events" for a global marriage matchmaking app called "Knot".
        Return as a JSON array of objects with 'message' and 'location'.
    `;

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            message: { type: Type.STRING },
                            location: { type: Type.STRING }
                        },
                        required: ["message", "location"]
                    }
                }
            }
        });

        const data = JSON.parse(response.text || '[]');
        const events = data.map((item: any, idx: number) => ({
            id: `event_${Date.now()}_${idx}`,
            message: item.message,
            location: item.location,
            timestamp: new Date()
        }));

        localStorage.setItem(CACHE_KEY, JSON.stringify({
            timestamp: Date.now(),
            data: events
        }));

        return events;
    } catch (e: any) {
        return FALLBACK_EVENTS;
    }
};

import React, { useState, useEffect, useCallback } from 'react';
import { User, Match, Screen, FilterState, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from './types';
import { INITIAL_FILTERS, CURRENT_USER } from './constants';
import { db } from './services/databaseService';
import { queryGlobalRegistry } from './services/matchingService';
import Header from './components/Header';
import BottomNav from './components/BottomNav';
import MatchCard from './components/MatchCard';
import DiscoveryScreen from './components/DiscoveryScreen';
import ProfileDetailScreen from './components/ProfileDetailScreen';
import ChatScreen from './components/ChatScreen';
import VideoCallScreen from './components/VideoCallScreen';
import ProfileCard from './components/ProfileCard';
import VerificationScreen from './components/VerificationScreen';
import EditProfileScreen from './components/EditProfileScreen';
import PhotoManagerScreen from './components/PhotoManagerScreen';
import AuthScreen from './components/AuthScreen';
import LikesScreen from './components/LikesScreen';
import PremiumModal from './components/PremiumModal';
import MessagesScreen from './components/MessagesScreen';
import FilterModal from './components/FilterModal';
import PaymentScreen from './components/PaymentScreen';
import OnboardingFlow from './components/OnboardingFlow';
