import React, { useState, useEffect, useCallback } from 'react';
import { User, Match, Screen, FilterState, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from './types';
import { INITIAL_FILTERS, CURRENT_USER } from './constants';
import { db } from './services/databaseService';
import { queryGlobalRegistry } from './services/matchingService';
import Header from './components/Header';
import BottomNav from './components/BottomNav';
import MatchCard from './components/MatchCard';
import DiscoveryScreen from './components/DiscoveryScreen';
import ProfileDetailScreen from './components/ProfileDetailScreen';
import ChatScreen from './components/ChatScreen';
import VideoCallScreen from './components/VideoCallScreen';
import ProfileCard from './components/ProfileCard';
import VerificationScreen from './components/VerificationScreen';
import EditProfileScreen from './components/EditProfileScreen';
import PhotoManagerScreen from './components/PhotoManagerScreen';
import AuthScreen from './components/AuthScreen';
import LikesScreen from './components/LikesScreen';
import PremiumModal from './components/PremiumModal';
import MessagesScreen from './components/MessagesScreen';
import FilterModal from './components/FilterModal';
import PaymentScreen from './components/PaymentScreen';
import OnboardingFlow from './components/OnboardingFlow';
import { FilterIcon } from './components/icons/FilterIcon';
import { DiscoveryIcon } from './components/icons/DiscoveryIcon';
import { ToastProvider, useToast } from './components/feedback/useToast';

const AppContent: React.FC = () => {
    const [user, setUser] = useState<User | null>(null);
    const [matches, setMatches] = useState<Match[]>([]);
    const [isLoggedIn, setIsLoggedIn] = useState(false);
    const [activeScreen, setActiveScreen] = useState<Screen>('home');
    const [selectedMatch, setSelectedMatch] = useState<Match | null>(null);
    const [filters, setFilters] = useState<FilterState>(INITIAL_FILTERS);
    const [isFilterModalOpen, setIsFilterModalOpen] = useState(false);
    const [isPremiumModalOpen, setIsPremiumModalOpen] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);
    const { addToast } = useToast();

    useEffect(() => {
        const loadData = async () => {
            const userData = await db.getUser();
            const matchesData = await db.getMatches();
            setUser(userData);
            setMatches(matchesData);
        };
        loadData();
    }, []);

    const fetchMoreFromGlobalRegistry = useCallback(async (isSilent = false) => {
        if (isSyncing) return;
        setIsSyncing(true);
        if (!isSilent) addToast("Syncing Global Registry...", "info");

        try {
            const newMatches = await queryGlobalRegistry(4);
            if (newMatches.length > 0) {
                await db.addGlobalMatches(newMatches);
                const updatedMatches = await db.getMatches();
                setMatches(updatedMatches);
                if (!isSilent) addToast(`Found ${newMatches.length} new profiles.`, "success");
            }
        } catch (e) {
            if (!isSilent) addToast("Registry sync failed.", "error");
        } finally {
            setIsSyncing(false);
        }
    }, [isSyncing, addToast]);

    const handleLogin = (isNewUser: boolean = false, name?: string) => {
        if (isNewUser) {
            const newUserTemplate: User = {
                ...CURRENT_USER,
                id: `user_${Date.now()}`,
                name: name || 'New User',
                bio: '',
                age: 25,
                isVerified: false,
                isPremium: false,
                profileImageUrls: ['https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=800&auto=format&fit=crop'],
                personalValues: [],
                occupation: '',
                marriageTimeline: '1-2 years',
                maritalStatus: MaritalStatus.NeverMarried,
                childrenPreference: ChildrenPreference.OpenToChildren,
                willingToRelocate: WillingToRelocate.Maybe,
            };
            setUser(newUserTemplate);
            db.saveUser(newUserTemplate);
            setIsLoggedIn(true);
            setActiveScreen('onboarding');
        } else {
            setIsLoggedIn(true);
            setActiveScreen('home');
        }
    };

    const handleNavigate = (screen: Screen) => {
        if (screen === 'likes' && user && !user.isPremium) {
            setIsPremiumModalOpen(true);
        } else {
            setActiveScreen(screen);
        }
    };

    const handleCardClick = (match: Match) => {
        setSelectedMatch(match);
        setActiveScreen('profileDetail');
    };

    const handleStartChat = (match: Match) => {
        if (user && !user.isPremium) {
            setIsPremiumModalOpen(true);
            return;
        }
        setSelectedMatch(match);
        setActiveScreen('chat');
    };

    const handleStartCall = (match: Match) => {
        if (user && !user.isPremium) {
            setIsPremiumModalOpen(true);
            return;
        }
        setSelectedMatch(match);
        setActiveScreen('videoCall');
    };

    const handleBack = () => {
        if (activeScreen === 'chat' || activeScreen === 'videoCall') {
            setActiveScreen('profileDetail');
        } else if (activeScreen === 'profileDetail' || activeScreen === 'payment') {
            setActiveScreen('home');
            setSelectedMatch(null);
        } else if (['verification', 'editProfile', 'managePhotos'].includes(activeScreen)) {
            setActiveScreen('profile');
            setSelectedMatch(null);
        } else {
            setActiveScreen('home');
            setSelectedMatch(null);
        }
    };

    const handleUpgradeClick = () => {
        setIsPremiumModalOpen(false);
        setActiveScreen('payment');
    };

    const handleSubscribe = () => {
        if (user) {
            const updated = { ...user, isPremium: true };
            setUser(updated);
            db.saveUser(updated);
        }
        addToast('Welcome to Premium!', 'success');
        setActiveScreen('likes'); 
    };

    const handleSaveProfile = (updatedUser: User) => {
        setUser(updatedUser);
        db.saveUser(updatedUser);
        addToast('Registry updated!', 'success');
        if (activeScreen === 'onboarding') {
            setActiveScreen('home');
        } else {
            handleBack();
        }
    };

    const handleVerificationComplete = () => {
        if (user) {
            const updated = {...user, isVerified: true};
            setUser(updated);
            db.saveUser(updated);
        }
        setActiveScreen('profile');
    };

    const handleUpdatePhotos = (photos: string[]) => {
        if (user) {
            const updated = {...user, profileImageUrls: photos};
            setUser(updated);
            db.saveUser(updated);
        }
        addToast('Photos updated!', 'success');
        handleBack();
    };

    const filteredMatches = matches.filter(match => {
        const ageMatch = match.age >= filters.ageRange[0] && match.age <= filters.ageRange[1];
        const locationMatch = filters.location ? (match.city?.toLowerCase().includes(filters.location.toLowerCase()) || match.country?.toLowerCase().includes(filters.location.toLowerCase())) : true;
        const verifiedMatch = filters.showVerifiedOnly ? match.isVerified : true;
        return ageMatch && locationMatch && verifiedMatch;
    });

    if (!isLoggedIn) {
        return <AuthScreen onLogin={(name) => handleLogin(false, name)} onSignUp={(name) => handleLogin(true, name)} />;
    }

    if (!user) return <div className="h-screen flex items-center justify-center">Loading Knot...</div>;

    const renderScreen = () => {
        if (selectedMatch) {
            switch(activeScreen) {
                case 'profileDetail':
                    return <ProfileDetailScreen match={selectedMatch} user={user} onBack={handleBack} onStartChat={handleStartChat} onStartCall={handleStartCall} />;
                case 'chat':
                    return <ChatScreen match={selectedMatch} user={user} onBack={handleBack} onStartCall={handleStartCall} />;
                case 'videoCall':
                    return <VideoCallScreen match={selectedMatch} user={user} onEndCall={handleBack} />;
            }
        }

        switch (activeScreen) {
            case 'onboarding':
                return <OnboardingFlow user={user} onComplete={handleSaveProfile} />;
            case 'home':
                return (
                    <div className="p-4 space-y-3 pb-32">
                        {/* Feed Header - Restored nomenclature */}
                        <div className="flex items-center justify-between px-2 pt-0.5 pb-1 border-b border-gray-100 mb-2">
                            <div className="flex flex-col">
                                <h2 className="text-xl font-black text-brand-dark tracking-tighter uppercase leading-none">Your Vows Waiting</h2>
                                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-0.5">High Compatibility Suggestions</p>
                            </div>
                            <div className="flex items-center gap-2">
                                <button onClick={() => setIsFilterModalOpen(true)} className="p-1.5 bg-brand-primary text-white rounded-lg shadow-md active:scale-95 transition-all">
                                    <FilterIcon className="w-5 h-5" />
                                </button>
                            </div>
                        </div>

                        {filteredMatches.length > 0 ? (
                            filteredMatches.map(match => (
                                <MatchCard key={match.id} match={match} onCardClick={handleCardClick} />
                            ))
                        ) : (
                            <div className="text-center py-20">
                                <p className="text-gray-500 font-bold uppercase tracking-widest text-xs">No matches found for these filters.</p>
                                <button onClick={() => setFilters(INITIAL_FILTERS)} className="mt-4 text-brand-primary font-black uppercase text-[10px] tracking-widest underline">Reset Filters</button>
                            </div>
                        )}

                        <div className="pt-6 pb-4 flex flex-col items-center">
                            <button 
                                onClick={() => setActiveScreen('discovery')} 
                                className="flex items-center gap-2 bg-white border border-brand-primary/20 text-brand-primary font-black px-8 py-3 rounded-full shadow-sm hover:shadow-md transition-all active:scale-95"
                            >
                                <DiscoveryIcon className="w-5 h-5" />
                                <span>Browse Global Registry</span>
                            </button>
                        </div>
                    </div>
                );
            case 'discovery':
                return (
                    <div className="space-y-2">
                        {/* Discovery Header - Restored exactly as before and smaller */}
                        <div className="flex items-center justify-between px-6 pt-3 pb-1 border-b border-gray-50 mb-2">
                             <div className="flex flex-col">
                                 <h2 className="text-[10px] font-black text-brand-dark uppercase tracking-widest leading-none">Global Discovery</h2>
                                 <p className="text-[8px] font-bold text-gray-400 uppercase tracking-tighter mt-0.5">Browsing All Registered Members</p>
                             </div>
                             <button onClick={() => setIsFilterModalOpen(true)} className="p-1.5 text-brand-primary border border-brand-primary/20 rounded-lg">
                                <FilterIcon className="w-4 h-4" />
                             </button>
                        </div>
                        <DiscoveryScreen matches={filteredMatches} onMatchClick={handleCardClick} />
                    </div>
                );
            case 'likes':
                 return <LikesScreen likedMatches={[]} onMatchClick={handleCardClick} />;
            case 'messages':
                return <MessagesScreen onChatSelect={handleStartChat} user={user} />;
            case 'profile':
                return <ProfileCard 
                    user={user} 
                    onEditProfile={() => setActiveScreen('editProfile')} 
                    onManagePhotos={() => setActiveScreen('managePhotos')}
                    onVerifyProfile={() => setActiveScreen('verification')}
                />;
            case 'verification':
                return <VerificationScreen onVerificationComplete={handleVerificationComplete} onBack={handleBack} />;
            case 'editProfile':
                return <EditProfileScreen user={user} onBack={handleBack} onSave={handleSaveProfile} />;
            case 'managePhotos':
                return <PhotoManagerScreen user={user} onBack={handleBack} onUpdatePhotos={handleUpdatePhotos} />;
            case 'payment':
                return <PaymentScreen onBack={handleBack} onSubscribe={handleSubscribe} />;
            default:
                return <div>Home</div>;
        }
    };

    const showHeader = ['home', 'discovery', 'likes', 'messages', 'profile'].includes(activeScreen);
    const showBottomNav = ['home', 'discovery', 'likes', 'messages', 'profile'].includes(activeScreen);

    return (
        <div className="max-w-md mx-auto bg-gray-50 min-h-screen font-sans">
            {showHeader && (
                <div className="fixed top-0 left-0 right-0 max-w-md mx-auto z-50">
                    <Header />
                    {isSyncing && (
                        <div className="h-0.5 w-full bg-brand-light relative overflow-hidden">
                            <div className="absolute inset-0 bg-brand-primary animate-progress-ind"></div>
                        </div>
                    )}
                </div>
            )}

            <main className={`${showHeader ? 'pt-[4rem]' : ''}`}>
                {renderScreen()}
            </main>

            {showBottomNav && (
                <BottomNav activeScreen={activeScreen} onNavigate={handleNavigate} />
            )}

            <FilterModal 
                isOpen={isFilterModalOpen} 
                onClose={() => setIsFilterModalOpen(false)}
                currentFilters={filters}
                onApplyFilters={(newFilters) => {
                    setFilters(newFilters);
                    addToast('Filters applied.', 'info');
                }}
                initialFilters={INITIAL_FILTERS}
            />

            {/* Fix component casing to resolve JSX intrinsic element error */}
            <PremiumModal 
                isOpen={isPremiumModalOpen}
                onClose={() => setIsPremiumModalOpen(false)}
                onUpgrade={handleUpgradeClick}
            />

            <style>{`
                @keyframes progress-ind {
                    0% { left: -100%; width: 100%; }
                    100% { left: 100%; width: 100%; }
                }
                .animate-progress-ind { animation: progress-ind 1.5s infinite linear; }
            `}</style>
        </div>
    );
};

const App: React.FC = () => {
    return (
        <ToastProvider>
            <AppContent />
        </ToastProvider>
    );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Match, User } from '../types';
import { VerifiedIcon } from './icons/VerifiedIcon';
import { MessageIcon } from './icons/MessageIcon';
import { VideoCameraIcon } from './icons/VideoCameraIcon';
import { SparklesIcon } from './icons/SparklesIcon';
import { getCompatibilityInsight } from '../services/matchingService';

interface ProfileDetailScreenProps {
  match: Match;
  user: User;
  onBack: () => void;
  onStartChat: (match: Match) => void;
  onStartCall: (match: Match) => void;
}

interface ProfileSectionProps {
    title: string;
    children: React.ReactNode;
}

const ProfileSection: React.FC<ProfileSectionProps> = ({ title, children }) => (
    <div className="border-b border-gray-100 last:border-0">
        <div className="py-5 text-left">
            <h3 className="font-black text-lg text-brand-dark uppercase tracking-tight">{title}</h3>
        </div>
        <div className="pb-6 space-y-5 animate-fade-in">
            {children}
        </div>
    </div>
);

const ProfileDataItem: React.FC<{ label: string; value: React.ReactNode }> = ({ label, value }) => (
    <div className="space-y-1">
        <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">{label}</p>
        <div className="text-sm text-black font-medium leading-relaxed">
            {value || <span className="text-gray-300 italic">Not specified</span>}
        </div>
    </div>
);


const ProfileDetailScreen: React.FC<ProfileDetailScreenProps> = ({ match: initialMatch, user, onBack, onStartChat, onStartCall }) => {
  const [match, setMatch] = useState<Match>(initialMatch);
  const [currentPhotoIndex, setCurrentPhotoIndex] = useState(0);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const photos = match.profileImageUrls && match.profileImageUrls.length > 0 
    ? match.profileImageUrls 
    : ['https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=800&auto=format&fit=crop'];

  useEffect(() => {
    const fetchInsight = async () => {
        if (!match.compatibilityInsight) {
            setIsAnalyzing(true);
            const { score, insight } = await getCompatibilityInsight(user, match);
            setMatch(prev => ({ ...prev, compatibilityScore: score, compatibilityInsight: insight }));
            setIsAnalyzing(false);
        }
    };
    fetchInsight();
  }, [match.id, user.id]);

  const handlePhotoTap = (e: React.MouseEvent<HTMLDivElement, MouseEvent>) => {
    e.stopPropagation();
    const { clientX, currentTarget } = e;
    const { left, width } = currentTarget.getBoundingClientRect();
    const isRightSide = clientX > left + width / 2;

    if (isRightSide) {
      setCurrentPhotoIndex(prev => Math.min(prev + 1, photos.length - 1));
    } else {
      setCurrentPhotoIndex(prev => Math.max(prev - 1, 0));
    }
  };

  return (
    <div className="w-full h-screen bg-white flex flex-col">
      <div className="flex-1 overflow-y-auto pb-32">
        {/* Image Carousel */}
        <div className="relative aspect-square w-full flex-shrink-0">
          <div className="absolute top-4 left-4 right-4 z-20 flex items-center gap-1.5">
            {photos.map((_, index) => (
              <div key={index} className={`h-1 flex-1 rounded-full ${index === currentPhotoIndex ? 'bg-white' : 'bg-white/40'}`} />
            ))}
          </div>
          <button onClick={onBack} className="absolute top-8 left-4 z-30 text-white bg-black/40 backdrop-blur-sm p-3 rounded-full shadow-lg active:scale-90 transition-transform">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
          <div className="absolute inset-0" onClick={handlePhotoTap}>
              <img 
                  src={photos[currentPhotoIndex]} 
                  alt={`${match.name}'s photo ${currentPhotoIndex + 1}`} 
                  className="w-full h-full object-cover" 
              />
          </div>
          <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent pointer-events-none"></div>
        </div>

        {/* Profile Info */}
        <div className="bg-white -mt-12 rounded-t-[3rem] z-10 relative">
          <div className="p-8 pb-4">
            <div className="flex items-start justify-between">
                <div>
                    <div className="flex items-center gap-3">
                        <h1 className="text-4xl font-black text-brand-dark tracking-tighter">{match.name}, {match.age}</h1>
                        {match.isVerified && (
                             <div className="bg-brand-accent rounded-full p-1 shadow-md">
                                <VerifiedIcon className="w-4 h-4 text-brand-dark" />
                            </div>
                        )}
                    </div>
                    <p className="text-sm font-bold text-gray-400 uppercase tracking-widest mt-1">
                      {match.residenceCity && match.residenceCountry ? `${match.residenceCity}, ${match.residenceCountry}` : `${match.city}, ${match.country}`}
                    </p>
                </div>
                {match.compatibilityScore && (
                    <div className="bg-brand-primary text-white p-3 rounded-2xl flex flex-col items-center shadow-xl shadow-brand-primary/20">
                        <span className="text-[8px] font-black uppercase tracking-widest opacity-60">Match</span>
                        <span className="text-xl font-black">{match.compatibilityScore}%</span>
                    </div>
                )}
            </div>

            {/* AI Insight Box */}
            <div className="mt-8 bg-brand-light p-5 rounded-[2rem] border border-brand-primary/5">
                <div className="flex items-center gap-2 mb-3">
                    <SparklesIcon className="w-4 h-4 text-brand-primary" />
                    <span className="text-[10px] font-black text-brand-primary uppercase tracking-widest">Registry Compatibility Agent</span>
                </div>
                {isAnalyzing ? (
                    <div className="flex items-center gap-4 py-1">
                        <div className="w-4 h-4 border-2 border-brand-primary border-t-transparent rounded-full animate-spin"></div>
                        <p className="text-[11px] font-bold text-gray-500 uppercase tracking-widest animate-pulse">Running comparison engine...</p>
                    </div>
                ) : (
                    <p className="text-sm text-black font-medium leading-relaxed italic">
                        "{match.compatibilityInsight || "Establishing deep value connection..."}"
                    </p>
                )}
            </div>
          </div>

          {/* Profile Content */}
          <div className="px-8 space-y-2">
              <ProfileSection title={`Identity & Roots`}>
                  <div className="grid grid-cols-2 gap-x-8 gap-y-4">
                      <ProfileDataItem label="Marital Status" value={match.maritalStatus} />
                      <ProfileDataItem label="Occupation" value={match.occupation} />
                  </div>

                  <div className="p-4 bg-gray-50 rounded-2xl border border-gray-100 space-y-4">
                        <div className="space-y-2">
                            <h4 className="text-[9px] font-black text-brand-primary uppercase tracking-widest">Current Residence</h4>
                            <div className="grid grid-cols-3 gap-2">
                                <ProfileDataItem label="Country" value={match.residenceCountry} />
                                <ProfileDataItem label="State" value={match.residenceState} />
                                <ProfileDataItem label="City" value={match.residenceCity} />
                            </div>
                        </div>

                        <div className="h-[1px] bg-gray-200 w-full"></div>

                        <div className="space-y-2">
