import React, { useState, useEffect } from 'react';
import { Match, User } from '../types';
import { db } from '../services/databaseService';
import { CloseIcon } from './icons/CloseIcon';
import { ShieldCheckIcon } from './icons/ShieldCheckIcon';
import { TrashIcon } from './icons/TrashIcon';
import { VerifiedIcon } from './icons/VerifiedIcon';
import { useToast } from './feedback/useToast';

interface AdminScreenProps {
    onBack: () => void;
}

const StatCard: React.FC<{ label: string; value: string | number; color?: string }> = ({ label, value, color = "text-brand-primary" }) => (
    <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">{label}</p>
        <p className={`text-2xl font-black ${color}`}>{value}</p>
    </div>
);

const AdminScreen: React.FC<AdminScreenProps> = ({ onBack }) => {
    const [members, setMembers] = useState<Match[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const { addToast } = useToast();

    useEffect(() => {
        const loadRegistry = async () => {
            const data = await db.getMatches();
            setMembers(data);
            setIsLoading(false);
        };
        loadRegistry();
    }, []);

    const handleDelete = async (memberId: string) => {
        if (window.confirm("Purge this member from the registry? This action cannot be undone.")) {
            const updated = members.filter(m => m.id !== memberId);
            setMembers(updated);
            await db.saveMatches(updated);
            addToast("Member purged from registry.", "success");
        }
    };

    const toggleVerify = async (memberId: string) => {
        const updated = members.map(m => {
            if (m.id === memberId) {
                return { ...m, isVerified: !m.isVerified };
            }
            return m;
        });
        setMembers(updated);
        await db.saveMatches(updated);
        addToast("Registry status updated.", "info");
    };

    const stats = {
        total: members.length,
        verified: members.filter(m => m.isVerified).length,
        premium: members.filter(m => m.isPremium).length,
        pending: members.length - members.filter(m => m.isVerified).length
    };

    return (
        <div className="w-full h-screen bg-gray-50 flex flex-col font-sans">
            <header className="flex items-center justify-between p-4 bg-brand-dark text-white border-b border-white/10 sticky top-0 z-10 shadow-xl">
                <div className="flex items-center gap-3">
                    <ShieldCheckIcon className="w-6 h-6 text-brand-accent" />
                    <div>
                        <h1 className="text-xl font-black uppercase tracking-tighter leading-none">Registry Command</h1>
                        <p className="text-[8px] font-bold text-brand-accent uppercase tracking-[0.2em] mt-1">Superuser Mode</p>
                    </div>
                </div>
                <button onClick={onBack} className="p-2 bg-white/10 rounded-full text-white hover:bg-white/20">
                    <CloseIcon className="w-6 h-6" />
                </button>
            </header>

            <main className="flex-1 overflow-y-auto pb-32">
                {/* Metrics */}
                <div className="p-6 grid grid-cols-2 gap-4">
                    <StatCard label="Total Registry" value={stats.total} />
                    <StatCard label="Verified" value={stats.verified} color="text-green-600" />
                    <StatCard label="Premium" value={stats.premium} color="text-brand-secondary" />
                    <StatCard label="Suspicious/New" value={stats.pending} color="text-red-500" />
                </div>

                {/* Directory */}
                <div className="px-6">
                    <h2 className="text-sm font-black text-brand-dark uppercase tracking-widest mb-4">Member Directory</h2>

                    {isLoading ? (
                        <div className="flex justify-center py-10">
                            <div className="w-8 h-8 border-4 border-brand-primary border-t-transparent rounded-full animate-spin"></div>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            {members.map((member) => (
                                <div key={member.id} className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm flex items-center gap-4 group">
                                    <div className="relative">
                                        <img src={member.profileImageUrls[0]} alt={member.name} className="w-14 h-14 rounded-full object-cover shadow-inner" />
                                        {member.isPremium && <div className="absolute -top-1 -right-1 bg-brand-accent w-4 h-4 rounded-full flex items-center justify-center text-[8px] shadow-sm">★</div>}
                                    </div>

                                    <div className="flex-1 min-w-0">
                                        <div className="flex items-center gap-1.5">
                                            <p className="font-black text-brand-dark truncate">{member.name}, {member.age}</p>
                                            {member.isVerified && <VerifiedIcon className="w-4 h-4 text-green-500" />}
                                        </div>
                                        <p className="text-[10px] text-gray-400 font-bold uppercase truncate">{member.occupation}</p>
                                        <p className="text-[10px] text-brand-secondary font-black truncate mt-0.5">{member.id}</p>
                                    </div>

                                    <div className="flex items-center gap-2">
                                        <button 
                                            onClick={() => toggleVerify(member.id)}
                                            className={`p-2 rounded-xl border transition-all ${member.isVerified ? 'bg-green-50 border-green-200 text-green-600' : 'bg-gray-50 border-gray-100 text-gray-400'}`}
                                            title={member.isVerified ? "Revoke Verification" : "Grant Verification"}
                                        >
                                            <ShieldCheckIcon className="w-5 h-5" />
                                        </button>
                                        <button 
                                            onClick={() => handleDelete(member.id)}
                                            className="p-2 bg-red-50 border border-red-100 text-red-500 rounded-xl active:scale-95"
                                            title="Purge Member"
                                        >
                                            <TrashIcon className="w-5 h-5" />
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {/* Audit Logs */}
                <div className="p-6 mt-6">
                    <h2 className="text-sm font-black text-brand-dark uppercase tracking-widest mb-4">Live Audit Log</h2>
                    <div className="bg-brand-dark rounded-3xl p-6 font-mono text-[9px] text-brand-accent/80 space-y-2 leading-relaxed border border-white/5">
                        <p><span className="text-white opacity-40">[14:32:01]</span> REGISTRY_SYNC: Fetched 4 cloud members</p>
                        <p><span className="text-white opacity-40">[14:30:45]</span> AUTH_SUCCESS: User user_0 logged in</p>
                        <p><span className="text-white opacity-40">[14:28:12]</span> MATCH_FOUND: High compatibility detected for #global_zoe</p>
                        <p><span className="text-white opacity-40">[14:25:55]</span> DB_MIGRATION: childrenStatus integrity check passed</p>
                        <div className="w-1 h-3 bg-brand-accent/50 animate-pulse inline-block ml-1"></div>
                    </div>
                </div>
            </main>
        </div>
    );
};

export default AdminScreen;

import React, { useState } from 'react';
import { KnotLogo } from './KnotLogo';
import { EnvelopeIcon } from './icons/EnvelopeIcon';
import { GmailIcon } from './icons/GmailIcon';
import { AppleIcon } from './icons/AppleIcon';
import { CloseIcon } from './icons/CloseIcon';
import { ShieldCheckIcon } from './icons/ShieldCheckIcon';

interface AuthScreenProps {
    onLogin: (name?: string, email?: string) => void;
    onSignUp: (name?: string) => void;
}

interface MockAccount {
    name: string;
    email: string;
    role?: string;
}

const AuthScreen: React.FC<AuthScreenProps> = ({ onLogin, onSignUp }) => {
    const [isLogin, setIsLogin] = useState(true);
    const [showEmailForm, setShowEmailForm] = useState(false);
    const [showAccountPicker, setShowAccountPicker] = useState(false);
    const [pickerType, setPickerType] = useState<'Gmail' | 'Apple' | null>(null);
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');

    const mockAccounts: MockAccount[] = [
        { name: 'Registry Admin', email: 'admin@knot.ai', role: 'Administrator' },
        { name: 'Sofia Ricci', email: 'sofia.r@gmail.com' },
    ];

    const toggleAuthMode = () => {
        setIsLogin(!isLogin);
        setShowEmailForm(false);
        setShowAccountPicker(false);
    };

    const handleEmailContinue = () => {
        setShowEmailForm(true);
    };

    const handleSocialClick = (type: 'Gmail' | 'Apple') => {
        setPickerType(type);
        setShowAccountPicker(true);
    };

    const handleAccountSelect = (account: MockAccount) => {
        setShowAccountPicker(false);
        if (isLogin) {
            onLogin(account.name, account.email);
        } else {
            onSignUp(account.name);
        }
    };

    const handleFormSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (isLogin) {
            onLogin(name || 'User', email);
        } else {
            onSignUp(name);
        }
    };

    return (
        <div className="min-h-screen bg-brand-light flex flex-col justify-center items-center p-6 relative overflow-hidden">
            {/* Background Decorative Elements */}
            <div className="absolute top-[-10%] right-[-10%] w-64 h-64 bg-brand-primary/5 rounded-full blur-3xl"></div>
            <div className="absolute bottom-[-5%] left-[-5%] w-72 h-72 bg-brand-accent/10 rounded-full blur-3xl"></div>

            <KnotLogo className="text-4xl mb-8 relative z-10" />

            <div className="w-full max-w-sm bg-white p-8 rounded-[2.5rem] shadow-2xl relative z-10 border border-white/50">
                <h1 className="text-2xl font-black text-center text-brand-dark mb-6 tracking-tight">
                    {isLogin ? 'Welcome Back' : 'Create Account'}
                </h1>

                {showEmailForm ? (
                    <form onSubmit={handleFormSubmit} className="space-y-4 animate-fade-in">
                        {!isLogin && (
                             <div>
                                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5 block" htmlFor="name">Full Name</label>
                                <input 
                                    id="name"
                                    type="text" 
                                    value={name}
                                    onChange={(e) => setName(e.target.value)}
                                    required
                                    className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-2xl focus:outline-none focus:ring-2 focus:ring-brand-primary/20 focus:bg-white text-brand-dark transition-all"
                                    placeholder="Enter your name"
                                />
                            </div>
                        )}
                        <div>
                            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5 block" htmlFor="email">Email Address</label>
                            <input 
                                id="email"
                                type="email" 
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                required
                                className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-2xl focus:outline-none focus:ring-2 focus:ring-brand-primary/20 focus:bg-white text-brand-dark transition-all"
                                placeholder="admin@knot.ai"
                            />
                        </div>
                        <div>
                            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5 block" htmlFor="password">Security Password</label>
                            <input 
                                id="password"
                                type="password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                                className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-2xl focus:outline-none focus:ring-2 focus:ring-brand-primary/20 focus:bg-white text-brand-dark transition-all"
                                placeholder="knot2025"
                            />
                        </div>
                        {email === 'admin@knot.ai' && (
                            <div className="bg-brand-dark text-brand-accent p-3 rounded-xl flex items-center gap-2 animate-pulse">
                                <ShieldCheckIcon className="w-4 h-4" />
                                <span className="text-[9px] font-black uppercase tracking-widest">Administrator Credentials Detected</span>
                            </div>
                        )}
                         <button 
                            type="submit"
                            className="w-full bg-brand-primary text-white font-black py-4 rounded-2xl shadow-xl shadow-brand-primary/20 hover:bg-brand-secondary transition-all mt-4 active:scale-95"
                        >
                            {isLogin ? 'Log In to Registry' : 'Join the Registry'}
                        </button>
                        <button type="button" onClick={() => setShowEmailForm(false)} className="w-full text-gray-400 text-xs font-bold uppercase tracking-widest py-2">Go Back</button>
                    </form>
                ) : (
                    <div className="space-y-4">
                        <button onClick={() => handleSocialClick('Gmail')} className="w-full flex items-center justify-center gap-3 bg-white border border-gray-100 text-brand-dark font-bold py-4 rounded-2xl hover:shadow-md transition-all active:scale-95">
                            <GmailIcon className="w-5 h-5" />
                            Continue with Google
                        </button>
                        <button onClick={() => handleSocialClick('Apple')} className="w-full flex items-center justify-center gap-3 bg-brand-dark text-white font-bold py-4 rounded-2xl hover:bg-black transition-all active:scale-95 shadow-lg">
                            <AppleIcon className="w-5 h-5" />
                            Continue with Apple
                        </button>
                        <div className="relative flex py-4 items-center">
                            <div className="flex-grow border-t border-gray-100"></div>
                            <span className="flex-shrink mx-4 text-gray-300 text-[10px] font-black uppercase tracking-widest">OR</span>
