                        <div className="p-4 space-y-2">
                            {mockAccounts.map((account, idx) => (
                                <button 
                                    key={idx}
                                    onClick={() => handleAccountSelect(account)}
                                    className={`w-full flex items-center gap-4 p-4 rounded-2xl transition-colors text-left group border ${account.role === 'Administrator' ? 'bg-brand-dark text-white hover:bg-black' : 'hover:bg-brand-light border-transparent hover:border-brand-primary/10'}`}
                                >
                                    <div className={`w-12 h-12 rounded-full flex items-center justify-center font-black text-xl ${account.role === 'Administrator' ? 'bg-brand-accent text-brand-dark' : 'bg-brand-primary/10 text-brand-primary'}`}>
                                        {account.role === 'Administrator' ? <ShieldCheckIcon className="w-6 h-6" /> : account.name[0]}
                                    </div>
                                    <div className="flex-1 overflow-hidden">
                                        <div className="flex items-center gap-2">
                                            <p className="font-bold truncate">{account.name}</p>
                                            {account.role === 'Administrator' && (
                                                <span className="bg-brand-accent text-brand-dark text-[7px] font-black px-1.5 py-0.5 rounded uppercase tracking-tighter">Admin</span>
                                            )}
                                        </div>
                                        <p className={`text-xs truncate ${account.role === 'Administrator' ? 'text-brand-accent/60' : 'text-gray-400'}`}>{account.email}</p>
                                    </div>
                                    <div className="opacity-0 group-hover:opacity-100 transition-opacity">
                                        <svg xmlns="http://www.w3.org/2000/svg" className={`h-5 w-5 ${account.role === 'Administrator' ? 'text-brand-accent' : 'text-brand-primary'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                                        </svg>
                                    </div>
                                </button>
                            ))}
                            <button onClick={() => setShowAccountPicker(false)} className="w-full p-4 text-brand-primary text-xs font-black uppercase tracking-widest border-t border-gray-50 mt-2">
                                Use another account
                            </button>
                        </div>
                        <div className="bg-gray-50 p-6 text-center">
                            <p className="text-[10px] text-gray-400 font-medium leading-relaxed">
                                To continue, Google/Apple will share your name, email address, language preference, and profile picture with Knot.
                            </p>
                        </div>
                    </div>
                </div>
            )}

            <style>{`
                .animate-fade-in { animation: fadeIn 0.4s ease-out; }
                .animate-slide-up { animation: slideUp 0.5s cubic-bezier(0.2, 0.8, 0.2, 1); }
                @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
                @keyframes slideUp { from { transform: translateY(100%); } to { transform: translateY(0); } }
            `}</style>
        </div>
    );
};

export default AuthScreen;

import React, { useState, useEffect, useCallback } from 'react';
import { User, Match, Screen, FilterState, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from './types';
import { INITIAL_FILTERS, CURRENT_USER } from './constants';
import { db } from './services/databaseService';
import { queryGlobalRegistry } from './services/matchingService';
import Header from './components/Header';
import BottomNav from './components/BottomNav';
import MatchCard from './components/MatchCard';
import DiscoveryScreen from './components/DiscoveryScreen';
import ProfileDetailScreen from './components/ProfileDetailScreen';
import ChatScreen from './components/ChatScreen';
import VideoCallScreen from './components/VideoCallScreen';
import ProfileCard from './components/ProfileCard';
import VerificationScreen from './components/VerificationScreen';
import EditProfileScreen from './components/EditProfileScreen';
import PhotoManagerScreen from './components/PhotoManagerScreen';
import AuthScreen from './components/AuthScreen';
import LikesScreen from './components/LikesScreen';
import PremiumModal from './components/PremiumModal';
import MessagesScreen from './components/MessagesScreen';
import FilterModal from './components/FilterModal';
import PaymentScreen from './components/PaymentScreen';
import OnboardingFlow from './components/OnboardingFlow';
import AdminScreen from './components/AdminScreen';
import { FilterIcon } from './components/icons/FilterIcon';
import { DiscoveryIcon } from './components/icons/DiscoveryIcon';
import { ToastProvider, useToast } from './components/feedback/useToast';

const AppContent: React.FC = () => {
    const [user, setUser] = useState<User | null>(null);
    const [matches, setMatches] = useState<Match[]>([]);
    const [isLoggedIn, setIsLoggedIn] = useState(false);
    const [activeScreen, setActiveScreen] = useState<Screen>('home');
    const [selectedMatch, setSelectedMatch] = useState<Match | null>(null);
    const [filters, setFilters] = useState<FilterState>(INITIAL_FILTERS);
    const [isFilterModalOpen, setIsFilterModalOpen] = useState(false);
    const [isPremiumModalOpen, setIsPremiumModalOpen] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);
    const { addToast } = useToast();

    useEffect(() => {
        const loadData = async () => {
            const userData = await db.getUser();
            const matchesData = await db.getMatches();
            setUser(userData);
            setMatches(matchesData);
        };
        loadData();
    }, []);

    const fetchMoreFromGlobalRegistry = useCallback(async (isSilent = false) => {
        if (isSyncing) return;
        setIsSyncing(true);
        if (!isSilent) addToast("Syncing Global Registry...", "info");

        try {
            const newMatches = await queryGlobalRegistry(4);
            if (newMatches.length > 0) {
                await db.addGlobalMatches(newMatches);
                const updatedMatches = await db.getMatches();
                setMatches(updatedMatches);
                if (!isSilent) addToast(`Found ${newMatches.length} new profiles.`, "success");
            }
        } catch (e) {
            if (!isSilent) addToast("Registry sync failed.", "error");
        } finally {
            setIsSyncing(false);
        }
    }, [isSyncing, addToast]);

    const handleLogin = (isNewUser: boolean = false, name?: string, email?: string) => {
        if (isNewUser) {
            const newUserTemplate: User = {
                ...CURRENT_USER,
                id: `user_${Date.now()}`,
                name: name || 'New User',
                bio: '',
                age: 25,
                isVerified: false,
                isPremium: false,
                profileImageUrls: ['https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=800&auto=format&fit=crop'],
                personalValues: [],
                occupation: '',
                marriageTimeline: '1-2 years',
                maritalStatus: MaritalStatus.NeverMarried,
                childrenPreference: ChildrenPreference.OpenToChildren,
                willingToRelocate: WillingToRelocate.Maybe,
            };
            setUser(newUserTemplate);
            db.saveUser(newUserTemplate);
            setIsLoggedIn(true);
            setActiveScreen('onboarding');
        } else {
            // Check for Admin Demo credentials
            const isAdmin = email === 'admin@knot.ai' || name === 'Registry Admin';
            if (isAdmin) {
                setUser(CURRENT_USER); // CURRENT_USER has ID 'user_0'
                db.saveUser(CURRENT_USER);
                addToast("Admin Profile Loaded", "success");
            }
            setIsLoggedIn(true);
            setActiveScreen('home');
        }
    };

    const handleNavigate = (screen: Screen) => {
        if (screen === 'likes' && user && !user.isPremium) {
            setIsPremiumModalOpen(true);
        } else {
            setActiveScreen(screen);
        }
    };

    const handleCardClick = (match: Match) => {
        setSelectedMatch(match);
        setActiveScreen('profileDetail');
    };

    const handleStartChat = (match: Match) => {
        if (user && !user.isPremium) {
            setIsPremiumModalOpen(true);
            return;
        }
        setSelectedMatch(match);
        setActiveScreen('chat');
    };

    const handleStartCall = (match: Match) => {
        if (user && !user.isPremium) {
            setIsPremiumModalOpen(true);
            return;
        }
        setSelectedMatch(match);
        setActiveScreen('videoCall');
    };

    const handleBack = () => {
        if (activeScreen === 'chat' || activeScreen === 'videoCall') {
            setActiveScreen('profileDetail');
        } else if (activeScreen === 'profileDetail' || activeScreen === 'payment') {
            setActiveScreen('home');
            setSelectedMatch(null);
        } else if (['verification', 'editProfile', 'managePhotos', 'admin'].includes(activeScreen)) {
            setActiveScreen('profile');
            setSelectedMatch(null);
        } else {
            setActiveScreen('home');
            setSelectedMatch(null);
        }
    };

    const handleUpgradeClick = () => {
        setIsPremiumModalOpen(false);
        setActiveScreen('payment');
    };

    const handleSubscribe = () => {
        if (user) {
            const updated = { ...user, isPremium: true };
            setUser(updated);
            db.saveUser(updated);
        }
        addToast('Welcome to Premium!', 'success');
        setActiveScreen('likes'); 
    };

    const handleSaveProfile = (updatedUser: User) => {
        setUser(updatedUser);
        db.saveUser(updatedUser);
        addToast('Registry updated!', 'success');
        if (activeScreen === 'onboarding') {
            setActiveScreen('home');
        } else {
            handleBack();
        }
    };

    const handleVerificationComplete = () => {
        if (user) {
            const updated = {...user, isVerified: true};
            setUser(updated);
            db.saveUser(updated);
        }
        setActiveScreen('profile');
    };

    const handleUpdatePhotos = (photos: string[]) => {
        if (user) {
            const updated = {...user, profileImageUrls: photos};
            setUser(updated);
            db.saveUser(updated);
        }
        addToast('Photos updated!', 'success');
        handleBack();
    };

    const filteredMatches = matches.filter(match => {
        const ageMatch = match.age >= filters.ageRange[0] && match.age <= filters.ageRange[1];
        const locationMatch = filters.location ? (match.city?.toLowerCase().includes(filters.location.toLowerCase()) || match.country?.toLowerCase().includes(filters.location.toLowerCase())) : true;
        const verifiedMatch = filters.showVerifiedOnly ? match.isVerified : true;
        return ageMatch && locationMatch && verifiedMatch;
    });

    if (!isLoggedIn) {
        return <AuthScreen onLogin={(name, email) => handleLogin(false, name, email)} onSignUp={(name) => handleLogin(true, name)} />;
    }

    if (!user) return <div className="h-screen flex items-center justify-center">Loading Knot...</div>;

    const renderScreen = () => {
        if (selectedMatch) {
            switch(activeScreen) {
                case 'profileDetail':
                    return <ProfileDetailScreen match={selectedMatch} user={user} onBack={handleBack} onStartChat={handleStartChat} onStartCall={handleStartCall} />;
                case 'chat':
                    return <ChatScreen match={selectedMatch} user={user} onBack={handleBack} onStartCall={handleStartCall} />;
                case 'videoCall':
                    return <VideoCallScreen match={selectedMatch} user={user} onEndCall={handleBack} />;
            }
        }

        switch (activeScreen) {
            case 'onboarding':
                return <OnboardingFlow user={user} onComplete={handleSaveProfile} />;
            case 'home':
                return (
                    <div className="p-4 space-y-3 pb-32">
                        <div className="flex items-center justify-between px-2 pt-0.5 pb-1 border-b border-gray-100 mb-2">
                            <div className="flex flex-col">
                                <h2 className="text-xl font-black text-brand-dark tracking-tighter uppercase leading-none">Your Vows Waiting</h2>
                                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-0.5">High Compatibility Suggestions</p>
                            </div>
                            <div className="flex items-center gap-2">
                                <button onClick={() => setIsFilterModalOpen(true)} className="p-1.5 bg-brand-primary text-white rounded-lg shadow-md active:scale-95 transition-all">
                                    <FilterIcon className="w-5 h-5" />
                                </button>
                            </div>
                        </div>

                        {filteredMatches.length > 0 ? (
                            filteredMatches.map(match => (
                                <MatchCard key={match.id} match={match} onCardClick={handleCardClick} />
                            ))
                        ) : (
                            <div className="text-center py-20">
                                <p className="text-gray-500 font-bold uppercase tracking-widest text-xs">No matches found for these filters.</p>
                                <button onClick={() => setFilters(INITIAL_FILTERS)} className="mt-4 text-brand-primary font-black uppercase text-[10px] tracking-widest underline">Reset Filters</button>
                            </div>
                        )}

                        <div className="pt-6 pb-4 flex flex-col items-center">
                            <button 
                                onClick={() => setActiveScreen('discovery')} 
                                className="flex items-center gap-2 bg-white border border-brand-primary/20 text-brand-primary font-black px-8 py-3 rounded-full shadow-sm hover:shadow-md transition-all active:scale-95"
                            >
                                <DiscoveryIcon className="w-5 h-5" />
                                <span>Browse Global Registry</span>
                            </button>
                        </div>
                    </div>
                );
            case 'discovery':
                return (
                    <div className="space-y-2">
                        <div className="flex items-center justify-between px-6 pt-3 pb-1 border-b border-gray-50 mb-2">
                             <div className="flex flex-col">
                                 <h2 className="text-[10px] font-black text-brand-dark uppercase tracking-widest leading-none">Global Discovery</h2>
                                 <p className="text-[8px] font-bold text-gray-400 uppercase tracking-tighter mt-0.5">Browsing All Registered Members</p>
                             </div>
                             <button onClick={() => setIsFilterModalOpen(true)} className="p-1.5 text-brand-primary border border-brand-primary/20 rounded-lg">
                                <FilterIcon className="w-4 h-4" />
                             </button>
                        </div>
                        <DiscoveryScreen matches={filteredMatches} onMatchClick={handleCardClick} />
                    </div>
                );
            case 'likes':
                 return <LikesScreen likedMatches={[]} onMatchClick={handleCardClick} />;
            case 'messages':
                return <MessagesScreen onChatSelect={handleStartChat} user={user} />;
            case 'profile':
                return <ProfileCard 
                    user={user} 
                    onEditProfile={() => setActiveScreen('editProfile')} 
                    onManagePhotos={() => setActiveScreen('managePhotos')}
                    onVerifyProfile={() => setActiveScreen('verification')}
                    onOpenAdmin={() => setActiveScreen('admin')}
                />;
            case 'verification':
                return <VerificationScreen onVerificationComplete={handleVerificationComplete} onBack={handleBack} />;
            case 'editProfile':
                return <EditProfileScreen user={user} onBack={handleBack} onSave={handleSaveProfile} />;
            case 'managePhotos':
                return <PhotoManagerScreen user={user} onBack={handleBack} onUpdatePhotos={handleUpdatePhotos} />;
            case 'payment':
                return <PaymentScreen onBack={handleBack} onSubscribe={handleSubscribe} />;
            case 'admin':
                return <AdminScreen onBack={handleBack} />;
            default:
                return <div>Home</div>;
        }
    };

    const showHeader = ['home', 'discovery', 'likes', 'messages', 'profile'].includes(activeScreen);
    const showBottomNav = ['home', 'discovery', 'likes', 'messages', 'profile'].includes(activeScreen);

    return (
        <div className="max-w-md mx-auto bg-gray-50 min-h-screen font-sans">
            {showHeader && (
                <div className="fixed top-0 left-0 right-0 max-w-md mx-auto z-50">
                    <Header />
                    {isSyncing && (
                        <div className="h-0.5 w-full bg-brand-light relative overflow-hidden">
                            <div className="absolute inset-0 bg-brand-primary animate-progress-ind"></div>
                        </div>
                    )}
                </div>
            )}

            <main className={`${showHeader ? 'pt-[4rem]' : ''}`}>
                {renderScreen()}
            </main>

            {showBottomNav && (
                <BottomNav activeScreen={activeScreen} onNavigate={handleNavigate} />
            )}

            <FilterModal 
                isOpen={isFilterModalOpen} 
                onClose={() => setIsFilterModalOpen(false)}
                currentFilters={filters}
                onApplyFilters={(newFilters) => {
                    setFilters(newFilters);
                    addToast('Filters applied.', 'info');
                }}
                initialFilters={INITIAL_FILTERS}
            />

            <PremiumModal 
                isOpen={isPremiumModalOpen}
                onClose={() => setIsPremiumModalOpen(false)}
                onUpgrade={handleUpgradeClick}
            />

            <style>{`
                @keyframes progress-ind {
                    0% { left: -100%; width: 100%; }
                    100% { left: 100%; width: 100%; }
                }
                .animate-progress-ind { animation: progress-ind 1.5s infinite linear; }
            `}</style>
        </div>
    );
};

const App: React.FC = () => {
    return (
        <ToastProvider>
            <AppContent />
        </ToastProvider>
    );
};

export default App;

import React, { useState } from 'react';
import { KnotLogo } from './KnotLogo';
import { EnvelopeIcon } from './icons/EnvelopeIcon';
import { GmailIcon } from './icons/GmailIcon';
import { AppleIcon } from './icons/AppleIcon';
import { CloseIcon } from './icons/CloseIcon';
import { ShieldCheckIcon } from './icons/ShieldCheckIcon';

interface AuthScreenProps {
    onLogin: (name?: string, email?: string) => void;
    onSignUp: (name?: string) => void;
}

interface MockAccount {
    name: string;
    email: string;
    role?: string;
}

const AuthScreen: React.FC<AuthScreenProps> = ({ onLogin, onSignUp }) => {
    const [isLogin, setIsLogin] = useState(true);
    const [showEmailForm, setShowEmailForm] = useState(false);
    const [showAccountPicker, setShowAccountPicker] = useState(false);
    const [pickerType, setPickerType] = useState<'Gmail' | 'Apple' | null>(null);
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');

    const mockAccounts: MockAccount[] = [
        { name: 'Sofia Ricci', email: 'sofia.r@gmail.com' },
        { name: 'Liam Wilson', email: 'liam.w@outlook.com' },
    ];

    const toggleAuthMode = () => {
        setIsLogin(!isLogin);
        setShowEmailForm(false);
        setShowAccountPicker(false);
    };

    const handleEmailContinue = () => {
        setShowEmailForm(true);
    };

    const handleSocialClick = (type: 'Gmail' | 'Apple') => {
        setPickerType(type);
        setShowAccountPicker(true);
    };

    const handleAccountSelect = (account: MockAccount) => {
        setShowAccountPicker(false);
        if (isLogin) {
            onLogin(account.name, account.email);
        } else {
            onSignUp(account.name);
        }
    };

    const handleFormSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (isLogin) {
            onLogin(name || 'User', email);
        } else {
            onSignUp(name);
        }
    };

    return (
        <div className="min-h-screen bg-brand-light flex flex-col justify-center items-center p-6 relative overflow-hidden">
            {/* Background Decorative Elements */}
            <div className="absolute top-[-10%] right-[-10%] w-64 h-64 bg-brand-primary/5 rounded-full blur-3xl"></div>
            <div className="absolute bottom-[-5%] left-[-5%] w-72 h-72 bg-brand-accent/10 rounded-full blur-3xl"></div>

            <KnotLogo className="text-4xl mb-8 relative z-10" />

            <div className="w-full max-w-sm bg-white p-8 rounded-[2.5rem] shadow-2xl relative z-10 border border-white/50">
                <h1 className="text-2xl font-black text-center text-brand-dark mb-6 tracking-tight">
                    {isLogin ? 'Welcome Back' : 'Create Account'}
                </h1>

                {showEmailForm ? (
                    <form onSubmit={handleFormSubmit} className="space-y-4 animate-fade-in">
                        {!isLogin && (
                             <div>
                                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5 block" htmlFor="name">Full Name</label>
                                <input 
                                    id="name"
                                    type="text" 
                                    value={name}
                                    onChange={(e) => setName(e.target.value)}
                                    required
                                    className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-2xl focus:outline-none focus:ring-2 focus:ring-brand-primary/20 focus:bg-white text-brand-dark transition-all"
                                    placeholder="Enter your name"
                                />
                            </div>
                        )}
                        <div>
                            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5 block" htmlFor="email">Email Address</label>
                            <input 
                                id="email"
                                type="email" 
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                required
                                className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-2xl focus:outline-none focus:ring-2 focus:ring-brand-primary/20 focus:bg-white text-brand-dark transition-all"
                                placeholder="admin@knot.ai"
                            />
                        </div>
                        <div>
                            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5 block" htmlFor="password">Security Password</label>
                            <input 
                                id="password"
                                type="password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                                className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-2xl focus:outline-none focus:ring-2 focus:ring-brand-primary/20 focus:bg-white text-brand-dark transition-all"
                                placeholder="knot2025"
                            />
                        </div>
                        {email === 'admin@knot.ai' && (
                            <div className="bg-brand-dark text-brand-accent p-3 rounded-xl flex items-center gap-2 animate-pulse">
                                <ShieldCheckIcon className="w-4 h-4" />
                                <span className="text-[9px] font-black uppercase tracking-widest">Administrator Credentials Detected</span>
                            </div>
                        )}
                         <button 
                            type="submit"
                            className="w-full bg-brand-primary text-white font-black py-4 rounded-2xl shadow-xl shadow-brand-primary/20 hover:bg-brand-secondary transition-all mt-4 active:scale-95"
                        >
                            {isLogin ? 'Log In to Registry' : 'Join the Registry'}
                        </button>
                        <button type="button" onClick={() => setShowEmailForm(false)} className="w-full text-gray-400 text-xs font-bold uppercase tracking-widest py-2">Go Back</button>
                    </form>
                ) : (
                    <div className="space-y-4">
                        <button onClick={() => handleSocialClick('Gmail')} className="w-full flex items-center justify-center gap-3 bg-white border border-gray-100 text-brand-dark font-bold py-4 rounded-2xl hover:shadow-md transition-all active:scale-95">
                            <GmailIcon className="w-5 h-5" />
