            }
            return m;
        });
        setMembers(updated);
        await db.saveMatches(updated);
        addToast("Member verification approved.", "success");
    };

    const revokeVerification = async (memberId: string) => {
        const updated = members.map(m => {
            if (m.id === memberId) {
                return { ...m, isVerified: false };
            }
            return m;
        });
        setMembers(updated);
        await db.saveMatches(updated);
