import React, { useState, useEffect, useMemo } from 'react';
import { Match, User } from '../types';
import { db } from '../services/databaseService';
import { CloseIcon } from './icons/CloseIcon';
import { ShieldCheckIcon } from './icons/ShieldCheckIcon';
import { TrashIcon } from './icons/TrashIcon';
import { VerifiedIcon } from './icons/VerifiedIcon';
import { useToast } from './feedback/useToast';

interface AdminScreenProps {
    onBack: () => void;
}

type AdminTab = 'all' | 'pending' | 'verified' | 'subscribers';

const StatCard: React.FC<{ label: string; value: string | number; color?: string; subValue?: string }> = ({ label, value, color = "text-brand-primary", subValue }) => (
    <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">{label}</p>
        <p className={`text-2xl font-black ${color}`}>{value}</p>
        {subValue && <p className="text-[9px] font-bold text-gray-400 mt-1">{subValue}</p>}
    </div>
);

const AdminScreen: React.FC<AdminScreenProps> = ({ onBack }) => {
    const [members, setMembers] = useState<Match[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [activeTab, setActiveTab] = useState<AdminTab>('all');
    const [searchQuery, setSearchQuery] = useState('');
    const { addToast } = useToast();

    useEffect(() => {
        const loadRegistry = async () => {
            const data = await db.getMatches();
            setMembers(data);
            setIsLoading(false);
        };
        loadRegistry();
    }, []);

    const handleDelete = async (memberId: string) => {
        if (window.confirm("Purge this member from the registry? This action cannot be undone and will delete all their data.")) {
            const updated = members.filter(m => m.id !== memberId);
            setMembers(updated);
            await db.saveMatches(updated);
            addToast("Member purged from registry.", "success");
        }
    };

    const approveVerification = async (memberId: string) => {
        const updated = members.map(m => {
            if (m.id === memberId) {
                return { ...m, isVerified: true };
            }
            return m;
        });
        setMembers(updated);
        await db.saveMatches(updated);
        addToast("Identity verified successfully.", "success");
    };

    const revokeVerification = async (memberId: string) => {
        if (window.confirm("Revoke this member's verified status?")) {
            const updated = members.map(m => {
                if (m.id === memberId) {
                    return { ...m, isVerified: false };
                }
                return m;
            });
            setMembers(updated);
            await db.saveMatches(updated);
            addToast("Verification revoked.", "info");
        }
    };

    const filteredMembers = useMemo(() => {
        let list = [...members];

        // Tab Filtering
        if (activeTab === 'pending') list = list.filter(m => !m.isVerified);
        if (activeTab === 'verified') list = list.filter(m => m.isVerified);
        if (activeTab === 'subscribers') list = list.filter(m => m.isPremium);

        // Search Filtering
        if (searchQuery) {
            const q = searchQuery.toLowerCase();
            list = list.filter(m => 
                m.name.toLowerCase().includes(q) || 
                m.occupation.toLowerCase().includes(q) ||
                (m.email && m.email.toLowerCase().includes(q))
            );
        }

        return list;
    }, [members, activeTab, searchQuery]);

    const totalRevenue = members.reduce((sum, m) => sum + (m.subscriptionAmount || 0), 0);
    const stats = {
        total: members.length,
        verified: members.filter(m => m.isVerified).length,
        pending: members.filter(m => !m.isVerified).length,
        premium: members.filter(m => m.isPremium).length,
        revenue: `$${totalRevenue.toFixed(2)}`
    };

    return (
        <div className="w-full h-screen bg-gray-50 flex flex-col font-sans overflow-hidden">
            <header className="flex items-center justify-between p-4 bg-brand-dark text-white border-b border-white/10 sticky top-0 z-10 shadow-xl">
                <div className="flex items-center gap-3">
                    <ShieldCheckIcon className="w-6 h-6 text-brand-accent" />
                    <div>
                        <h1 className="text-xl font-black uppercase tracking-tighter leading-none">Command Center</h1>
                        <p className="text-[8px] font-bold text-brand-accent uppercase tracking-[0.2em] mt-1">Registry Admin Panel</p>
                    </div>
                </div>
                <button onClick={onBack} className="p-2 bg-white/10 rounded-full text-white hover:bg-white/20">
                    <CloseIcon className="w-6 h-6" />
                </button>
            </header>

            <main className="flex-1 overflow-y-auto pb-32">
                {/* Metrics Summary */}
                <div className="p-6 grid grid-cols-2 gap-4">
                    <StatCard label="Total Registry" value={stats.total} />
                    <StatCard label="Revenue" value={stats.revenue} color="text-brand-secondary" />
                    <StatCard label="Waitlist (Pending)" value={stats.pending} color="text-orange-500" />
                    <StatCard label="Trusted Members" value={stats.verified} color="text-green-600" />
                </div>

                {/* Directory Controls */}
                <div className="px-6 space-y-4">
                    <div className="relative">
                        <input 
                            type="text"
                            placeholder="Search by name or occupation..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full bg-white border border-gray-100 p-4 pl-12 rounded-2xl text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-sm"
                        />
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 absolute left-4 top-4 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                        </svg>
                    </div>

                    <div className="flex bg-gray-100 p-1 rounded-2xl gap-1">
                        {(['all', 'pending', 'verified', 'subscribers'] as AdminTab[]).map(tab => (
                            <button
                                key={tab}
                                onClick={() => setActiveTab(tab)}
                                className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-white text-brand-primary shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}
                            >
                                {tab}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Directory List */}
                <div className="px-6 mt-6">
                    {isLoading ? (
                        <div className="flex justify-center py-20">
                            <div className="w-8 h-8 border-4 border-brand-primary border-t-transparent rounded-full animate-spin"></div>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            {filteredMembers.length > 0 ? (
