// PRODUCTION MODE: ACTIVE
const STAGING_MODE_ACTIVE = false;

export const generateConversationStarters = async (user: User, match: Match): Promise<string[]> => {
    if (STAGING_MODE_ACTIVE || !process.env.API_KEY) {
        return [
            `I see we both have heritage from ${match.originCountry}. Does your family still follow many traditions from there?`,
            "Your registry mention of shared values caught my eye. What's the most important one to you in a marriage?",
            `As a ${user.occupation}, I'm curious: how does being a ${match.occupation} influence your perspective on building a future?`
        ];
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-flash-preview';

    const prompt = `
        Act as an expert marriage counselor and matchmaker.
        User: ${user.name}, Age: ${user.age}, Bio: ${user.bio}, Origin: ${user.originCountry}, Occupation: ${user.occupation}.
        Match: ${match.name}, Age: ${match.age}, Bio: ${match.bio}, Origin: ${match.originCountry}, Occupation: ${match.occupation}.

        Generate 3 high-intent, respectful conversation starters that focus on compatibility, family values, or future goals. 
        Avoid generic small talk. Keep it focused on the "Knot" app's mission of marriage.
        Return as a JSON array of strings.
    `;

    try {
