                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.STRING
                    }
                }
            }
        });
        const starters = JSON.parse(response.text?.trim() || '[]');
        return Array.isArray(starters) && starters.length > 0 ? starters : ["I'd love to learn more about your vision for a shared future."];
    } catch (error) {
        return [`Hi ${match.name}, your profile values really resonated with me.`];
