};

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { User, Match, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from '../types';
import { MATCHES_DATA } from '../constants';

// PRODUCTION MODE: ACTIVE
const STAGING_MODE_ACTIVE = false; 

async function callGeminiWithRetry(
  ai: any, 
  params: any, 
  retries = 3, 
  delay = 1500
): Promise<GenerateContentResponse> {
  try {
    return await ai.models.generateContent(params);
  } catch (error: any) {
    const isRetryable = error?.status === 'UNKNOWN' || error?.code === 500 || error?.code === 503 || error?.code === 429;
    if (retries > 0 && isRetryable) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return callGeminiWithRetry(ai, params, retries - 1, delay * 2);
    }
    throw error;
  }
}

export const getCompatibilityInsight = async (user: User, match: Match): Promise<{ score: number, insight: string }> => {
    if (STAGING_MODE_ACTIVE || !process.env.API_KEY) {
        const score = 85 + (match.name.length % 12);
        return { score, insight: "High alignment found in your professional stability and shared desire for children." };
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-pro-preview';

    const prompt = `
        Perform a deep compatibility analysis for the Knot Registry.
        User A: ${JSON.stringify({ name: user.name, bio: user.bio, values: user.personalValues, religion: user.religion, timeline: user.marriageTimeline })}
        User B: ${JSON.stringify({ name: match.name, bio: match.bio, values: match.personalValues, religion: match.religion, timeline: match.marriageTimeline })}

        Compare their long-term marital success probability based on values, religion, and timing.
        Return JSON format: { "score": number (0-100), "insight": string (max 25 words) }
    `;

    try {
        const response = await callGeminiWithRetry(ai, {
            model: model,
            contents: prompt,
            config: {
                thinkingConfig: { thinkingBudget: 4000 },
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.INTEGER },
                        insight: { type: Type.STRING }
                    },
                    required: ["score", "insight"]
                }
            }
        });

        return JSON.parse(response.text || '{"score": 75, "insight": "Stable connection predicted."}');
    } catch (error) {
        return { score: 75, insight: "Shared commitment to marriage makes you a strong potential match." };
    }
};

