export const queryGlobalRegistry = async (count: number = 3): Promise<Match[]> => {
    if (STAGING_MODE_ACTIVE || !process.env.API_KEY) {
        await new Promise(r => setTimeout(r, 1000));
        return MATCHES_DATA.slice(0, count);
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-flash-preview';

    const prompt = `
        Generate ${count} high-quality, realistic marriage-seeking profiles for the Knot Global Registry.
        Ensure diversity in origins (e.g. Asia, Africa, Europe, Americas).
        Include professional occupations and serious bios.
        Return JSON array.
    `;

    try {
        const response = await callGeminiWithRetry(ai, {
            model: model,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            name: { type: Type.STRING },
                            age: { type: Type.INTEGER },
                            bio: { type: Type.STRING },
                            occupation: { type: Type.STRING },
                            city: { type: Type.STRING },
                            country: { type: Type.STRING },
                            residenceCountry: { type: Type.STRING },
                            residenceState: { type: Type.STRING },
                            residenceCity: { type: Type.STRING },
                            originCountry: { type: Type.STRING },
                            originState: { type: Type.STRING },
                            originCity: { type: Type.STRING },
                            culturalBackground: { type: Type.STRING },
                            marriageTimeline: { type: Type.STRING },
                            profileImageUrls: { type: Type.ARRAY, items: { type: Type.STRING } },
                            maritalStatus: { type: Type.STRING }
                        },
                        required: ["id", "name", "age", "bio", "maritalStatus", "profileImageUrls"]
                    }
                }
            }
        });

        const rawMatches = JSON.parse(response.text || '[]');
        return rawMatches.map((m: any) => ({
            ...m,
            id: `global_${m.id || Math.random().toString(36).substr(2, 9)}`,
            smoking: SmokingHabits.NonSmoker,
            drinking: DrinkingHabits.Socially,
            maritalStatus: m.maritalStatus as MaritalStatus || MaritalStatus.NeverMarried,
            childrenStatus: "No kids",
            willingToRelocate: WillingToRelocate.Maybe,
            childrenPreference: ChildrenPreference.OpenToChildren,
            languages: ["English"],
            education: "University Graduate",
            isVerified: true,
            isPremium: false,
            personalValues: ["Family", "Trust", "Growth"],
            idealPartnerTraits: ["Kind", "Honest"],
            interests: ["Cooking", "Travel", "Reading"],
            religion: "Traditional",
            nationality: m.country,
            careerGoals: "Long-term stability."
        }));
    } catch (error) {
        return [];
    }
};

import React, { useState, useEffect, useCallback } from 'react';
import { User, Match, Screen, FilterState, SmokingHabits, DrinkingHabits, MaritalStatus, WillingToRelocate, ChildrenPreference } from './types';
import { INITIAL_FILTERS, CURRENT_USER } from './constants';
import { db } from './services/databaseService';
import { queryGlobalRegistry } from './services/matchingService';
import Header from './components/Header';
import BottomNav from './components/BottomNav';
import MatchCard from './components/MatchCard';
import DiscoveryScreen from './components/DiscoveryScreen';
import ProfileDetailScreen from './components/ProfileDetailScreen';
import ChatScreen from './components/ChatScreen';
import VideoCallScreen from './components/VideoCallScreen';
import ProfileCard from './components/ProfileCard';
import VerificationScreen from './components/VerificationScreen';
import EditProfileScreen from './components/EditProfileScreen';
import PhotoManagerScreen from './components/PhotoManagerScreen';
import AuthScreen from './components/AuthScreen';
import LikesScreen from './components/LikesScreen';
import PremiumModal from './components/PremiumModal';
import MessagesScreen from './components/MessagesScreen';
import FilterModal from './components/FilterModal';
import PaymentScreen from './components/PaymentScreen';
import OnboardingFlow from './components/OnboardingFlow';
import AdminScreen from './components/AdminScreen';
import GlobalActivityTicker from './components/GlobalActivityTicker';
import { FilterIcon } from './components/icons/FilterIcon';
import { DiscoveryIcon } from './components/icons/DiscoveryIcon';
import { ToastProvider, useToast } from './components/feedback/useToast';

const AppContent: React.FC = () => {
    const [user, setUser] = useState<User | null>(null);
    const [matches, setMatches] = useState<Match[]>([]);
    const [isLoggedIn, setIsLoggedIn] = useState(false);
    const [activeScreen, setActiveScreen] = useState<Screen>('home');
    const [selectedMatch, setSelectedMatch] = useState<Match | null>(null);
    const [filters, setFilters] = useState<FilterState>(INITIAL_FILTERS);
    const [isFilterModalOpen, setIsFilterModalOpen] = useState(false);
    const [isPremiumModalOpen, setIsPremiumModalOpen] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);
    const { addToast } = useToast();

    useEffect(() => {
        const loadData = async () => {
            const userData = await db.getUser();
            const matchesData = await db.getMatches();
            setUser(userData);
            setMatches(matchesData);
        };
        loadData();
    }, []);

    const fetchMoreFromGlobalRegistry = useCallback(async (isSilent = false) => {
        if (isSyncing) return;
        setIsSyncing(true);
        if (!isSilent) addToast("Syncing Global Registry...", "info");

        try {
            const newMatches = await queryGlobalRegistry(6);
            if (newMatches.length > 0) {
                await db.addGlobalMatches(newMatches);
                const updatedMatches = await db.getMatches();
                setMatches(updatedMatches);
                if (!isSilent) addToast(`Updated Registry: ${newMatches.length} profiles added.`, "success");
            }
        } catch (e) {
            if (!isSilent) addToast("Registry sync failed. Check connectivity.", "error");
        } finally {
            setIsSyncing(false);
        }
    }, [isSyncing, addToast]);

    // Auto-sync on home screen load
    useEffect(() => {
        if (isLoggedIn && activeScreen === 'home' && matches.length < 5) {
            fetchMoreFromGlobalRegistry(true);
        }
    }, [isLoggedIn, activeScreen, matches.length, fetchMoreFromGlobalRegistry]);

    const handleLogin = (isNewUser: boolean = false, name?: string, email?: string) => {
        if (isNewUser) {
            const newUserTemplate: User = {
                ...CURRENT_USER,
                id: `user_${Date.now()}`,
                name: name || 'New User',
                email: email,
                bio: '',
                age: 25,
                isVerified: false,
                isPremium: false,
                profileImageUrls: ['https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=800&auto=format&fit=crop'],
                personalValues: [],
                occupation: '',
                marriageTimeline: '1-2 years',
                maritalStatus: MaritalStatus.NeverMarried,
                childrenPreference: ChildrenPreference.OpenToChildren,
                willingToRelocate: WillingToRelocate.Maybe,
            };
            setUser(newUserTemplate);
            db.saveUser(newUserTemplate);
            setIsLoggedIn(true);
            setActiveScreen('onboarding');
        } else {
            const isAdmin = email === 'admin@knot.ai';
            if (isAdmin) {
                setUser(CURRENT_USER);
                db.saveUser(CURRENT_USER);
                addToast("Admin Dashboard Authorized", "success");
                setIsLoggedIn(true);
                setActiveScreen('admin');
            } else {
                setIsLoggedIn(true);
                setActiveScreen('home');
                addToast("Registry Authenticated", "success");
            }
        }
    };

    const handleNavigate = (screen: Screen) => {
        if (screen === 'likes' && user && !user.isPremium) {
            setIsPremiumModalOpen(true);
        } else {
            setActiveScreen(screen);
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }
    };

    const handleCardClick = (match: Match) => {
        setSelectedMatch(match);
        setActiveScreen('profileDetail');
    };

    const handleStartChat = (match: Match) => {
        if (user && !user.isPremium) {
            setIsPremiumModalOpen(true);
            return;
        }
        setSelectedMatch(match);
        setActiveScreen('chat');
    };

    const handleStartCall = (match: Match) => {
        if (user && !user.isPremium) {
            setIsPremiumModalOpen(true);
            return;
        }
        setSelectedMatch(match);
        setActiveScreen('videoCall');
    };

    const handleBack = () => {
        if (activeScreen === 'chat' || activeScreen === 'videoCall') {
            setActiveScreen('profileDetail');
        } else if (activeScreen === 'profileDetail' || activeScreen === 'payment') {
            setActiveScreen('home');
            setSelectedMatch(null);
        } else if (['verification', 'editProfile', 'managePhotos', 'admin'].includes(activeScreen)) {
            setActiveScreen('profile');
            setSelectedMatch(null);
        } else {
            setActiveScreen('home');
            setSelectedMatch(null);
        }
    };

    const handleUpgradeClick = () => {
        setIsPremiumModalOpen(false);
        setActiveScreen('payment');
    };

    const handleSubscribe = () => {
        if (user) {
            const updated: User = { 
                ...user, 
                isPremium: true,
                subscriptionAmount: 9.99,
                subscriptionDate: new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }),
                subscriptionPeriod: 'Monthly'
            };
            setUser(updated);
            db.saveUser(updated);
        }
        addToast('Welcome to Premium!', 'success');
        setActiveScreen('likes'); 
    };

    const handleSaveProfile = (updatedUser: User) => {
        setUser(updatedUser);
        db.saveUser(updatedUser);
        addToast('Registry updated!', 'success');
        if (activeScreen === 'onboarding') {
            setActiveScreen('home');
        } else {
            handleBack();
        }
    };

    const handleCancelOnboarding = () => {
        if (window.confirm("Exit registry activation? Your progress will be lost.")) {
            setIsLoggedIn(false);
            setUser(null);
            setActiveScreen('home');
        }
    };

    const handleVerificationComplete = () => {
        if (user) {
            const updated = {...user, isVerified: true};
            setUser(updated);
            db.saveUser(updated);
        }
        setActiveScreen('profile');
    };

    const handleUpdatePhotos = (photos: string[]) => {
        if (user) {
            const updated = {...user, profileImageUrls: photos};
            setUser(updated);
            db.saveUser(updated);
        }
        addToast('Photos updated!', 'success');
        handleBack();
    };

    const filteredMatches = matches.filter(match => {
        const ageMatch = match.age >= filters.ageRange[0] && match.age <= filters.ageRange[1];
        const locationMatch = filters.location ? (match.city?.toLowerCase().includes(filters.location.toLowerCase()) || match.country?.toLowerCase().includes(filters.location.toLowerCase())) : true;
        const verifiedMatch = filters.showVerifiedOnly ? match.isVerified : true;
        return ageMatch && locationMatch && verifiedMatch;
    });

    if (!isLoggedIn) {
        return <AuthScreen onLogin={(name, email) => handleLogin(false, name, email)} onSignUp={(name, email) => handleLogin(true, name, email)} />;
    }

    if (!user) return <div className="h-screen flex items-center justify-center bg-brand-dark text-brand-accent font-black animate-pulse">KNOT INITIALIZING...</div>;

    const renderScreen = () => {
        if (selectedMatch) {
            switch(activeScreen) {
                case 'profileDetail':
                    return <ProfileDetailScreen match={selectedMatch} user={user} onBack={handleBack} onStartChat={handleStartChat} onStartCall={handleStartCall} />;
                case 'chat':
                    return <ChatScreen match={selectedMatch} user={user} onBack={handleBack} onStartCall={handleStartCall} />;
                case 'videoCall':
                    return <VideoCallScreen match={selectedMatch} user={user} onEndCall={handleBack} />;
            }
        }

        switch (activeScreen) {
            case 'onboarding':
                return <OnboardingFlow user={user} onComplete={handleSaveProfile} onCancel={handleCancelOnboarding} />;
            case 'home':
                return (
                    <div className="p-4 space-y-3 pb-32">
                        <div className="flex items-center justify-between px-2 pt-0.5 pb-1 border-b border-gray-100 mb-2">
                            <div className="flex flex-col">
                                <h2 className="text-sm font-black text-brand-dark tracking-tighter uppercase leading-none">Global Matches</h2>
                                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-0.5">High compatibility registry</p>
                            </div>
                            <div className="flex items-center gap-2">
                                <button onClick={() => setIsFilterModalOpen(true)} className="p-1.5 bg-brand-primary text-white rounded-lg shadow-md active:scale-95 transition-all">
                                    <FilterIcon className="w-5 h-5" />
                                </button>
                            </div>
                        </div>

                        {filteredMatches.length > 0 ? (
                            filteredMatches.map(match => (
                                <MatchCard key={match.id} match={match} onCardClick={handleCardClick} />
                            ))
                        ) : (
                            <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200 m-2">
                                <p className="text-gray-500 font-bold uppercase tracking-widest text-xs">No active matches in this range.</p>
                                <button onClick={() => setFilters(INITIAL_FILTERS)} className="mt-4 text-brand-primary font-black uppercase text-[10px] tracking-widest underline">Reset Filters</button>
                            </div>
                        )}

                        <div className="pt-6 pb-4 flex flex-col items-center">
                            <button 
                                onClick={fetchMoreFromGlobalRegistry}
                                disabled={isSyncing}
                                className="flex items-center gap-2 bg-white border border-brand-primary/20 text-brand-primary font-black px-8 py-3 rounded-full shadow-sm hover:shadow-md transition-all active:scale-95 disabled:opacity-50"
                            >
                                <DiscoveryIcon className={`w-5 h-5 ${isSyncing ? 'animate-spin' : ''}`} />
                                <span>{isSyncing ? 'Scanning Registry...' : 'Load New Profiles'}</span>
                            </button>
                        </div>
                    </div>
                );
            case 'discovery':
                return <DiscoveryScreen matches={filteredMatches} onMatchClick={handleCardClick} />;
            case 'likes':
                 return <LikesScreen likedMatches={[]} onMatchClick={handleCardClick} />;
            case 'messages':
                return <MessagesScreen onChatSelect={handleStartChat} user={user} />;
            case 'profile':
                return <ProfileCard 
                    user={user} 
                    onEditProfile={() => setActiveScreen('editProfile')} 
                    onManagePhotos={() => setActiveScreen('managePhotos')}
                    onVerifyProfile={() => setActiveScreen('verification')}
                    onOpenAdmin={() => setActiveScreen('admin')}
                />;
            case 'verification':
                return <VerificationScreen onVerificationComplete={handleVerificationComplete} onBack={handleBack} />;
            case 'editProfile':
                return <EditProfileScreen user={user} onBack={handleBack} onSave={handleSaveProfile} />;
            case 'managePhotos':
                return <PhotoManagerScreen user={user} onBack={handleBack} onUpdatePhotos={handleUpdatePhotos} />;
            case 'payment':
                return <PaymentScreen onBack={handleBack} onSubscribe={handleSubscribe} />;
            case 'admin':
                return <AdminScreen onBack={handleBack} />;
            default:
                return <div className="p-10 text-center">Screen Not Found</div>;
        }
    };

    const showHeader = ['home', 'discovery', 'likes', 'messages', 'profile'].includes(activeScreen);
    const showBottomNav = ['home', 'discovery', 'likes', 'messages', 'profile'].includes(activeScreen);
    const showTicker = ['home', 'discovery'].includes(activeScreen);

    return (
        <div className="max-w-md mx-auto bg-gray-50 min-h-screen font-sans shadow-2xl overflow-x-hidden">
            {showHeader && (
                <div className="fixed top-0 left-0 right-0 max-w-md mx-auto z-50">
                    <Header />
                    {showTicker && <GlobalActivityTicker />}
                    {isSyncing && (
                        <div className="h-0.5 w-full bg-brand-light relative overflow-hidden">
                            <div className="absolute inset-0 bg-brand-primary animate-progress-ind"></div>
                        </div>
                    )}
                </div>
            )}

            <main className={`${showHeader ? (showTicker ? 'pt-[5.75rem]' : 'pt-[4rem]') : ''}`}>
                {renderScreen()}
            </main>

            {showBottomNav && (
                <BottomNav activeScreen={activeScreen} onNavigate={handleNavigate} />
            )}

            <FilterModal 
                isOpen={isFilterModalOpen} 
                onClose={() => setIsFilterModalOpen(false)}
                currentFilters={filters}
                onApplyFilters={(newFilters) => {
                    setFilters(newFilters);
                    addToast('Filters applied.', 'info');
                }}
                initialFilters={INITIAL_FILTERS}
            />

            <PremiumModal 
                isOpen={isPremiumModalOpen}
                onClose={() => setIsPremiumModalOpen(false)}
                onUpgrade={handleUpgradeClick}
            />

            <style>{`
                @keyframes progress-ind {
                    0% { left: -100%; width: 100%; }
                    100% { left: 100%; width: 100%; }
                }
                .animate-progress-ind { animation: progress-ind 1.5s infinite linear; }
                body { background-color: #f3f4f6; }
            `}</style>
        </div>
    );
};

const App: React.FC = () => {
    return (
        <ToastProvider>
            <AppContent />
        </ToastProvider>
    );
};

