import { GoogleGenAI, Type } from "@google/genai";

export interface GlobalEvent {
    id: string;
    message: string;
    location: string;
    timestamp: Date;
}

// PRODUCTION MODE: ACTIVE
const STAGING_MODE_ACTIVE = false;

const CACHE_KEY = 'knot_global_activity_cache';
const CACHE_EXPIRY = 1000 * 60 * 5; // 5 minutes for live feel

const FALLBACK_EVENTS: GlobalEvent[] = [
    { id: 'f1', message: "New marriage-minded match found", location: "London, UK", timestamp: new Date() },
    { id: 'f2', message: "User profile verified via Biometrics", location: "Toronto, CA", timestamp: new Date() },
    { id: 'f3', message: "Marriage timeline aligned for new couple", location: "Lagos, NG", timestamp: new Date() }
];

export const fetchRecentGlobalActivity = async (): Promise<GlobalEvent[]> => {
    if (STAGING_MODE_ACTIVE) {
        return FALLBACK_EVENTS;
    }

    const cached = localStorage.getItem(CACHE_KEY);
    if (cached) {
        const { timestamp, data } = JSON.parse(cached);
        if (Date.now() - timestamp < CACHE_EXPIRY) {
            return data.map((d: any) => ({ ...d, timestamp: new Date(d.timestamp) }));
        }
    }

    if (!process.env.API_KEY) return FALLBACK_EVENTS;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-flash-preview';

    const prompt = `
        Generate 5 real-sounding "Live Community Events" for a global marriage matchmaking app called "Knot".
        Events should sound positive and high-intent, like "Registry profile verified", "Compatibility match found", "New premium member joined".
        Include specific worldwide locations (City, Country).
        Return as a JSON array.
    `;

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            message: { type: Type.STRING },
                            location: { type: Type.STRING }
                        },
                        required: ["message", "location"]
                    }
                }
            }
        });

        const data = JSON.parse(response.text || '[]');
        const events = data.map((item: any, idx: number) => ({
            id: `event_${Date.now()}_${idx}`,
            message: item.message,
            location: item.location,
            timestamp: new Date()
        }));

        localStorage.setItem(CACHE_KEY, JSON.stringify({
            timestamp: Date.now(),
            data: events
        }));

        return events;
    } catch (e: any) {
        return FALLBACK_EVENTS;
    }
};

