 * Set to true to bypass Gemini API and use local static logic.
 */
const STAGING_MODE_ACTIVE = true; 

async function callGeminiWithRetry(
  ai: any, 
  params: any, 
  retries = 3, 
  delay = 1500
): Promise<GenerateContentResponse> {
  try {
    return await ai.models.generateContent(params);
  } catch (error: any) {
    const isRetryable = error?.status === 'UNKNOWN' || error?.code === 500 || error?.code === 503 || error?.code === 429;
    if (retries > 0 && isRetryable) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return callGeminiWithRetry(ai, params, retries - 1, delay * 2);
    }
    throw error;
  }
}

export const getCompatibilityInsight = async (user: User, match: Match): Promise<{ score: number, insight: string }> => {
    // Preserved API logic bypassed for testing
    if (STAGING_MODE_ACTIVE || !process.env.API_KEY) {
        const score = 88 + (match.name.length % 10);
        return { 
