        User A: ${JSON.stringify({ name: user.name, bio: user.bio, values: user.personalValues, religion: user.religion, timeline: user.marriageTimeline })}
        User B: ${JSON.stringify({ name: match.name, bio: match.bio, values: match.personalValues, religion: match.religion, timeline: match.marriageTimeline })}
        Return JSON format: { "score": number (0-100), "insight": string (max 25 words) }
    `;

    try {
        const response = await callGeminiWithRetry(ai, {
            model: model,
            contents: prompt,
            config: {
                thinkingConfig: { thinkingBudget: 4000 },
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.INTEGER },
                        insight: { type: Type.STRING }
                    },
                    required: ["score", "insight"]
                }
            }
        });

        return JSON.parse(response.text || '{"score": 75, "insight": "Stable connection predicted."}');
    } catch (error) {
        return { score: 75, insight: "Shared commitment to marriage makes you a strong potential match." };
    }
