        let list = [...members];
        if (activeTab === 'pending') list = list.filter(m => !m.isVerified);
        if (activeTab === 'verified') list = list.filter(m => m.isVerified);
        if (activeTab === 'subscribers') list = list.filter(m => m.isPremium);

        if (searchQuery) {
            const q = searchQuery.toLowerCase();
