import { User, Match, FilterState } from '../types';
import { MATCHES_DATA } from '../constants';

/**
 * Calculates a compatibility score (0-100) based on shared profile data.
 * Purely deterministic local logic.
 */
export const calculateMatchScore = (user: User, match: Match): number => {
    let score = 60; // Base score

    // Location matching
    if (user.residenceCountry === match.residenceCountry) score += 10;
    if (user.residenceState === match.residenceState) score += 5;
    if (user.residenceCity === match.residenceCity) score += 5;

    // Timeline alignment
    if (user.marriageTimeline === match.marriageTimeline) score += 10;

    // Shared Values intersection
    const sharedValues = user.personalValues.filter(v => match.personalValues.includes(v));
    score += sharedValues.length * 3;

    // Children preference
    if (user.childrenPreference === match.childrenPreference) score += 5;

    // Lifestyle
    if (user.smoking === match.smoking) score += 2;
    if (user.drinking === match.drinking) score += 2;

    return Math.min(score, 100);
};

export const getCompatibilityInsight = async (user: User, match: Match): Promise<{ score: number, insight: string }> => {
    const score = calculateMatchScore(user, match);

    let insight = "Shared values and lifestyle choices show good potential for a stable foundation.";
    if (score > 85) insight = "Exceptional alignment in heritage, values, and marriage timeline.";
    else if (score < 70) insight = "Profiles show some variations in lifestyle preferences but share core registry standards.";

    return { score, insight };
};

export const searchRegistry = (query: string, matches: Match[]): Match[] => {
    if (!query.trim()) return matches;
    const q = query.toLowerCase();
    return matches.filter(m => 
        m.name.toLowerCase().includes(q) ||
        m.occupation.toLowerCase().includes(q) ||
        m.city.toLowerCase().includes(q) ||
        m.country.toLowerCase().includes(q) ||
        m.culturalBackground.toLowerCase().includes(q)
    );
};

export const queryGlobalRegistry = async (count: number = 3): Promise<Match[]> => {
    // Returns static matches instantly from local constants to simulate a backend query
    return [...MATCHES_DATA].sort(() => 0.5 - Math.random()).slice(0, count);
};

