    const handlePaystackPayment = () => {
        setIsProcessing(true);

        // Paystack handler
        const handler = window.PaystackPop.setup({
            key: 'pk_test_xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx', 
