                                </div>

                                <button 
                                    onClick={incrementMonths}
                                    className="w-12 h-12 rounded-2xl bg-white/20 flex items-center justify-center hover:bg-white/30 active:scale-90 transition-all"
                                >
                                    <PlusIcon className="w-6 h-6" />
