                     <h2 className="text-lg font-bold text-brand-primary">Premium Benefits</h2>
                     <ul className="space-y-4">
                         <li className="flex items-center gap-3 text-sm text-gray-700 font-medium">
                             <div className="w-6 h-6 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-xs">✓</div>
                             See who liked your profile instantly
                         </li>
                         <li className="flex items-center gap-3 text-sm text-gray-700 font-medium">
                             <div className="w-6 h-6 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-xs">✓</div>
                             Unlimited global registry searches
                         </li>
                         <li className="flex items-center gap-3 text-sm text-gray-700 font-medium">
                             <div className="w-6 h-6 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-xs">✓</div>
                             Priority badge on your profile
                         </li>
                         <li className="flex items-center gap-3 text-sm text-gray-700 font-medium">
                             <div className="w-6 h-6 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-xs">✓</div>
